INSERT OR REPLACE INTO datasets VALUES ('airport-rail-link-arl','สถานีรับส่งผู้โดยสารรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (AIRPORT RAIL LINK: ARL)','ชั้นข้อมูลสถานีรับส่งผู้โดยสารรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (AIRPORT RAIL LINK: ARL)','กรุงเทพมหานคร','["สถานี","สุวรรณภูมิ"]','["ZIP","MAP","JSON","PDF"]',5,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/e659e132-15da-4914-8740-3c128c90304d/resource/8ece12ed-4761-483f-9384-31b20e768532/download/airport-rail-link-arl-1k_ojf.zip"},{"name":"สถานีรับส่งผู้โดยสารรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (AIRPORT RAIL LINK: ARL)","format":"ZIP","url":"https://data.go.th/dataset/e659e132-15da-4914-8740-3c128c90304d/resource/ba96dc07-43d9-4faf-9690-f3e0f2774214/download/airportlink_station.zip"},{"name":"สถานีรับส่งผู้โดยสารรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (AIRPORT RAIL LINK: ARL) (GML)","format":"MAP","url":"https://data.go.th/dataset/e659e132-15da-4914-8740-3c128c90304d/resource/1a830ef5-7176-4c3b-ab31-c4d9aafc3a46/download/airportlink_station.gml"},{"name":"สถานีรับส่งผู้โดยสารรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (AIRPORT RAIL LINK: ARL)","format":"JSON","url":"https://data.go.th/dataset/e659e132-15da-4914-8740-3c128c90304d/resource/4d3bcb46-7687-4e3d-a138-5d934498052d/download/airportlink_station.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/e659e132-15da-4914-8740-3c128c90304d/resource/f1d3aa5d-8120-4785-94fc-c51331ef0962/download/airportlink_station.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:36.166220','https://data.go.th/dataset/airport-rail-link-arl');
INSERT OR REPLACE INTO datasets VALUES ('suvarnabhumi-airport-rial-link-sarl','เส้นทางรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (SUVARNABHUMI AIRPORT RIAL LINK:SARL)','ชั้นข้อมูลเส้นทางรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (SUVARNABHUMI AIRPORT RIAL LINK:SARL) เส้นทางรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (SARL) เป็นระบบขนส่งทางรถไฟเชื่อมท่าอากาศยานสุวรรณภูมิ และสถานีรับส่งผู้โดยสารทาอากายานในเมือง เพื่อเชื่อมเส้นทางระหว่างเมืองหลวงไปยังท่าอากาศยานสุวรรณภูมิ ระยะทาง 28.6 กม. โดยใช้รถไฟฟ้าความเร็วสูงแบบทางคู่ ยกระดับขนานไปตามแนวเส้นทางรถไฟทางไกลสายตะวันออก เพื่อให้บริการแก่ผู้โดยสารท้องถิ่นตลอดเส้นทาง และผู้โดยสารท่าอากาศยานสุวรรณภูมิ เดินทางรถไฟฟ้าความเร็วสูงนี้ มีรูปแบบการให้บริการ 2 แบบ คือ 1. รถไฟฟ้าด่วนท่าอากาศยานสุวรรณภูมิ ให้บริการผู้โดยสารด้วยรถไฟฟ้าปรับอากาศความเร็วสู…','กรุงเทพมหานคร','["สุวรรณภูมิ","เส้นทางรถไฟฟ้า"]','["ZIP","MAP","JSON","PDF"]',5,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/45d00821-46aa-4552-a094-49446c0fb444/resource/fce0aa42-540e-4fb1-8faf-2d949c1b6c4a/download/suvarnabhumi-airport-rial-link-sarl-wdnbp6.zip"},{"name":"เส้นทางรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (SUVARNABHUMI AIRPORT RIAL LINK:SARL)","format":"ZIP","url":"https://data.go.th/dataset/45d00821-46aa-4552-a094-49446c0fb444/resource/5c119032-5109-40e7-8f95-f6016eda41f5/download/airportlink_line.zip"},{"name":"เส้นทางรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (SUVARNABHUMI AIRPORT RIAL LINK:SARL) (GML)","format":"MAP","url":"https://data.go.th/dataset/45d00821-46aa-4552-a094-49446c0fb444/resource/da85af6b-bbcf-475e-a0d0-ae8f599a7250/download/airportlink_line.gml"},{"name":"เส้นทางรถไฟฟ้าท่าอากาศยานสุวรรณภูมิ (SUVARNABHUMI AIRPORT RIAL LINK:SARL)","format":"JSON","url":"https://data.go.th/dataset/45d00821-46aa-4552-a094-49446c0fb444/resource/f5184985-f262-4d1f-b086-f44fa940d9e7/download/airportlink_line.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/45d00821-46aa-4552-a094-49446c0fb444/resource/1eecca24-314f-4677-a6ae-4125503d50dd/download/airportlink_line.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:35.784036','https://data.go.th/dataset/suvarnabhumi-airport-rial-link-sarl');
