INSERT OR REPLACE INTO datasets VALUES ('train_station','สถานีรถไฟ/ที่หยุดรถไฟในกรุงเทพมหานคร','ชั้นข้อมูลสถานีรถไฟ/ที่หยุดรถไฟในกรุงเทพมหานคร 1. สถานีรถไฟ หมายถึง สถานีที่มีสัญญาณหยุดจอดรถประจำสถานี สามารถซื้อตั๋ว และจองตั๋วล่วงหน้าได้ 2.ที่หยุดรถไฟ ไม่ใช่สถานีรถไฟ แต่ในอนาคตอาจเป็นสถานีได้ สามารถขึ้นลงและซื้อตั๋วบนรถได้','กรุงเทพมหานคร','["กรุงเทพ","กรุงเทพมหานคร","รถไฟ","สถานีรถไฟ"]','["ZIP","MAP","JSON","PDF"]',5,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/ee189de7-7131-4808-8c69-de101c0bd0e4/resource/21eee3f2-7caf-4e15-85fa-9f9d2c70feec/download/train_station-oguf__.zip"},{"name":"สถานีรถไฟ/ที่หยุดรถไฟในกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/ee189de7-7131-4808-8c69-de101c0bd0e4/resource/c10e9b39-b461-4d2b-8778-8a1f9af1fe7a/download/train_station.zip"},{"name":"สถานีรถไฟ/ที่หยุดรถไฟในกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/ee189de7-7131-4808-8c69-de101c0bd0e4/resource/1af4e679-9d8b-4c53-8100-9e677f5754d6/download/train_station.gml"},{"name":"สถานีรถไฟ/ที่หยุดรถไฟในกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/ee189de7-7131-4808-8c69-de101c0bd0e4/resource/7dcc70f4-b03d-4cdd-b2ce-d0b5fc66b91e/download/train_station.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/ee189de7-7131-4808-8c69-de101c0bd0e4/resource/3566cd8b-115b-49db-9d7d-8202d40ccdf9/download/train_station.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:33.680472','https://data.go.th/dataset/train_station');
