INSERT OR REPLACE INTO datasets VALUES ('bangkok-mass-transit-system-bts','เส้นทางรถไฟลอยฟ้า (Bangkok Mass Transit System :BTS) ในพื้นที่เขตกรุงเทพมหานคร','เส้นทางรถไฟลอยฟ้า (Bangkok Mass Transit System :BTS) ในพื้นที่เขตกรุงเทพมหานคร รถไฟฟ้าลอยฟ้า (BTS) เป็นระบบขนส่งมวลชนที่มีขีดความสามารถสูงในด้านการให้บริการทั้งในด้านความรวดเร็ว ความสะดวกสบาย และมีมาตรฐานความตรงต่อเวลา ซึ่งในขณะนี้ได้เปิดให้บริการแล้ว 2 เส้นทาง ได้แก่ สายสุขุมวิท (จากสถานีหมอชิต-สถานีอ่อนนุช รวม 17 สถานี ระยะทางประมาณ 1.8 กม.) สายสีลม (จากสถานีสนามกีฬาแห่งชาติ-สถานีวงเวียนใหญ่ รวม 8 สถานี ระยะทาง 8.5 กม.)','กรุงเทพมหานคร','["BTS","กรุงเทพ"]','["ZIP","MAP","XML","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/5726250c-a66c-40a7-8c66-aa2781388186/resource/e1ab5112-1d7d-4abf-96fc-4ab383c95d2c/download/bangkok-mass-transit-system-bts-zhh2rr.zip"},{"name":"เส้นทางรถไฟลอยฟ้า (Bangkok Mass Transit System :BTS) ในพื้นที่เขตกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/5726250c-a66c-40a7-8c66-aa2781388186/resource/78e6b714-ff35-40e3-8e47-5a6839a36c0a/download/bts_line.zip"},{"name":"เส้นทางรถไฟลอยฟ้า (Bangkok Mass Transit System :BTS) ในพื้นที่เขตกรุงเทพมหานคร (KML)","format":"MAP","url":"https://data.go.th/dataset/5726250c-a66c-40a7-8c66-aa2781388186/resource/ff9b9eca-9671-40cc-af02-e1fdf267fd5e/download/bts_line.kml"},{"name":"เส้นทางรถไฟลอยฟ้า (Bangkok Mass Transit System :BTS) ในพื้นที่เขตกรุงเทพมหานคร (GML)","format":"XML","url":""},{"name":"เส้นทางรถไฟลอยฟ้า (Bangkok Mass Transit System :BTS) ในพื้นที่เขตกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/5726250c-a66c-40a7-8c66-aa2781388186/resource/9f7c7598-7aea-4988-b7c7-8bf8947628f3/download/bts_line.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/5726250c-a66c-40a7-8c66-aa2781388186/resource/10bab03a-518b-441b-8255-e7d779395a01/download/bts_line.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:31.891268','https://data