INSERT OR REPLACE INTO datasets VALUES ('public_park','ที่ตั้งสวนสาธารณะของกรุงเทพมหานคร','ชั้นข้อมูลที่ตั้งสวนสาธารณะของกรุงเทพมหานคร สวนสาธารณะของกรุงเทพมหานคร หมายถึง สวนสาธารณะหลักที่อยู่ในความรับผิดชอบของกรุงเทพมหานคร โดยมีคุณสมบัติดังนี้ 1. สามารถรอบรับและให้บริการประชาชนทั่วไป โดยไม่จำกัดประเภทและข้อจำกัดการใช้ 2.มีพื้นที่ตั้งแต่ 10 ไร่ขึ้นไป 3.มีพันธุ์ไม้หลากหลายซึ่งจำเป็นต้องใช้เทคนิคทางวิชาการในการดูแลเป็นพิเศษ มีการปลูกไม้ดอก ไม้ประดับหมุดเวียนตลอดปี และมีเรือนเพาะชำพันธุ์ไม้ 4.มีสิ่งอำนวยความสะดวกต่างๆ ทั้งส่วนนันทนาการและการกีฬา เช่น สนามเด็กเล่น สระว่ายน้ำ ฯลฯ มีส่วนของการศึกษาหาความรู้ เช่น ห้องสมุดประชาชน สวนพฤกษศาสตร์ 5.มีกิจกรรมอย่างต่อเนื่อง เป็นกิจจะลักษณะอย่างส…','กรุงเทพมหานคร','["กรุงเทพมหานคร","ที่ตั้ง","สวน","สวนสาธารณะ"]','["MAP","JSON","PDF","ZIP"]',6,'[{"name":"ที่ตั้งสวนสาธารณะของกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/21bec4a3-22e7-4ad7-9b0c-370d7c37d799/resource/8cb15a2c-a038-40ee-b2d5-f5ca38de831a/download/public_park.gml"},{"name":"ที่ตั้งสวนสาธารณะของกรุงเทพมหานคร (KML)","format":"MAP","url":"https://data.go.th/dataset/21bec4a3-22e7-4ad7-9b0c-370d7c37d799/resource/63620f66-2ea0-4069-88ae-59fb0c922135/download/public_park.kml"},{"name":"ที่ตั้งสวนสาธารณะของกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/21bec4a3-22e7-4ad7-9b0c-370d7c37d799/resource/f3088111-6685-4571-a603-19e78696c232/download/public_park.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/21bec4a3-22e7-4ad7-9b0c-370d7c37d799/resource/6b43ba76-3bb1-4d3a-8fc5-ef1d8e0f0624/download/public_park.pdf"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/21bec4a3-22e7-4ad7-9b0c-370d7c37d799/resource/d4db5e5c-2fe9-4b44-a4ee-bbe7c75460b6/download/public_park-7stxdw.zip"},{"name":"ที่ตั้งสวนสาธารณะของกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/21bec4a3-22e7-4ad7-9b0c-370d7c37d799/resource/457872fb-8542-41fb-be07-9c52732f0482/download/public_park.zip