INSERT OR REPLACE INTO datasets VALUES ('tourism_kios','ซุ้มบริการการท่องเที่ยวกรุงเทพมหานคร','ชั้นข้อมูลซุ้มบริการการท่องเที่ยวกรุงเทพมหานคร ซุ้มบริการ การท่องเที่ยว จัดสร้างเพื่อให้บริการตอบคำถามนักท่องเที่ยว ชาวไทย และชาวต่างประเทศ สนับสนุนข้อมูล เอกสาร หนังสือ สื่อสิ่งพิมพ์ ด้านการท่องเที่ยว ประสานหน่วยงานที่เกี่ยวกับการช่วยเหลือ นักท่องเที่ยว เช่น ตำรวจท่องเที่ยว สำนักงานตำรวจท้องที่','กรุงเทพมหานคร','["กรุงเทพมหานคร","ซุ้ม","ซุ้มท่องเที่ยว","ที่ตั้ง","ท่องเที่ยว"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/ca131c05-8766-418f-b89e-0981db6be16b/resource/eb37c601-075d-4b6d-81f7-388bce51a8f9/download/tourism_kios-6ei4ox.zip"},{"name":"ซุ้มบริการการท่องเที่ยวกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/ca131c05-8766-418f-b89e-0981db6be16b/resource/f171b6ea-7b02-4c85-aa92-d3a48e57b769/download/tourism_kios.zip"},{"name":"ซุ้มบริการการท่องเที่ยวกรุงเทพมหานคร","format":"MAP","url":"https://data.go.th/dataset/ca131c05-8766-418f-b89e-0981db6be16b/resource/8521b115-ebf5-437e-98a6-c3988f8a68bb/download/tourism_kios.kml"},{"name":"ซุ้มบริการการท่องเที่ยวกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/ca131c05-8766-418f-b89e-0981db6be16b/resource/fe8e94d1-0ac4-49af-8688-c11a8be80c29/download/tourism_kios.gml"},{"name":"ซุ้มบริการการท่องเที่ยวกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/ca131c05-8766-418f-b89e-0981db6be16b/resource/bfcd3126-23a9-4cea-99e7-9fa21f4256b3/download/tourism_kios.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/ca131c05-8766-418f-b89e-0981db6be16b/resource/721a92dd-1c23-4270-8457-387af7249c4e/download/tourism_kios.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:23.331802','https://data.go.th/dataset/tourism_kios');
INSERT OR REPLACE INTO datasets VALUES ('eco_tourism','พื้นที่แหล่งท่องเที่ยวเชิงอนุรักษ์ในเขตพื้นที่กรุงเทพมหานคร','ชั้นข้อมูลพื้นที่แหล่งท่องเที่ยวเชิงอนุรักษ์ในเขตพื้นที่กรุงเทพมหานคร เป็นโครงการชุมชนท่องเที่ยวเชิงอนุรักษ์อย่างยั่งยืนของ นายอภิรักษ์ โกษะโยธิน ผู้ว่าราชการกรุงเทพมหานคร ภายใต้แคมเปญ "ที่สุดในกรุงเทพ" เพื่อกระตุนเศรษฐกิจของกรุงเทพมหานครด้วยการส่งเสริมการท่องเที่ยว โดยรวบรวมความเป็นที่สุดในกรุงเทพมหานครมาจัดเป็นกิจกรรมตามกรอบวิสัยทัศน์ และยุทธศาสตร์การพัฒนา2ด้าน คือการพัฒนาแหล่งท่องเที่ยวเชิงอนุรักษ์อย่างยั่งยืน และส่งเสริมการท่องเที่ยวให้ได้มาตรฐานระดับสากล ส่งเสริมการท่องเที่ยวของกรุงเทพมหานครให้ได้มาตรฐานในระดับสากล','กรุงเทพมหานคร','["กรุงเทพมหานคร","ที่ตั้ง","ท่องเที่ยว","ท่องเที่ยวเชิงอนุรักษ์"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/a0ce3576-3d5f-437d-b610-e7bd219d30e3/resource/aaf9bb2a-2fc1-467c-b5c7-a444a7874499/download/eco_tourism-_avhz8.zip"},{"name":"พื้นที่แหล่งท่องเที่ยวเชิงอนุรักษ์ในเขตพื้นที่กรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/a0ce3576-3d5f-437d-b610-e7bd219d30e3/resource/711de3b1-4b1a-465e-ba58-1baa2ddb2c02/download/eco_tourism.zip"},{"name":"พื้นที่แหล่งท่องเที่ยวเชิงอนุรักษ์ในเขตพื้นที่กรุงเทพมหานคร (KML)","format":"MAP","url":"https://data.go.th/dataset/a0ce3576-3d5f-437d-b610-e7bd219d30e3/resource/3f90fdaa-74bb-447d-8245-1af30520224c/download/eco_tourism.kml"},{"name":"พื้นที่แหล่งท่องเที่ยวเชิงอนุรักษ์ในเขตพื้นที่กรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/a0ce3576-3d5f-437d-b610-e7bd219d30e3/resource/efaeeed7-e597-4fcb-9c4b-0e85d710106c/download/eco_tourism.gml"},{"name":"พื้นที่แหล่งท่องเที่ยวเชิงอนุรักษ์ในเขตพื้นที่กรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/a0ce3576-3d5f-437d-b610-e7bd219d30e3/resource/cdc18ae2-72ed-44d6-b596-0e8509d90a95/download/eco_tourism.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/a0ce3576-3d5f-437d-b610-e7bd219d3