INSERT OR REPLACE INTO datasets VALUES ('church','ที่ตั้งโบสถ์ที่ขึ้นทะเบียนกับสภาคริสตจักรในประเทศไทยในพื้นที่เขตกรุงเทพมหานคร','ชั้นข้อมูลที่ตั้งโบสถ์ที่ขึ้นทะเบียนกับสภาคริสตจักรในประเทศไทยในพื้นที่เขตกรุงเทพมหานคร โบสถ์คริสต์ หมายถึง อาคารสถานที่ ที่ผู้นับถือศาสนาคริสต์มารวมตัวกันเพื่อประกอบพิธีหรือทาศาสนกิจร่วมกัน เช่นเผยแพร่พระกิตติคุณและรับใช้พระเจ้าและชุมชน ตามน้าพระทัยของพระเจ้าด้วยวิธีการเลี้ยงตนเอง ปกครองตนเองและสร้างเสริมกิจกรรมทั้งปวงให้เจริญเติบโตยิ่งขึ้น ซึ่งการจัดตั้งจะต้องจดทะเบียนกับสภาคริสตจักรในประเทศไทย','กรุงเทพมหานคร','["กรุงเทพมหานคร","คริสตจักร","ที่ตั้ง","โบสถ์"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/04d501d3-d6d2-4ab5-946f-043686561f5b/resource/422d05d2-8c5b-4015-a3da-9d08e42a9dc8/download/church-b83ygo.zip"},{"name":"ที่ตั้งโบสถ์ที่ขึ้นทะเบียนกับสภาคริสตจักรในประเทศไทยในพื้นที่เขตกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/04d501d3-d6d2-4ab5-946f-043686561f5b/resource/3556ee03-6cbe-4238-865f-6914edc7dfb8/download/church.zip"},{"name":"ที่ตั้งโบสถ์ที่ขึ้นทะเบียนกับสภาคริสตจักรในประเทศไทยในพื้นที่เขตกรุงเทพมหานคร (KML)","format":"MAP","url":"https://data.go.th/dataset/04d501d3-d6d2-4ab5-946f-043686561f5b/resource/11c057b4-6ac9-4f62-8df4-77fc5e35723c/download/church.kml"},{"name":"ที่ตั้งโบสถ์ที่ขึ้นทะเบียนกับสภาคริสตจักรในประเทศไทยในพื้นที่เขตกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/04d501d3-d6d2-4ab5-946f-043686561f5b/resource/312001d3-bf0a-4407-ba58-c13234f3cd82/download/church.gml"},{"name":"ที่ตั้งโบสถ์ที่ขึ้นทะเบียนกับสภาคริสตจักรในประเทศไทยในพื้นที่เขตกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/04d501d3-d6d2-4ab5-946f-043686561f5b/resource/cfe01af3-4f88-47ba-bcc9-16348623ec22/download/church.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/04d501d3-d6d2-4ab5-946f-043686561f5b/resource/355dbdb9-5462-4e2b-9bdd-0896b7d21d3e/download/church.pdf"}]','Creative 