INSERT OR REPLACE INTO datasets VALUES ('post_office','ที่ตั้งที่ทำการไปรษณีย์ไทยในเขตพื้นที่กรุงเทพมหานคร','ชั้นข้อมูลที่ตั้งที่ทำการไปรษณีย์ไทยในเขตพื้นที่กรุงเทพมหานคร ที่ทำการไปรษณีย์ให้บริการการสื่อสาร, การขนส่ง, ค้าปลีก และการเงิน ครอบคลุมพื้นที่ทั่วประเทศ ซึ่งการบริการที่สำคัญของหน่วยไปรษณีย์ภัณฑ์ ได้แก่ 1. จดหมาย จดหมายอากาศ ไปรษณียบัตร ของตีพิมพ์ พัสดุย่อย เครื่องอ่านสำหรับคนเสียจักษุ 2. postal parcel เช่น พัสดุไปรษณีย์ในประเทศ, พัสดุุไปรษณีย์ระหว่างประเทศ 3. ไปรษณีย์ด่วนพิเศษ 4. บริการพิเศษ เช่น ไปรษณีย์รับรอง ไปรษณีย์ลงทะเบียน ไปรษณีย์รับประกัน ไปรษณีย์ตอบรับ นำจ่ายด่วน ธุรกิจตอบรับ','กรุงเทพมหานคร','["กรุงเทพมหานคร","ที่ตั้ง","ไปรษณีย์"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/8e2f0fb9-a01c-4584-8e87-0f7a8b1f4d33/resource/473fa9f2-da81-43bf-b8a4-f82951daf0fc/download/post_office-pttmik.zip"},{"name":"ที่ตั้งที่ทำการไปรษณีย์ไทยในเขตพื้นที่กรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/8e2f0fb9-a01c-4584-8e87-0f7a8b1f4d33/resource/e08355a3-63f4-469c-8702-74542384a4a3/download/post_office.zip"},{"name":"ที่ตั้งที่ทำการไปรษณีย์ไทยในเขตพื้นที่กรุงเทพมหานคร (KML)","format":"MAP","url":"https://data.go.th/dataset/8e2f0fb9-a01c-4584-8e87-0f7a8b1f4d33/resource/59b1d6aa-8cfe-4378-b1bb-28e47fc9e6c9/download/bmawms-post_office.kml"},{"name":"ที่ตั้งที่ทำการไปรษณีย์ไทยในเขตพื้นที่กรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/8e2f0fb9-a01c-4584-8e87-0f7a8b1f4d33/resource/7bed4079-58c8-4c46-99b6-2e53796f2528/download/post_office.gml"},{"name":"ที่ตั้งที่ทำการไปรษณีย์ไทยในเขตพื้นที่กรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/8e2f0fb9-a01c-4584-8e87-0f7a8b1f4d33/resource/131d2491-3eef-45cd-b81d-5d7056e14d11/download/post_office.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/8e2f0fb9-a01c-4584-8e87-0f7a8b1f4d33/resource/52ad9349-b21f-4e46-857a-0d1222a011d8/download/post_office.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:21.037893','https://data.go.th/dataset/post_office');
