INSERT OR REPLACE INTO datasets VALUES ('department_store','ที่ตั้งห้างสรรพสินค้าในพื้นที่กรุงเทพมหานคร','ชั้นข้อมูลที่ตั้งห้างสรรพสินค้าในพื้นที่กรุงเทพมหานคร ห้างสรรพสินค้า คือ ร้านค้าขายปลีกขนาดใหญ่ซึ่งมีสินค้าหลากหลายประเภทแยกตามแผนก เช่น เสื้อผ้า เครื่องใช้ เครื่องเรือนภายในบ้าน เครื่องใช้ไฟฟ้า เป็นต้น และเป็นพื้นที่ทางสังคมในลักษณะใหม่ เช่น พื้นที่แห่งการพักผ่อนหย่อนใจ (Leisure) และเป็นการสร้างพื้นที่ชุมชนของกลุ่มคนที่มีความสนใจเหมือนกัน อาทิ พื้นที่สำหรับเรียนพิเศษ พื้นที่ของวัยรุ่นและเยาวชนในด้านต่างฯ','กรุงเทพมหานคร','["กรุงเทพมหานคร","ที่ตั้ง","ห้าง","ห้างสรรพสินค้า"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/24c949fc-a032-480e-a7ce-7f88ac41f00e/resource/b0f6fe27-40c7-452b-8668-e64adc3061f5/download/department_store-1ga5f9.zip"},{"name":"ที่ตั้งห้างสรรพสินค้าในพื้นที่กรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/24c949fc-a032-480e-a7ce-7f88ac41f00e/resource/cc94d7d4-8dfd-47a4-85cb-8406597ecbfb/download/department_store.zip"},{"name":"ที่ตั้งห้างสรรพสินค้าในพื้นที่กรุงเทพมหานคร (KML)","format":"MAP","url":"https://data.go.th/dataset/24c949fc-a032-480e-a7ce-7f88ac41f00e/resource/06479481-e83f-46c0-b584-308adb9475eb/download/department_store.kml"},{"name":"ที่ตั้งห้างสรรพสินค้าในพื้นที่กรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/24c949fc-a032-480e-a7ce-7f88ac41f00e/resource/8d5a50c2-d28d-4869-bd63-5fd10e69572b/download/department_store.gml"},{"name":"ที่ตั้งห้างสรรพสินค้าในพื้นที่กรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/24c949fc-a032-480e-a7ce-7f88ac41f00e/resource/913fd3cc-e839-4c00-a5d6-07e6c073752c/download/department_store.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/24c949fc-a032-480e-a7ce-7f88ac41f00e/resource/aba85f84-d0c7-40ed-92bb-8af4b7753427/download/department_store.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:13.512169','https://data.go.th/dataset/departme