INSERT OR REPLACE INTO datasets VALUES ('zoo','ที่ตั้งสวนสัตว์ในพื้นที่เขตกรุงเทพมหานคร','ชั้นข้อมูลที่ตั้งสวนสัตว์ในพื้นที่เขตกรุงเทพมหานคร 1.สวนสัตว์เป็นสถานที่จัดแสดงสัตว์ป่าที่จับมาได้จากป่าใหญ่ หรือนำเข้าจากต่างประเทศ และมีส่วนอนุรักษ์วิจัยเพื่อศึกษาชีวิตของสัตว์ป่าทุกชนิด จะเป็นสัตว์ป่า สัตว์ปีก สัตว์เลื้อยคลาน และสัตว์น้ำที่จับมาจากทะเล แม่น้ำ 2. สวนสัตว์ในประเทศไทยอยู่ในความดูแลของหน่วยงานราชการ เรียนกว่า องค์การสวนสัตว์ในพระบรมราชูปถัมภ์ และอยู่ในความดูแลของภาคเอกชน','กรุงเทพมหานคร','["กรุงเทพมหานคร","ที่ตั้ง","สวนสัตว์"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/79ec2d0b-d439-4690-a358-e1b835256f46/resource/5b4002ac-4eed-4354-886a-73ecf1dc8c95/download/zoo-bwyxtk.zip"},{"name":"ที่ตั้งสวนสัตว์ในพื้นที่เขตกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/79ec2d0b-d439-4690-a358-e1b835256f46/resource/a4d1810d-1d51-4770-92f0-f213d4f3f232/download/zoo.zip"},{"name":"ที่ตั้งสวนสัตว์ในพื้นที่เขตกรุงเทพมหานคร (KMZ)","format":"MAP","url":"https://data.go.th/dataset/79ec2d0b-d439-4690-a358-e1b835256f46/resource/add89078-93fc-49a5-b2bf-8e9df2740760/download/zoo.kml"},{"name":"ที่ตั้งสวนสัตว์ในพื้นที่เขตกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/79ec2d0b-d439-4690-a358-e1b835256f46/resource/3c507f4c-f0fa-475f-b692-cda7f1105246/download/zoo.gml"},{"name":"ที่ตั้งสวนสัตว์ในพื้นที่เขตกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/79ec2d0b-d439-4690-a358-e1b835256f46/resource/0db8b9b2-1a64-4ba3-a019-82fb49aa56a7/download/zoo.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/79ec2d0b-d439-4690-a358-e1b835256f46/resource/744be70d-6bec-42bf-86b4-ed3f87036f3e/download/zoo.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:12.587664','https://data.go.th/dataset/zoo');
INSERT OR REPLACE INTO datasets VALUES ('market','ที่ตั้งตลาดในเขตกรุงเทพมหานคร','ชั้นข้อมูลที่ตั้งตลาดในเขตกรุงเทพมหานคร 1.ตลาด ในการนำเสนอหมายถึง ตลาดที่มีโครงสร้าง เป็นสถานที่ซึ่งจัดไว้เพื่อจำหน่ายสินค้าประเภทสัตว์ เนื้อสัตว์ ผัก ผลไม้ หรืออาหารมีสภาพเป็นของสด ประกอบหรือปรุงแล้ว หรือของเสียง่ายซึ่งมีไว้จำหน่ายเป็นประจำหรือเป็นครั้งคราวตามที่กำหนด ความแตกต่างระหว่างตลาดเอกชนกับตลาดของกรุงเทพมหานคร คือ ตลาดเอกชนจะจัดตั้งได้ ต้องได้รับใบอนุญาตจากเจ้าพนักงานท้องถิ่นตาม มาตรา 38 ของพระราชบัญญัติการสาธารณสุข พ.ศ. 2535 2. การขอจัดตั้งตลาดในเขตพื้นที่กรุงเทพมหานคร ต้องเป็นไปตามข้อบัญญัติกรุงเทพมหานครเรื่อง ตลาด พ.ศ. 2546 และกฎกระทรวงว่าด้วยสุขลักษณะของตลาด พ.ศ. 2551','กรุงเทพมหานคร','["กรุงเทพมหานคร","ตลาด","ที่ตั้ง"]','["ZIP","XML","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/b7fddf41-d345-4383-90dc-4dcf230a341e/resource/754faec2-7bd8-4ebe-84ca-0a291a7d9690/download/market-ith5w1.zip"},{"name":"ที่ตั้งตลาดในเขตกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/b7fddf41-d345-4383-90dc-4dcf230a341e/resource/3fd4b480-63cc-492d-83d5-14e33812c1df/download/market.zip"},{"name":"ที่ตั้งตลาดในเขตกรุงเทพมหานคร (KMZ)","format":"XML","url":""},{"name":"ที่ตั้งตลาดในเขตกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/b7fddf41-d345-4383-90dc-4dcf230a341e/resource/ed75ae3f-7fcd-400b-8b19-340c349da31a/download/market.gml"},{"name":"ที่ตั้งตลาดในเขตกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/b7fddf41-d345-4383-90dc-4dcf230a341e/resource/bbfa1210-0be6-4c82-a6ba-a9521d9470fd/download/market.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/b7fddf41-d345-4383-90dc-4dcf230a341e/resource/ca5a63f7-50c5-4edf-bf4e-8262f3af6202/download/market.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:11.470322','https://data.go.th/dataset/market');
INSERT OR REPLACE INTO datasets VALUES ('community','ที่ตั้งชุมชนในพื้นที่เขตกรุงเทพมหานคร','ที่ตั้งชุมชนในพื้นที่เขตกรุงเทพมหานคร ชุมชนหมายถึง ชุมชนแออัด ชุมชนชานเมือง เคหะชุมชน หมู่บ้านจัดสรร และชุมชนเมืองที่กรุงเทพมหานครกำหนดขึ้น ทั้งนี้โดยทำเป็นประกาศกรุงเทพมหานครตามระเบียบว่าด้วยกรรมการชุมชน 1. ชุมชนแออัด หมายถึง ชุมชนส่วนใหญ่ที่มีอาคารหนาแน่น ไร้ระเบียบ และชำรุดทรุดโทรม ประชาชนอยู่อย่างแออัด สภาพแวดล้อมไม่เหมาะสมอันอาจเป็นอันตรายต่อสุขภาพอนามัยและความปลอดภัยของผู้อยู่อาศัย โดยให้ถือเกณฑ์ความหนาแน่นของบ้านเรือนอย่างน้อย 15 หลังคาเรือนต่อพื้นที่ 1 ไร่ 2. ชุมชนชานเมือง หมายถึง ชุมชนที่กรุงเทพมหานครได้จัดทำเป็นประกาศกำหนดชุมชน โดยมีพื้นที่ดำเนินการด้านเกษตรกรรม ในเขตกรุงเทพมหานครรอ…','กรุงเทพมหานคร','["กรุงเทพมหานคร","ชุมชน","ที่ตั้ง"]','["ZIP","MAP","JSON","PDF"]',6,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/20b60628-b806-43f9-a19e-0097a5d6b0c9/resource/c6356dea-a737-41e6-aa2a-3bd0b5840284/download/community-wrngbt.zip"},{"name":"ที่ตั้งชุมชนในพื้นที่เขตกรุงเทพมหานคร","format":"ZIP","url":"https://data.go.th/dataset/20b60628-b806-43f9-a19e-0097a5d6b0c9/resource/c1ad68b6-3572-414c-a4ad-a03a5596119f/download/community.zip"},{"name":"ที่ตั้งชุมชนในพื้นที่เขตกรุงเทพมหานคร (KMZ)","format":"MAP","url":"https://data.go.th/dataset/20b60628-b806-43f9-a19e-0097a5d6b0c9/resource/706ceb41-7e26-47c0-a50d-43cb588eb775/download/community.kml"},{"name":"ที่ตั้งชุมชนในพื้นที่เขตกรุงเทพมหานคร (GML)","format":"MAP","url":"https://data.go.th/dataset/20b60628-b806-43f9-a19e-0097a5d6b0c9/resource/14515a3a-964d-4b5a-9949-f745289df24b/download/community.gml"},{"name":"ที่ตั้งชุมชนในพื้นที่เขตกรุงเทพมหานคร (JSON)","format":"JSON","url":"https://data.go.th/dataset/20b60628-b806-43f9-a19e-0097a5d6b0c9/resource/dc34f832-1910-499d-8eab-fa0134d7fd82/download/community.json"},{"name":"พจนานุกรมข้อมูล","format":"PDF","url":"https://data.go.th/dataset/20b60628-b806-43f9-a19e-0097a5d6b0c9/resource/b104a61f-8abf-486e-bd21-5629a604fdfb/download/community.pdf"}]','Creative Commons Attributions','2021-10-31T05:59:09.444604','https://data.go.th/dataset/community');
