INSERT OR REPLACE INTO datasets VALUES ('lpg-other','ปริมาณการจำหน่ายรายจังหวัด ก๊าซแอลพีจี สาขาอื่นๆ','ปริมาณการจำหน่าย ก๊าซแอลพีจี สาขาอื่นๆ ของผู้ค้าน้ำมันตามมาตรา 7 (ผู้ค้าน้ำมันตามมาตรา 7 คือ ผู้ค้าน้ำมันที่มีปริมาณการค้าแต่ละชนิด หรือรวมกันทุกชนิดปีละตั้งแต่หนึ่งแสนเมตริกตันขึ้นไป หรือเป็นผู้ค้าน้ำมันชนิดก๊าซปิโตรเลียมเหลวแต่เพียวชนิดเดียวที่มีปริมาณการค้าปีละตั้งแต่ห้าหมื่นเมตริกตันขึ้นไป)น้ำมันไปยังจังหวัดต่างๆ ทั้ง 77 จังหวัดของประเทศไทย','กรมธุรกิจพลังงาน','["ก๊าซแอลพีจี","ปริมาณการจำหน่ายรายจังหวัด","สาขาอื่นๆ"]','["ZIP","CSV"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/88351b7d-e662-4b04-81a3-8b2ee0878eb3/resource/3ee6e836-bc96-4e31-b873-9335ca5bf995/download/lpg-other-sdlff2.zip"},{"name":"","format":"CSV","url":"https://data.go.th/dataset/88351b7d-e662-4b04-81a3-8b2ee0878eb3/resource/58a159b3-f6e7-446e-8081-8f6e3ba8ea83/download/22-lpg-20-06jun-oth.csv"},{"name":"ปริมาณการจำหน่ายรายจังหวัด ก๊าซแอลพีจี สาขาอื่นๆ เดือน มิถุนายน 2563","format":"CSV","url":"https://data.go.th/dataset/88351b7d-e662-4b04-81a3-8b2ee0878eb3/resource/594ba69c-fba9-42a9-bdfd-9861328c8e89/download/22-lpg-20-06jun-oth.csv"}]','Creative Commons Attributions','2021-10-31T05:55:38.293850','https://data.go.th/dataset/lpg-other');
