INSERT OR REPLACE INTO datasets VALUES ('95premium-other','ปริมาณการจำหน่ายรายจังหวัด น้ำมันแก๊สโซฮอล์ 95 (ชนิดพิเศษ) สาขาอื่นๆ','ปริมาณการจำหน่าย น้ำมันแก๊สโซฮอล์ 95 (ชนิดพิเศษ) ของผู้ค้าน้ำมันตามมาตรา 7 (ผู้ค้าน้ำมันตามมาตรา 7 คือ ผู้ค้าน้ำมันที่มีปริมาณการค้าแต่ละชนิด หรือรวมกันทุกชนิดปีละตั้งแต่หนึ่งแสนเมตริกตันขึ้นไป หรือเป็นผู้ค้าน้ำมันชนิดก๊าซปิโตรเลียมเหลวแต่เพียวชนิดเดียวที่มีปริมาณการค้าปีละตั้งแต่ห้าหมื่นเมตริกตันขึ้นไป)น้ำมันไปยังจังหวัดต่างๆ ทั้ง 77 จังหวัดของประเทศไทย','กรมธุรกิจพลังงาน','["ชนิดพิเศษ","น้ำมันแก๊สโซฮอล์","ปริมาณการจำหน่ายรายจังหวัด","สาขาอื่นๆ","ออกเทน 95","อี 10"]','["CSV","ZIP"]',2,'[{"name":"ปริมาณการจำหน่ายรายจังหวัด น้ำมันแก๊สโซฮอล์ 95 (ชนิดพิเศษ) สาขาอื่นๆ","format":"CSV","url":"https://data.go.th/dataset/bf86a0eb-d390-4b36-9994-364a92c0650e/resource/26cbf3ce-9497-47f0-9894-423d619e5368/download/07_95premium_19_02feb_oth_.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/bf86a0eb-d390-4b36-9994-364a92c0650e/resource/237cfa16-71d8-46df-b4e4-dad96faa4006/download/95premium-other-z0thuc.zip"}]','Creative Commons Attributions','2021-10-31T05:52:48.558265','https://data.go.th/dataset/95premium-other');
