INSERT OR REPLACE INTO datasets VALUES ('101-105-106-2563','ข้อมูลโรงงานประเภท 101,105,106 เดือนกุมภาพันธ์ 2563','ข้อมูลโรงงานประเภท 101,105,106 เดือนกุมภาพันธ์ 2563','กรมโรงงานอุตสาหกรรม','["อุตสาหกรรม"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/47f426c8-d91d-4121-9d13-607fdddd508e/resource/323487fc-cdac-4300-b7f1-a18f26b61e7e/download/101-105-106-2563-eaum_s.zip"},{"name":"ข้อมูลโรงงานประเภท 101,105,106 เดือนกุมภาพันธ์ 2563","format":"CSV","url":"https://data.go.th/dataset/47f426c8-d91d-4121-9d13-607fdddd508e/resource/8f60076e-d3f6-4ef0-8dac-c5254c289521/download/63-feb_101-105-106.csv"}]','Creative Commons Attributions','2021-10-31T05:52:17.912996','https://data.go.th/dataset/101-105-106-2563');
INSERT OR REPLACE INTO datasets VALUES ('item_19ed0e63-c7dd-4913-8ea5-1eb5ca3e4c6d','ผลการสำรวจความพึงพอใจด้านระบบอินเทอร์เน็ต/WiFi ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อระบบอินเทอร์เน็ต/WiFi ในภาพรวมในระดับพอใจ (คะแนนเต็ม 5)','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/cb00ce66-571d-4ece-bd18-bcebaeccb0cf/resource/59aadcfb-d327-4997-8341-f98b7c201ead/download/item_19ed0e63-c7dd-4913-8ea5-1eb5ca3e4c6d-mjzjkf.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านระบบอินเทอร์เน็ต/WiFi ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในป…","format":"CSV","url":"http://www.mots.go.th/download/opendata/wi-fi.csv"}]','Creative Commons Attributions','2021-10-31T05:52:12.315101','https://data.go.th/dataset/item_19ed0e63-c7dd-4913-8ea5-1eb5ca3e4c6d');
INSERT OR REPLACE INTO datasets VALUES ('item_68eb0aeb-bb82-4a3b-b415-5d9e244784f4','ผลการสำรวจความพึงพอใจด้านศูนย์บริการข้อมูลข่าวสารนักท่องเที่ยว ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความ พึงพอใจต่อการให้บริการศูนย์บริการข้อมูลข่าวสารนักท่องเที่ยวในภาพรวมในระดับพอใจ และมีความพึงพอใจในระดับพอใจในทุกประเด็น ได้แก่ การต้อนรับ การใช้ประโยชน์ของข้อมูล การบริการ ความสะดวกในการเข้าถึง แ…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["การตอนรับ","การบริการ","การสื่อสาร","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/f3df310f-6244-45a7-b0d1-8bf56eadeeef/resource/81e8fcc4-7deb-427a-b2e4-f3ad691b9c26/download/item_68eb0aeb-bb82-4a3b-b415-5d9e244784f4-uiewa5.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านศูนย์บริการข้อมูลข่าวสารนักท่องเที่ยว ของนักท่องเที่ยวชาวต่างประเทศที่เดิน…","format":"CSV","url":"http://www.mots.go.th/download/opendata/service.csv"}]','Creative Commons Attributions','2021-10-31T05:52:11.737650','https://data.go.th/dataset/item_68eb0aeb-bb82-4a3b-b415-5d9e244784f4');
INSERT OR REPLACE INTO datasets VALUES ('item_f48c8b85-de10-4641-ad7d-3974c90dd9ce','นิคมอุตสาหกรรมในประเทศไทย','นิคมอุตสาหกรรมในประเทศไทย','การนิคมอุตสาหกรรมแห่งประเทศไทย','["นิคมอุตสาหกรรม"]','["ZIP"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/5a43088c-bb38-4af8-9aee-4520dff286f4/resource/413b0d44-cf14-470a-9645-fd4a33c16acf/download/item_f48c8b85-de10-4641-ad7d-3974c90dd9ce-2eiqpx.zip"},{"name":"นิคมอุตสาหกรรมในประเทศไทย","format":null,"url":"http://www.ieat.go.th/investment/about-industrial-estates/industrial-estates-in-thailand"}]','Creative Commons Attributions','2021-10-31T05:52:10.616137','https://data.go.th/dataset/item_f48c8b85-de10-4641-ad7d-3974c90dd9ce');
INSERT OR REPLACE INTO datasets VALUES ('item_e2cb09e3-7967-48eb-930d-ab9538762be3','ผลการสำรวจความพึงพอใจด้านบริการเพื่อสุขภาพ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อบริการเพื่อสุขภาพ (สปา/นวดแผนไทย ฯลฯ) ในภาพรวมในระดับพอใจมาก และมีความพึงพอใจในระดับพอใจมากในทุกประเด็นที่ประเมิน ได้แก่ ความหลากหลาย การบริการ ความปลอดภัย ความซื่อสัตย์ และการติดต่อสื่…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["การบริการ","การสื่อสาร_ภาษา","ความหลากหลาย","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/ac54e19d-d867-4b8d-97de-675787ffb21a/resource/49690927-72fa-44b7-a47e-5a93efff155c/download/item_e2cb09e3-7967-48eb-930d-ab9538762be3-dlfr9g.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านบริการเพื่อสุขภาพ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเท…","format":"CSV","url":"http://www.mots.go.th/download/opendata/health.csv"}]','Creative Commons Attributions','2021-10-31T05:52:10.130386','https://data.go.th/dataset/item_e2cb09e3-7967-48eb-930d-ab9538762be3');
INSERT OR REPLACE INTO datasets VALUES ('item_250ca575-4003-4091-a8b7-36735aa8b8eb','ผลการสำรวจความพึงพอใจด้านกิจกรรม/สถานที่ท่องเที่ยว ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อกิจกรรม/สถานที่ท่องเที่ยวในภาพรวมในระดับพอใจ และมีความพอใจระดับพอใจในทุกประเด็นที่ประเมิน ได้แก่ ความหลากหลาย ความน่าตื่นเต้น การบริการ ความคุ้มค่าเงิน และความปลอดภัย &nbsp; &nbsp; &nbs…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["การบริการ","ความปลอดภัย","ความหลากหลาย","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/a8850f66-726c-4dbb-907c-e4088752e6c5/resource/8862307c-32fd-4cf1-9a0d-ce71c2e63a07/download/item_250ca575-4003-4091-a8b7-36735aa8b8eb-apr74h.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านกิจกรรม/สถานที่ท่องเที่ยว ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ย…","format":"CSV","url":"http://www.mots.go.th/download/opendata/Attractions.csv"}]','Creative Commons Attributions','2021-10-31T05:52:08.590875','https://data.go.th/dataset/item_250ca575-4003-4091-a8b7-36735aa8b8eb');
INSERT OR REPLACE INTO datasets VALUES ('item_e4de0105-2441-467d-8e37-aea043b06c77','การส่งเสริมการอนุรักษ์พลังงานในโรงงานอุตสาหกรรมขนาดกลางและขนาดเล็ก ผลการดำเนินงาน (toe/ปี) รายจังหวัด ปีงบประมาณ 2560','การส่งเสริมการอนุรักษ์พลังงานในโรงงานอุตสาหกรรมขนาดกลางและขนาดเล็ก ผลการดำเนินงาน (toe/ปี) รายจังหวัด ปีงบประมาณ 2560','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','[]','["ZIP"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/6a07490e-0094-4868-a331-241e1bb29fe0/resource/555db1e6-2da5-452f-96d3-0e2cf7ba61b5/download/item_e4de0105-2441-467d-8e37-aea043b06c77-dx7fyr.zip"},{"name":"การส่งเสริมการอนุรักษ์พลังงานในโรงงานอุตสาหกรรมขนาดกลางและขนาดเล็ก ผลการดำเนินงาน (toe/ปี) รายจังหว…","format":null,"url":"http://www.dede.go.th/ewt_dl_link.php?nid=47476"}]','Creative Commons Attributions','2021-10-31T05:52:07.046878','https://data.go.th/dataset/item_e4de0105-2441-467d-8e37-aea043b06c77');
INSERT OR REPLACE INTO datasets VALUES ('item_f8c0a77b-d335-4f11-af36-99fd10446b2c','ผลการสำรวจความพึงพอใจด้านห้องน้ำสาธารณะ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อ การให้บริการห้องน้ำสาธารณะในภาพรวมในระดับพอใจ และทุกประเด็นมีความพึงพอใจในระดับพอใจ ได้แก่ ความปลอดภัย ความพร้อมใช้งาน และความสะอาด &nbsp;(คะแนนเต็ม 5)','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["ความปลอดภัย","ความพร้อมใช้งาน","ความสะอาด","สำรวจความพึงพอใจ","ห้องน้ำสาธารณะ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/b35d755e-c7d0-4ed7-b9d0-b61fc5ee0292/resource/6162117b-805e-426f-89e0-092ed768fd7b/download/item_f8c0a77b-d335-4f11-af36-99fd10446b2c-xxwxvy.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านห้องน้ำสาธารณะ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย","format":"CSV","url":"http://www.mots.go.th/download/opendata/toilet.csv"}]','Creative Commons Attributions','2021-10-31T05:52:05.543575','https://data.go.th/dataset/item_f8c0a77b-d335-4f11-af36-99fd10446b2c');
