INSERT OR REPLACE INTO datasets VALUES ('item_ed8058a7-2795-438d-8302-f430357750ff','สรุปผลการจัดซื้อจัดจ้าง','สรุปผลการจัดซื้อจัดจ้างของสำนักงานปลัดกระทรวงเกษตรและสหกรณ์','สำนักงานปลัดกระทรวงเกษตรและสหกรณ์','[]','["ZIP","XML"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/de3e4478-18a9-4c83-9062-165cc34d9916/resource/baaa43db-ce5b-4cae-b4f0-e63afd4858e1/download/item_ed8058a7-2795-438d-8302-f430357750ff-hwy5jr.zip"},{"name":"สรุปผลการจัดซื้อจัดจ้าง","format":"XML","url":"http://www.opsmoac.go.th/rss/group1247.xml"}]','Creative Commons Attributions','2021-10-31T05:52:02.781332','https://data.go.th/dataset/item_ed8058a7-2795-438d-8302-f430357750ff');
INSERT OR REPLACE INTO datasets VALUES ('item_a5ce9eb0-101c-4c70-9933-9e5fad046d80','ผลการสำรวจความพึงพอใจด้านสถานที่พัก ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อสถานที่พัก ในภาพรวมในระดับพอใจ และมีความพึงพอใจในระดับพอใจในทุกประเด็นที่ประเมิน ได้แก่ ความปลอดภัย ความหลากหลาย การบริการ ความคุ้มค่าเงิน ทำเลที่ตั้ง อุปกรณ์เครื่องใช้ต่างๆ ความสะอาดแล…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["ความคุ้มค่าเงิน","ความปลอดภัย","ทำเลที่ตั้ง","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/b0af257f-cd7e-49be-a7aa-366af37bf326/resource/1df2c2a8-b138-433c-b30f-dfcabd8e95c7/download/item_a5ce9eb0-101c-4c70-9933-9e5fad046d80-rmszn1.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านสถานที่พัก ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย","format":"CSV","url":"http://www.mots.go.th/download/opendata/hostel.csv"}]','Creative Commons Attributions','2021-10-31T05:52:02.095882','https://data.go.th/dataset/item_a5ce9eb0-101c-4c70-9933-9e5fad046d80');
INSERT OR REPLACE INTO datasets VALUES ('item_627537af-679a-4a93-8bb6-c83775486a8d','ผลการสำรวจความพึงพอใจด้านความปลอดภัย ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งความปลอดภัย นักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อความปลอดภัยในภาพรวมในระดับพอใจ &nbsp; &nbsp; &nbsp; (คะแนนเต็ม 5)','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','[]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/4cdd3cd4-3b22-42bd-9359-232bb3dc114d/resource/18d69512-9b6f-41ac-bed1-522ae4fef692/download/item_627537af-679a-4a93-8bb6-c83775486a8d-g5usek.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านความปลอดภัย ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย","format":"CSV","url":"http://www.mots.go.th/download/opendata/security.csv"}]','Creative Commons Attributions','2021-10-31T05:52:01.005919','https://data.go.th/dataset/item_627537af-679a-4a93-8bb6-c83775486a8d');
INSERT OR REPLACE INTO datasets VALUES ('item_49bae7fe-51df-4a40-869a-01bd02a5f86f','ผลการสำรวจความพึงพอใจด้านภัตตาคาร/ร้านอาหาร ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อภัตตาคาร/ร้านอาหารในภาพรวมในระดับพอใจ และมีความพึงพอใจในระดับพอใจในทุกประเด็นที่ประเมิน ได้แก่ ความคุ้มค่าเงิน คุณภาพและรสชาติของอาหาร ความหลากหลาย ทาเลที่ตั้ง การบริการ และการติดต่อสื่…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["บริการ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/c7b6d4b2-3999-401a-acb5-f2ace78e1f4b/resource/98a16a18-a910-48a8-a4f6-922fc8a72522/download/item_49bae7fe-51df-4a40-869a-01bd02a5f86f-gwjf9q.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านภัตตาคาร/ร้านอาหาร ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเ…","format":"CSV","url":"http://www.mots.go.th/download/opendata/restaurant.csv"}]','Creative Commons Attributions','2021-10-31T05:51:59.804974','https://data.go.th/dataset/item_49bae7fe-51df-4a40-869a-01bd02a5f86f');
INSERT OR REPLACE INTO datasets VALUES ('item_16e60456-cc98-42ea-ac70-aff49aba9a1c','ผลการสำรวจความพึงพอใจด้านรถโดยสารสาธารณะ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อ การให้บริการรถโดยสารสาธารณะ เช่น รถประจาทาง รถแท็กซี่ รถไฟ เป็นต้น ในภาพรวมในระดับพอใจ และทุกประเด็นมีความพึงพอใจในระดับพอใจ ได้แก่ ความคุ้มค่าเงิน ความสะดวกในการใช้บริการ ความปลอดภัย…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["ความคุ้มค่าเงิน","ความปลอดภัย","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/ae493010-8e07-485d-950f-3f6f11854fd6/resource/9c8d1330-1049-4476-bf07-2df41362b391/download/item_16e60456-cc98-42ea-ac70-aff49aba9a1c-5ozbq6.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านรถโดยสารสาธารณะ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไ…","format":"CSV","url":"http://www.mots.go.th/download/opendata/bus.csv"}]','Creative Commons Attributions','2021-10-31T05:51:58.295595','https://data.go.th/dataset/item_16e60456-cc98-42ea-ac70-aff49aba9a1c');
INSERT OR REPLACE INTO datasets VALUES ('item_2ea677a1-6783-4b42-99bc-475c9701622e','ผลการสำรวจความพึงพอใจด้านการให้บริการโทรศัพท์ไปต่างประเทศ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความ พึงพอใจต่อการใช้โทรศัพท์ไปต่างประเทศในภาพรวมในระดับพอใจ &nbsp;(คะแนนเต็ม 5)','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/74570128-b02f-4d38-a77a-d01616f4c486/resource/c6dce556-a50c-4ed3-84a6-2e69b1645e9d/download/item_2ea677a1-6783-4b42-99bc-475c9701622e-mjt9l6.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านการให้บริการโทรศัพท์ไปต่างประเทศ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่…","format":"CSV","url":"http://www.mots.go.th/download/opendata/tell.csv"}]','Creative Commons Attributions','2021-10-31T05:51:57.623021','https://data.go.th/dataset/item_2ea677a1-6783-4b42-99bc-475c9701622e');
INSERT OR REPLACE INTO datasets VALUES ('item_cca48996-47ba-4679-a061-1439f7162fb0','ผลการสำรวจความพึงพอใจด้านมัคคุเทศก์ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อการให้บริการของมัคคุเทศก์ในภาพรวมในระดับพอใจ และมีความพึงพอใจในระดับพอใจในทุกประเด็นที่ประเมิน ได้แก่ ความเป็นมิตรมีอัธยาศัยดี ความรู้/ความสามารถ ความซื่อสัตย์ และการติดต่อสื่อสาร/ภาษา…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["การสื่อสาร_ภาษา","ความรู้_ความสามารถ","ความเป็นมิตร","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/f32560e8-5e2c-4a48-aa22-ae82fcf96d38/resource/43de025b-e486-407a-a218-1778bfcb7496/download/item_cca48996-47ba-4679-a061-1439f7162fb0-0o4m2d.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านมัคคุเทศก์ ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย","format":"CSV","url":"http://www.mots.go.th/download/opendata/guide.csv"}]','Creative Commons Attributions','2021-10-31T05:51:54.449872','https://data.go.th/dataset/item_cca48996-47ba-4679-a061-1439f7162fb0');
INSERT OR REPLACE INTO datasets VALUES ('item_88e3abfc-072a-4d77-98fd-5b782163180e','ผลการสำรวจความพึงพอใจด้านตัวแทนนำเที่ยว ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อการให้บริการของตัวแทนนำเที่ยวในภาพรวมในระดับพอใจ และมีความพึงพอใจระดับพอใจในทุกประเด็นย่อยที่ประเมิน ได้แก่ การบริการ การติดต่อสื่อสาร/ภาษา ความคุ้มค่าเงิน และความซื่อสัตย์ &nbsp; &nbsp…','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["การบริการ","การสื่อสาร_ภาษา","ความคุ้มค่าเงิน","สำรวจความพึงพอใจ"]','["ZIP","CSV"]',2,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/56476f6e-f950-4b2e-ba20-b2043b45587c/resource/99e16bfe-93d0-472d-bbde-49a410dd4e93/download/item_88e3abfc-072a-4d77-98fd-5b782163180e-9h9kta.zip"},{"name":"ผลการสำรวจความพึงพอใจด้านตัวแทนนำเที่ยว ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย","format":"CSV","url":"http://www.mots.go.th/download/opendata/agency.csv"}]','Creative Commons Attributions','2021-10-31T05:51:47.318032','https://data.go.th/dataset/item_88e3abfc-072a-4d77-98fd-5b782163180e');
