INSERT OR REPLACE INTO datasets VALUES ('item_f628f08d-b45e-4f56-906d-ca52131c31ed','ข้อมูลการจดทะเบียนนิติบุคคล พ.ศ.2559','รายชื่อนิติบุคคลจดทะเบียนจัดตั้งใหม่ประจำเดือนเป็นข้อมูลจากการรับจดทะเบียนนิติบุคคลที่สำนักงานของกรมพัฒนาธุรกิจการค้าทั่วประเทศ&nbsp;ประกอบด้วยข้อมูลดังนี้ - เลขทะเบียน 13 หลัก - ชื่อนิติบุคคล - วันที่จดทะเบียน - ทุนจดทะเบียน - รายละเอียดวัตถุประสงค์ - ที่ตั้งสำนักงานใหญ่','กรมพัฒนาธุรกิจการค้า','["จดทะเบียน","จัดตั้งใหม่","นิติบุคคล"]','["CSV","XSL","PDF","ZIP"]',22,'[{"name":"ข้อมูลการจดทะเบียนนิติบุคคล-มกราคม-2559-CSV","format":"CSV","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/f5738d43-efe9-4939-922e-801b23c3e380/download/99_201601.csv"},{"name":"ข้อมูลการจดทะเบียนนิติบุคคล-มิถุนายน-2559-XLS","format":"XSL","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/5ab52565-2bbf-4aeb-b2ea-1e24cfb7c30f/download/99_201606.xls"},{"name":"Metadata-ข้อมูลการจดทะเบียนนิติบุคคล-มกราคม-2559","format":"PDF","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/da8e1dbb-2c83-4706-9480-0e393eda1a1e/download/0159_meta.pdf"},{"name":"ข้อมูลการจดทะเบียนนิติบุคคล-มิถุนายน-2559-CSV","format":"CSV","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/239aee7f-41a5-415a-bfe0-444fb898daba/download/99_201606.csv"},{"name":"ข้อมูลการจดทะเบียนนิติบุคคล-กุมภาพันธ์-2559-XLS","format":"XSL","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/98a3052f-bd50-4711-9143-f3f70afe1460/download/99_201602.xls"},{"name":"ข้อมูลการจดทะเบียนนิติบุคคล-พฤษภาคม-2559-XLS","format":"XSL","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/03e96434-4b04-433d-bd6c-64620021667e/download/99_201605.xls"},{"name":"Metadata-ข้อมูลการจดทะเบียนนิติบุคคล-กรกฎาคม-2559","format":"PDF","url":"https://data.go.th/dataset/2b691a7e-a2de-453f-bfe5-a98d2a691505/resource/5b534512-fe61-4dc5-b17a-e4665556bfd7/download/0759_meta.pdf"},{"name"