INSERT OR REPLACE INTO datasets VALUES ('item_1f9c8151-2a1b-4fb3-ad29-c66d5b5f3cb1','ข้อมูลทะเบียนกลุ่มเกษตรกรผู้เลี้ยงสัตว์','ข้อมูลกลุ่มเกษตรกรผู้เลี้ยงสัตว์ที่ขึ้นทะเบียนกับกองส่งเสริมและพัฒนาการปศุสัตว์ ตั้งแต่ปี 2554 ถึง ณ ปัจจุบัน เพื่อเป็นข้อมูลพื้นฐานในการกำหนดแนวทาง และมาตรการเพื่อการส่งเสริมและสนับสนุนการพัฒนาอาชีพการเลี้ยงสัตว์แก่เกษตรกรผู้เลี้ยงสัตว์รายย่อยสำหรับหน่วยงานที่เกี่ยวข้อง อีกทั้งยังเป็นการรับรองสถานภาพของกลุ่มเกษตรกรผู้เลี้ยงสัตว์ รองรับการสนับสนุนจากแหล่งทุนและหน่วยงานต่างๆ อาทิ กองทุนหมู่บ้าน อบต. เทศบาล และ อบจ. เป็นต้น และสร้างความมั่นใจแก่เกษตรกรผู้เลี้ยงสัตว์สำหรับความร่วมมือกับหน่วยงานของกรมปศุสัตว์ ในพัฒนาอาชีพการเลี้ยงสัตว์สู่เป้าหมายที่วางไว้','กรมปศุสัตว์','["จังหวัด","ชนิดปศุสัตว์","เลขทะเบียนกลุ่ม"]','["XSL","ZIP"]',2,'[{"name":"ข้อมูลทะเบียนกลุ่มเกษตรกรผู้เลี้ยงสัตว์","format":"XSL","url":"https://data.go.th/dataset/0b727106-edad-41ee-b4a7-4d74f155ca30/resource/6f5b092f-bc4e-450f-ae77-f1b762669887/download/2016-dld6.xls"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/0b727106-edad-41ee-b4a7-4d74f155ca30/resource/a2e35429-d2bb-4acc-821f-243dadac784a/download/item_1f9c8151-2a1b-4fb3-ad29-c66d5b5f3cb1-8nyxs1.zip"}]','Creative Commons Attributions','2021-10-31T05:50:45.837435','https://data.go.th/dataset/item_1f9c8151-2a1b-4fb3-ad29-c66d5b5f3cb1');
