INSERT OR REPLACE INTO datasets VALUES ('item_64bd04af-ec0a-4ac6-b895-ce7f0e49d4c9','ข้อมูลหน่วยงานบริการสุขภาพในกรุงเทพมหานคร','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["หน่วยงานบริการสุขภาพ"]','["CSV","XML","ZIP"]',3,'[{"name":"รหัสหน่วยงานบริการสุขภาพ_กรุงเทพ_CSV","format":"CSV","url":"https://data.go.th/dataset/11cd36b9-7c5f-4db8-b451-efc1a7aaada0/resource/3cd7edf4-aad7-42b8-8617-e99aed38f816/download/__csv.csv"},{"name":"รหัสหน่วยงานบริการสุขภาพ_กรุงเทพ_XML","format":"XML","url":"https://data.go.th/dataset/11cd36b9-7c5f-4db8-b451-efc1a7aaada0/resource/0b2f1325-875c-4941-b525-104bbb991a2c/download/__xml.xml"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/11cd36b9-7c5f-4db8-b451-efc1a7aaada0/resource/ba826f58-9ab9-4397-8c14-5689f852e212/download/item_64bd04af-ec0a-4ac6-b895-ce7f0e49d4c9-gun1ls.zip"}]','Creative Commons Attributions','2021-10-31T05:47:06.781235','https://data.go.th/dataset/item_64bd04af-ec0a-4ac6-b895-ce7f0e49d4c9');
