INSERT OR REPLACE INTO datasets VALUES ('item_2a1f6f83-4721-4f3d-894e-f886a6d6f157','ข้อมูลเกษตรกรผู้เลี้ยงโคนม','ข้อมูลเกษตรกรผู้เลี้ยงโคนม จัดทำขึ้นเพื่อรวบรวม และนำเสนอข้อมูลซึ่งมาจากการขึ้นทะเบียนฟาร์ม และ ทะเบียนโค ของระบบฐานข้อมูลโคนมของ สำนักเทคโนโลยีชีววภาพการผลิตปศุสัตว์ กรมปศุสัตว์ เพื่อเป็นข้อมูลพื้นฐานในการวางแผน ในการส่งเสริมการเลี้ยงโคนมในประเทศไทย','กรมปศุสัตว์','["กรมปศุสัตว์"]','["CSV","ZIP"]',2,'[{"name":"ข้อมูลเกษตรกรผู้เลี้ยงโคนม","format":"CSV","url":"https://data.go.th/dataset/46a23ff5-d111-4c71-82f5-b1dd3de0b380/resource/b76b8019-189a-42aa-b552-cf29751fb76a/download/2016-dld4.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/46a23ff5-d111-4c71-82f5-b1dd3de0b380/resource/2b58c49f-ddb0-497a-9113-869422afa532/download/item_2a1f6f83-4721-4f3d-894e-f886a6d6f157-4c85lf.zip"}]','Creative Commons Attributions','2021-10-31T05:46:45.025459','https://data.go.th/dataset/item_2a1f6f83-4721-4f3d-894e-f886a6d6f157');
INSERT OR REPLACE INTO datasets VALUES ('fit_d123','ฐานะการคลังตามระบบ สศค. หรือ GFS (Statement of Government Operations)','เป็นการแสดงผลการดําเนินงานของภาครัฐบาลตามระบบสถิติเพื่อการศึกษาและวิเคราะห์นโยบายการครัง(ระบบ สศค.) หรือ Government Finance Statistics(GFS) มาตรฐานปีค.ศ. 2001 ประกอบด้วยรายได้ รายจ่าย การเปลี่ยนแปลงในการถือครองสินทรัพย์และหนี้สิน หน่วย : ล้านบาท','สำนักงานเศรษฐกิจการเกษตร','["รายจ่ายภาครัฐ"]','["ZIP","CSV","PDF"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/adab6daa-dbdf-4dfc-9cbc-ef38dfde69c4/resource/d361f6e6-980a-4bc8-93ea-a7ea3a239cb2/download/fit_d123-q9l1ma.zip"},{"name":"ฐานะการคลังตามระบบ สศค. หรือ GFS (Statement of Government Operations)","format":"CSV","url":"https://data.go.th/dataset/adab6daa-dbdf-4dfc-9cbc-ef38dfde69c4/resource/c6e04fd6-099a-4700-bdbf-bdbd24bd2de8/download/d123_st1_2018.csv"},{"name":"คำอธิบาย FIT_D123","format":"PDF","url":""}]','Creative Commons Attributions','2021-10-31T05:46:44.286474','https://data.go.th/dataset/fit_d123');
INSERT OR REPLACE INTO datasets VALUES ('fit_d106_month','ฐานะการคลังตามระบบกระแสเงินสดของรัฐบาล','ฐานะการคลังตามระบบกระแสเงินสดเป็นการแสดงฐานะการคลังของรัฐบาลเพื่อ ใช้ในการติดตามฐานะเงินสดของรัฐบาลที่มีการรับและจ่ายเงินจริงผ่านบัญชีเงินคงคลัง รวมทั้งใช้ในการบริหารเงินสด และการกู้ยืมเงินเพื่ออชดเชยการขาดดุลของรัฐบาล โดยมี องค์ประกอบของฐานะ หน่วย: ล้านบาท','สำนักงานเศรษฐกิจการเกษตร','["รายจ่่ายภาครัฐ"]','["ZIP","CSV"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/a62e97ab-4017-463f-9043-792666229ae3/resource/4e8d1b02-104b-451f-af75-f2c23047a80c/download/fit_d106_month-zymd0r.zip"},{"name":"ฐานะการคลังตามระบบกระแสเงินสดของรัฐบาล รายเดีอน","format":"CSV","url":"https://data.go.th/dataset/a62e97ab-4017-463f-9043-792666229ae3/resource/924601dc-b0dd-44c2-af28-e85ef1f18703/download/fit_d106-month.csv"},{"name":"ฐานะการคลังตามระบบกระแสเงินสดของรัฐบาล รายปี","format":"CSV","url":"https://data.go.th/dataset/a62e97ab-4017-463f-9043-792666229ae3/resource/2b2409bc-3895-460c-904b-2821e4f45f31/download/fit_d106-year.csv"}]','Creative Commons Attributions','2021-10-31T05:46:43.789208','https://data.go.th/dataset/fit_d106_month');
INSERT OR REPLACE INTO datasets VALUES ('expense-fit_d125','ค่าใช้จ่าย (Expense)','รายจ่าย (Expenditure) หมายถึง จํานวนเงินทั้งหมดที่รัฐบาลจ่ายออกไปเพื่อ การใช้จ่ายทางเศรษฐกิจ','สำนักงานเศรษฐกิจการเกษตร','["รายจ่่ายภาครัฐ","เศรษฐกิจ"]','["ZIP","CSV","PDF"]',4,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/ad801d01-76d6-44ce-8066-90599b825b26/resource/f8339dfb-9b66-446a-a112-34089962abf6/download/expense-fit_d125-qw6cnx.zip"},{"name":"ค่าใช้จ่าย(Expense)","format":"CSV","url":"https://data.go.th/dataset/ad801d01-76d6-44ce-8066-90599b825b26/resource/262188a9-3301-46c1-9600-15d1fddb086d/download/d125_t2_2018.csv"},{"name":"การจัดทําคําอธิบายข้อมูล FIT_D125","format":null,"url":""},{"name":"การจัดทําคําอธิบายข้อมูล FIT_D125","format":"PDF","url":"https://data.go.th/dataset/ad801d01-76d6-44ce-8066-90599b825b26/resource/72282920-9618-42df-aea0-c1ab59a67516/download/cnt0007217-1.pdf"}]','Creative Commons Attributions','2021-10-31T05:46:40.460474','https://data.go.th/dataset/expense-fit_d125');
INSERT OR REPLACE INTO datasets VALUES ('fit_d104-2532-2563','ตาราง-Fit_D104-โครงสร้างงบประมาณปี-2532-2563','ปรับปรุงครั้งสุดท้ายวันที่ : วันที่ 30 กันยายน 2561 หมายเหตุ : 1. ปีงบประมาณ พ.ศ. 2540 เป็นตัวเลขที่ปรับลดจาก พ.ร.บ.ที่ประกาศใช้จำนวน 984,000 ล้านบาท 2. ปีงบประมาณ พ.ศ. 2541 เป็นตัวเลขที่ปรับลดและปรับเพิ่มจาก พ.ร.บ.ที่ประกาศใช้จำนวน 923,000 ล้านบาท 3. ปีงบประมาณ พ.ศ. 2547 เป็นตัวเลขที่ปรับเพิ่มจาก พ.ร.บ.ที่ประกาศใช้จำนวน 1,028,000 ล้านบาท 4. ปีงบประมาณ พ.ศ. 2552 เป็นปีแรกที่มีการตั้งงบประมาณรายจ่ายเพื่อชดใช้เงินคงคลังจำนวน 27,540.2 ซึ่งในที่นี้จะรวมอยู่ในรายจ่ายประจำ 5. ปีงบประมาณ พ.ศ. 2559 พรบ. งบประมาณรายจ่ายเพิ่มเติมประจำปีงบประมาณ พ.ศ. 2559 จำนวน 56,000 ล้านบาท มีผลบังคับใช้แล้วตั้งแต่วัน…','สำนักงานเศรษฐกิจการเกษตร','["งบประมาณ","รายจ่่ายภาครัฐ"]','["ZIP","CSV","PDF"]',4,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/7b27ff07-9a24-47cd-ac70-f5677c71eaac/resource/e2205332-b148-43f0-88fd-13dcb12d20f6/download/fit_d104-2532-2563-lirh40.zip"},{"name":"โครงสร้างงบประมาณปี-2532-2563","format":null,"url":""},{"name":"โครงสร้างงบประมาณปี-2532-2563","format":"CSV","url":"https://data.go.th/dataset/7b27ff07-9a24-47cd-ac70-f5677c71eaac/resource/c29209ef-ab60-4987-b5e6-af3d67c286f6/download/book1.csv"},{"name":"คําอธิบายข้อมูล","format":"PDF","url":"https://data.go.th/dataset/7b27ff07-9a24-47cd-ac70-f5677c71eaac/resource/d5931012-1883-4c56-a0f4-2b5db61d7b10/download/cnt0006844-1.pdf"}]','Creative Commons Attributions','2021-10-31T05:46:40.027062','https://data.go.th/dataset/fit_d104-2532-2563');
