INSERT OR REPLACE INTO datasets VALUES ('item_003e28b9-42a3-4aef-98a6-b68f51206e8b','งานวิจัยมูลค่าทางเศรษฐศาสตร์จากการพัฒนาการท่องเที่ยว “รัฐขาดทุนหรือกำไร เมื่อจำเป็นต้องพัฒนาการท่องเที่ยวให้เกิดความอยู่ดีมีสุขแก่ประชาชน','การประเมินระดับความอยู่ดีมีสุขของประชาชนในพื้นที่พิเศษ และ ผลการวิเคราะห์ประเมินมูลค่าทางเศรษฐศาสตร์ (Economics value) จากการพัฒนาการท่องเที่ยวอย่างยั่งยืนของ อพท. ผลสำเร็จจากการพัฒนาการท่องเที่ยวด้านสังคมและสิ่งแวดล้อมที่สามารถวัดออกมาเป็นตัวเลขได้ว่ามีมูลค่าเท่าใดเมื่อเทียบเป็นตัวเงิน และประเด็นคุ้มค่ากับเงินงบประมาณที่ได้รับการจัดสรรหรือไม่ &nbsp;','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF","ZIP"]',2,'[{"name":"งานวิจัยมูลค่าทางเศรษฐศาสตร์จากการพัฒนาการท่องเที่ยว “รัฐขาดทุนหรือกำไร เมื่อจำเป็นต้องพัฒนาการท่อง…","format":"PDF","url":"https://data.go.th/dataset/2bb96123-9bc4-4557-bfb6-67ce7685999d/resource/65738a58-12af-4c05-88f7-a87a409d66a8/download/dasta-forum2016.pdf"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/2bb96123-9bc4-4557-bfb6-67ce7685999d/resource/0466917c-9a70-4e37-bfc7-f92234b52698/download/item_003e28b9-42a3-4aef-98a6-b68f51206e8b-waa6al.zip"}]','Creative Commons Attributions','2021-10-31T05:46:27.617838','https://data.go.th/dataset/item_003e28b9-42a3-4aef-98a6-b68f51206e8b');
INSERT OR REPLACE INTO datasets VALUES ('item_d51220c3-d3d9-4451-b286-eb405d65e4e2','แผ่นพับโครงการรถไฟฟ้าสายสีเขียว ช่วงหมอชิต-สะพานใหม่-คูคต','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทยได้รับมอบหมายให้ดำเนินการโครงการรถไฟฟ้าสายสีเขียว ช่วงหมอชิต-สะพานใหม่-คูคต โครงการมีระยะทางประมาณ 19 กิโลเมตร ลักษณะเป็นโครงสร้างทางวิ่งยกระดับตลอดเส้นทาง มีสถานียกระดับจำนวน 16 สถานี แนวเส้นทางเริ่มต้น ต่อเนื่องจากแนวเส้นทางของโครงการระบบขนส่งมวลชนกรุงเทพมหานคร (BTS) ที่สถานีหมอชิต ข้ามทางยกระดับดอนเมืองโทลล์เวย์บริเวณห้าแยก ลาดพร้าว ผ่านแยกรัชโยธิน แยกมหาวิทยาลัยเกษตรศาสตร์ ไปจนถึงบริเวณแยกหลักสี่และเบี่ยงออกด้านขวาเลียบไปตามขอบอุโมงค์ลอดแยกหลักสี่ และเบี่ยงเข้าสู่เกาะกลางดังเดิม ไปจนถึงบริเวณสะพานใหม่หน้าตลาดยิ่งเจริญ โดยเมื่อถึงประมาณกิโลเมตรที่ 25 ของถนน…','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["หมอชิตสะพานใหม่คูคต"]','["PDF"]',1,'[{"name":"Greenline-North","format":"PDF","url":"https://data.go.th/dataset/03fc41fc-73e1-4223-8546-342174527c7b/resource/b760c697-04ef-49b9-ab65-83a2bda673c4/download/greenline-north.pdf"}]','Creative Commons Attributions','2021-10-31T05:46:27.190103','https://data.go.th/dataset/item_d51220c3-d3d9-4451-b286-eb405d65e4e2');
