INSERT OR REPLACE INTO datasets VALUES ('item_6dcf4094-bb6b-4d6a-937f-b7d4f0ecd3bf','ข้อมูลหน่วยงานบริการสุขภาพจังหวัดอ่างทอง','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["dataset","หน่วยงานบริการสุขภาพ"]','["ZIP","CSV","XML"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/53f1241a-a1fe-412c-9e53-ccae6c40397d/resource/92b2d1b2-0a8f-4316-a14a-44aab76f026d/download/item_6dcf4094-bb6b-4d6a-937f-b7d4f0ecd3bf-tkivam.zip"},{"name":"รหัสหน่วยงานบริการสุขภาพ_อ่างทอง_CSV","format":"CSV","url":"https://data.go.th/dataset/53f1241a-a1fe-412c-9e53-ccae6c40397d/resource/dc354bcf-63db-4319-a493-4afc9b156371/download/__csv.csv"},{"name":"รหัสหน่วยงานบริการสุขภาพ_อ่างทอง_XML","format":"XML","url":"https://data.go.th/dataset/53f1241a-a1fe-412c-9e53-ccae6c40397d/resource/f3e1b755-5df3-4834-80df-276535c30e62/download/__xml.xml"}]','Creative Commons Attributions','2021-10-31T05:46:24.476370','https://data.go.th/dataset/item_6dcf4094-bb6b-4d6a-937f-b7d4f0ecd3bf');
INSERT OR REPLACE INTO datasets VALUES ('item_76cb87a7-7486-470a-8754-4696527f5a2c','ข้อมูลหน่วยงานบริการสุขภาพจังหวัดสิงห์บุรี','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["dataset","หน่วยงานบริการสุขภาพ"]','["ZIP","XML","CSV"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/74b78abc-9d2c-4328-84b1-635cabda1c69/resource/5b46359f-ea25-4b62-b2ea-99dc6410a92f/download/item_76cb87a7-7486-470a-8754-4696527f5a2c-3xnzbl.zip"},{"name":"รหัสหน่วยงานบริการสุขภาพ_สิงห์บุรี_XML","format":"XML","url":"https://data.go.th/dataset/74b78abc-9d2c-4328-84b1-635cabda1c69/resource/f443ecfb-3bde-4342-8e8d-2745ab6922ca/download/__xml.xml"},{"name":"รหัสหน่วยงานบริการสุขภาพ_สิงห์บุรี_CSV","format":"CSV","url":"https://data.go.th/dataset/74b78abc-9d2c-4328-84b1-635cabda1c69/resource/1bf102fd-ec40-48eb-842b-09662e7395c2/download/__csv.csv"}]','Creative Commons Attributions','2021-10-31T05:46:24.048584','https://data.go.th/dataset/item_76cb87a7-7486-470a-8754-4696527f5a2c');
INSERT OR REPLACE INTO datasets VALUES ('item_6a0bfd33-891a-471a-84de-9c03593b7b4e','ข้อมูลหน่วยงานบริการสุขภาพจังหวัดสมุทรสาคร','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["dataset","หน่วยงานบริการสุขภาพ"]','["ZIP","CSV","XML"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/8c49d070-5a89-4e2b-8894-81bfe492ab21/resource/2b84c90c-c407-4b24-89ee-e69eb78881a4/download/item_6a0bfd33-891a-471a-84de-9c03593b7b4e-vqhdix.zip"},{"name":"รหัสหน่วยงานบริการสุขภาพ_สมุทรสาคร_CSV","format":"CSV","url":"https://data.go.th/dataset/8c49d070-5a89-4e2b-8894-81bfe492ab21/resource/f7e752ed-0e70-4eaf-ab75-7885b1a56990/download/__csv.csv"},{"name":"รหัสหน่วยงานบริการสุขภาพ_สมุทรสาคร_XML","format":"XML","url":"https://data.go.th/dataset/8c49d070-5a89-4e2b-8894-81bfe492ab21/resource/0b32b6a7-0693-4b56-8111-2dc56a315a0c/download/__xml.xml"}]','Creative Commons Attributions','2021-10-31T05:46:23.577558','https://data.go.th/dataset/item_6a0bfd33-891a-471a-84de-9c03593b7b4e');
INSERT OR REPLACE INTO datasets VALUES ('item_78d7f38f-867e-4632-a1dc-dfec8f586a1e','ข้อมูลหน่วยงานบริการสุขภาพจังหวัดพิษณุโลก','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["dataset","หน่วยงานบริการสุขภาพ"]','["ZIP","XML","CSV"]',3,'[{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/89d9e7c5-5b34-4295-8b27-0da670f89b58/resource/ee2f1cff-451f-4594-9bf8-ac2759150935/download/item_78d7f38f-867e-4632-a1dc-dfec8f586a1e-1bsko0.zip"},{"name":"รหัสหน่วยงานบริการสุขภาพ_พิษณุโลก_XML","format":"XML","url":"https://data.go.th/dataset/89d9e7c5-5b34-4295-8b27-0da670f89b58/resource/9772a846-ebd6-4e35-ae60-d2baac4d73fc/download/__xml.xml"},{"name":"รหัสหน่วยงานบริการสุขภาพ_พิษณุโลก_CSV","format":"CSV","url":"https://data.go.th/dataset/89d9e7c5-5b34-4295-8b27-0da670f89b58/resource/ef04eef9-c3a6-44f2-913f-57fcd9848b1c/download/__csv.csv"}]','Creative Commons Attributions','2021-10-31T05:46:23.027059','https://data.go.th/dataset/item_78d7f38f-867e-4632-a1dc-dfec8f586a1e');
