INSERT OR REPLACE INTO datasets VALUES ('item_7b67ea61-f9b1-4157-a867-a38626af815c','สถิติผลการดำเนินงานด้านการตรวจสอบทรัพย์สินและหนี้สิน (ตั้งแต่ปีงบประมาณ พ.ศ. 2550 - 2556)','สถิติการดำเนินงานด้านการตรวจสอบทรัพย์สินและหนี้สิน &nbsp; &nbsp; &nbsp; &nbsp;การยื่นบัญชีแสดงรายการทรัพย์สินและหนี้สินถือว่าเป็นหน้าที่เฉพาะตัวของผู้มีหน้าที่ยื่นบัญชีแสดงรายการทรัพย์สินและหนี้สิน หากจงใจไม่ยื่นบัญชีแสดงรายการทรัพย์สินและหนี้สินและเอกสารประกอบภายในเวลาที่กฎหมายกำหนด หรือจงใจยื่นบัญชีแสดงรายการทรัพย์สินและหนี้สินและเอกสารประกอบด้วยข้อความอันเป็นเท็จหรือปกปิดข้อเท็จจริงที่ควรแจ้งให้ทราบ อาจต้องพ้นจากตำแหน่งและห้ามดำรงตำแหน่งเป็นเวลา ๕ ปี และได้รับโทษทางอาญาอีกด้วย (จำคุกไม่เกิน ๖ เดือน หรือปรับไม่เกิน ๑๐,๐๐๐ บาท หรือทั้งจำทั้งปรับ) &nbsp;','สำนักงานคณะกรรมการป้องกันและปราบปรามการทุจริตแห่งชาติ','["ตรวจสอบ","ทรัพย์สิน","ป.ป.ช.","ยื่นบัญชี","สถิติ","หนี้สิน"]','["CSV","XLSX","ZIP"]',3,'[{"name":"สถิติผลการดำเนินงานด้านการตรวจสอบทรัพย์สินและหนี้สิน (ตั้งแต่ปีงบประมาณ พ.ศ. 2550 - 2556) (csv)","format":"CSV","url":"https://data.go.th/dataset/d21a9e28-ecfc-40ef-a93d-a68c87e128d3/resource/a4f58084-aebb-4369-af2a-bf541ce664f0/download/naccasset_2550_2556.csv"},{"name":"สถิติผลการดำเนินงานด้านการตรวจสอบทรัพย์สินและหนี้สิน (ตั้งแต่ปีงบประมาณ พ.ศ. 2550 - 2556) (xlsx)","format":"XLSX","url":"https://data.go.th/dataset/d21a9e28-ecfc-40ef-a93d-a68c87e128d3/resource/28b1d073-650b-4b49-89b3-1412a6ee6ddd/download/naccasset_xls_2550_2556.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/d21a9e28-ecfc-40ef-a93d-a68c87e128d3/resource/bcf9e477-50f4-4c65-9223-d06f5e5f8b23/download/item_7b67ea61-f9b1-4157-a867-a38626af815c-0um8co.zip"}]','Creative Commons Attributions','2021-10-31T05:46:14.240247','https://data.go.th/dataset/item_7b67ea61-f9b1-4157-a867-a38626af815c');
