INSERT OR REPLACE INTO datasets VALUES ('item_6892514e-27db-4728-9cca-906fc931f236','ทะเบียนผู้ได้รับใบอนุญาตตรวจสอบและรับรองการจัดการพลังงาน สำหรับผู้ตรวจสอบพลังงาน','ข้อมูลใบอนุญาต และ รายละเอียดของใบอนุญาตประกอบด้วย ข้อมูลผู้ชำนาญการและผู้ช่วยผู้ชำนาญการ ที่ผ่านการอบรมจาก พพ.และได้รับการขึ้นทะเบียนเป็นผู้ตรวจสอบและรับรองรายงานการจัดการพลังงาน','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ข้อมูลใบอนุญาต"]','["XLSX","ZIP"]',3,'[{"name":"ทะเบียนผู้ได้รับใบอนุญาตตรวจสอบและรับรองการจัดการพลังงาน สำหรับผู้ตรวจสอบพลังงาน","format":"XLSX","url":"https://data.go.th/dataset/f37477eb-369b-4649-bd52-9e4db898980e/resource/6049768c-c6f6-4c38-b98d-64a5bcd9052e/download/3_.xlsx"},{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(ทะเบียนผู้ได้รับใบอนุญาตตรวจสอบและรับรอง)","format":"XLSX","url":"https://data.go.th/dataset/f37477eb-369b-4649-bd52-9e4db898980e/resource/9c3e6542-f577-44f4-b5aa-82a88972ef70/download/metadata_.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/f37477eb-369b-4649-bd52-9e4db898980e/resource/735b8c1a-ea07-4c81-800c-02272074d7fe/download/item_6892514e-27db-4728-9cca-906fc931f236-wrmkub.zip"}]','Creative Commons Attributions','2021-10-31T05:46:01.392993','https://data.go.th/dataset/item_6892514e-27db-4728-9cca-906fc931f236');
