INSERT OR REPLACE INTO datasets VALUES ('item_731e0ad9-cdf1-4e3a-a0e1-820c6f812262','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2551','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2551","format":"XLSX","url":"https://data.go.th/dataset/c1967cfb-cb8e-4769-b7cc-e32c0cc07f24/resource/3f60aca2-5e31-467c-be16-4367ab194e64/download/-2551.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/c1967cfb-cb8e-4769-b7cc-e32c0cc07f24/resource/8d860d3a-7a0f-41b6-ab5b-dbed05b3d9c5/download/item_731e0ad9-cdf1-4e3a-a0e1-820c6f812262-yxprif.zip"}]','Creative Commons Attributions','2021-10-31T05:45:59.815129','https://data.go.th/dataset/item_731e0ad9-cdf1-4e3a-a0e1-820c6f812262');
INSERT OR REPLACE INTO datasets VALUES ('item_78ce72dc-24e0-4ded-bcb7-0fc0d6890b3d','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2550','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2550","format":"XLSX","url":"https://data.go.th/dataset/4301800f-04fb-42cb-a6a6-62867c61a999/resource/f37b2b22-6363-4e66-b5f5-90c123f2bda6/download/-2550.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/4301800f-04fb-42cb-a6a6-62867c61a999/resource/d9515f82-9d34-44d7-8bef-0c2c4ba41c5f/download/item_78ce72dc-24e0-4ded-bcb7-0fc0d6890b3d-famqa8.zip"}]','Creative Commons Attributions','2021-10-31T05:45:59.390444','https://data.go.th/dataset/item_78ce72dc-24e0-4ded-bcb7-0fc0d6890b3d');
