INSERT OR REPLACE INTO datasets VALUES ('item_69eecdef-edc8-4854-b5dd-b1a58e31e2a5','ตำแหน่งงานว่าง จำแนกตามอุตสาหกรรม และอายุ ทั่วราชอาณาจักร ปี 2558','ข้อมูลตำแหน่งงานว่าง &nbsp;จำแนกตามอุตสาหกรรม และอายุ &nbsp;ทั่วราชอาณาจักร &nbsp;ปี 2558&nbsp;เป็นข้อมูลจากการให้บริการจัดหางานในประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ ประกอบด้วยข้อมูลดังนี้ - ตำแหน่งงานว่าง - ประเภทอุตสาหกรรม - อายุ','กรมการจัดหางาน','["ตำแหน่งงานว่าง","ประเภทอุตสาหกรรม","อายุ"]','["XLSX"]',1,'[{"name":"ตำแหน่งอุตสาหกรรมอายุ","format":"XLSX","url":"https://data.go.th/dataset/cd3dd4f2-b15c-42da-bf6a-ce184e85066e/resource/7eefaea3-5986-4bb5-9ae7-972cc6fbcfd3/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:45:51.462361','https://data.go.th/dataset/item_69eecdef-edc8-4854-b5dd-b1a58e31e2a5');
INSERT OR REPLACE INTO datasets VALUES ('item_68ac8184-8011-4df9-8c23-a3ac921b43db','เกณฑ์การท่องเที่ยวอย่างยั่งยืนโลก','เกณฑ์การท่องเที่ยวอย่างยั่งยืนโลก','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["ท่องเที่ยว","อย่างยั่งยืน","โลก"]','["PDF","XLSX","ZIP"]',3,'[{"name":"เกณฑ์การท่องเที่ยวอย่างยั่งยืนโลก","format":"PDF","url":"https://data.go.th/dataset/a7c423a6-4b1f-43c8-a5ff-b977392d26da/resource/aa53b1e9-d02a-4be9-957f-1c27d38e85fa/download/gstc-criteria_1.pdf"},{"name":"metadata_องค์การบริหาร(เกณฑ์การท่องเที่ยวอย่างยั่งยืนโลก)","format":"XLSX","url":"https://data.go.th/dataset/a7c423a6-4b1f-43c8-a5ff-b977392d26da/resource/92c9e546-b3fa-4e48-9e09-ed984d4b501a/download/metadata_.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/a7c423a6-4b1f-43c8-a5ff-b977392d26da/resource/246baae1-11bb-4aee-aba5-5df54abad13b/download/item_68ac8184-8011-4df9-8c23-a3ac921b43db-78mbo9.zip"}]','Creative Commons Attributions','2021-10-31T05:45:50.381714','https://data.go.th/dataset/item_68ac8184-8011-4df9-8c23-a3ac921b43db');
INSERT OR REPLACE INTO datasets VALUES ('item_69edc096-1d09-4e64-afc8-ec4bf90c4abc','การบรรจุงาน จำแนกตามอุตสาหกรรม และอายุ ทั่วราชอาณาจักร ปี 2558','ข้อมูลการบรรจุงาน &nbsp;จำแนกตามอุตสาหกรรม &nbsp;และอายุ &nbsp; ทั่วราชอาณาจักร &nbsp;ปี 2558&nbsp;เป็นข้อมูลจากการให้บริการจัดหางานในประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ ประกอบด้วยข้อมูลดังนี้ - การบรรจุงาน - ประเภทอุตสาหกรรม - อายุ','กรมการจัดหางาน','["การบรรจุงาน","ประเภทอุตสาหกรรม","อายุ"]','["XLSX"]',1,'[{"name":"บรรจุงานอุตสาหกรรมอายุ","format":"XLSX","url":"https://data.go.th/dataset/04083ee4-87d5-4157-a046-f8c69baa9aa9/resource/4fe51dbf-d730-437c-8b2a-b30860c52b85/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:45:49.549692','https://data.go.th/dataset/item_69edc096-1d09-4e64-afc8-ec4bf90c4abc');
INSERT OR REPLACE INTO datasets VALUES ('item_5e8dc92e-9a3a-46a4-8fc1-3941a66920d1','ข้อมูลหน่วยงานบริการสุขภาพจังหวัดนครราชสีมา','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["หน่วยงานบริการสุขภาพ"]','["CSV","XML","ZIP"]',3,'[{"name":"รหัสหน่วยงานบริการสุขภาพ_นครศรีธรรมราช_CSV","format":"CSV","url":"https://data.go.th/dataset/d5275758-bf90-4c65-b43e-86169affa195/resource/ac3a5422-f8b9-4c94-9e4d-affd6494b1c3/download/__csv.csv"},{"name":"รหัสหน่วยงานบริการสุขภาพ_นครศรีธรรมราช_XML","format":"XML","url":"https://data.go.th/dataset/d5275758-bf90-4c65-b43e-86169affa195/resource/44614883-4b69-4468-b739-a8c2cf1bd90e/download/__xml.xml"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/d5275758-bf90-4c65-b43e-86169affa195/resource/1ead2a8f-e8f3-4296-9667-66184917041a/download/item_5e8dc92e-9a3a-46a4-8fc1-3941a66920d1-mxbbg6.zip"}]','Creative Commons Attributions','2021-10-31T05:45:48.646350','https://data.go.th/dataset/item_5e8dc92e-9a3a-46a4-8fc1-3941a66920d1');
