INSERT OR REPLACE INTO datasets VALUES ('item_eefc5c2d-c0ce-4fc3-8740-0eeb2b06a519','สรุปผลการจัดซื้อจัดจ้างตามแบบ สขร.1 (เดือน มิถุนายน)','สรุปผลการซื้อจัดจ้างตามแบบ สขร.1 ประกอบด้วยข้อมูล ประเภทงาน ชื่อโครงการ วงเงินที่จะซื้อ/จ้าง ราคากลาง วิธีการจัดซื้อจัดจ้าง จำนวนผู้ซื้อแบบ จำนวนผู้ที่มีสิทธิ์เสนอราคา เลขทะเบียน ชื่อผู้รับจ้าง ราคาที่ตกลงซื้อ/จ้าง เลขที่สัญญาหรือข้อตกลงในการซื้อ/จ้าง วันที่สัญญาหรือข้อตกลงในการซื้อ/จ้าง สถานะ','กรมทางหลวงชนบท','["สขร.1"]','["PDF","XLSX","CSV","ZIP"]',4,'[{"name":"สรุปผลการจัดซื้อจัดจ้างตามแบบ สขร.1 (pdf)","format":"PDF","url":"https://data.go.th/dataset/f37ef597-cc7a-42ca-8354-cbf93d9800f0/resource/9dd293e5-d4ac-4bb9-b1f3-c4559b145a28/download/-.1.pdf"},{"name":"สรุปผลการจัดซื้อจัดจ้างตามแบบ สขร.1 (xlsx)","format":"XLSX","url":"https://data.go.th/dataset/f37ef597-cc7a-42ca-8354-cbf93d9800f0/resource/df99d3bc-86a8-47d8-9751-ce86c7e10aaa/download/-.1.xlsx"},{"name":"สรุปผลการจัดซื้อจัดจ้างตามแบบ สขร.1 (csv)","format":"CSV","url":"https://data.go.th/dataset/f37ef597-cc7a-42ca-8354-cbf93d9800f0/resource/8dd59074-1a8f-4eb1-8b1b-8bafb2bea8ce/download/-.1.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/f37ef597-cc7a-42ca-8354-cbf93d9800f0/resource/7d7cad8c-41aa-49c7-bee6-132fd96337ce/download/item_eefc5c2d-c0ce-4fc3-8740-0eeb2b06a519-1og6nh.zip"}]','Creative Commons Attributions','2021-10-31T05:45:04.503181','https://data.go.th/dataset/item_eefc5c2d-c0ce-4fc3-8740-0eeb2b06a519');
