set/item_cff8e5ad-0827-4a43-9501-e3690feea153');
INSERT OR REPLACE INTO datasets VALUES ('item_d08c4a4f-76ee-45cc-ae2e-8cd30a79efe7','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2558','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2558","format":"XLSX","url":"https://data.go.th/dataset/2affd7db-848c-49f4-aea9-dfd58d7bf8ea/resource/beccba4d-1500-47ce-aec5-bbdd198ddfb4/download/-2558.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/2affd7db-848c-49f4-aea9-dfd58d7bf8ea/resource/1704fc58-3c93-4af5-a5a1-d6b596d9aac5/download/item_d08c4a4f-76ee-45cc-ae2e-8cd30a79efe7-frnzhf.zip"}]','Creative Commons Attributions','2021-10-31T05:44:38.169054','https://data.go.th/dataset/item_d08c4a4f-76ee-45cc-ae2e-8cd30a79efe7');
