INSERT OR REPLACE INTO datasets VALUES ('item_c6292098-716e-4acb-8a40-a3bf488d046d','ข้อมูลทะเบียนผู้รับผิดชอบด้านพลังงานประจำอาคาร/โรงงานควบคุม','รายชื่อบุคคลที่ได้รับการขึ้นทะเบียนจาก พพ.ให้เป็นผู้รับผิดชอบประจำอาคาร/โรงงานควบคุม มีสถานะการขอขึ้นทะเบียน สถานะคงอยู่ และลาออก เปลี่ยนแปลง','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ขึ้นทะเบียน"]','["XLSX","ZIP"]',3,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(ข้อมูลทะเบียนผู้รับผิดชอบด้านพลังงาน)","format":"XLSX","url":"https://data.go.th/dataset/b73b683f-66bf-41f9-b591-e8fd237f5d48/resource/526d8520-2339-4ec1-bcd7-e1010ef8ac51/download/metadata_.xlsx"},{"name":"ข้อมูลทะเบียนผู้รับผิดชอบด้านพลังงานประจำอาคาร/โรงงานควบคุม","format":"XLSX","url":"https://data.go.th/dataset/b73b683f-66bf-41f9-b591-e8fd237f5d48/resource/ca29d368-4711-4645-98b0-bdbe374e501c/download/2_.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/b73b683f-66bf-41f9-b591-e8fd237f5d48/resource/f3750ed1-4701-4689-853f-115b64572358/download/item_c6292098-716e-4acb-8a40-a3bf488d046d-0cwpr5.zip"}]','Creative Commons Attributions','2021-10-31T05:44:33.062988','https://data.go.th/dataset/item_c6292098-716e-4acb-8a40-a3bf488d046d');
INSERT OR REPLACE INTO datasets VALUES ('item_c795cfeb-bea7-4988-b73b-62c76b4aa39c','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2555','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2555","format":"XLSX","url":"https://data.go.th/dataset/fd114cce-c852-4a53-857c-c43f60d5516a/resource/055eed0d-c6fa-4e18-8b24-6f0719527442/download/-2555.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/fd114cce-c852-4a53-857c-c43f60d5516a/resource/7253ebed-7e2d-4956-bce5-8573440d762b/download/item_c795cfeb-bea7-4988-b73b-62c76b4aa39c-nkpno9.zip"}]','Creative Commons Attributions','2021-10-31T05:44:32.033238','https://data.go.th/dataset/item_c795cfeb-bea7-4988-b73b-62c76b4aa39c');
