INSERT OR REPLACE INTO datasets VALUES ('item_3c649412-91ac-40d7-b654-b6db1a76e611','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2540','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิ�"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2540","format":"XLSX","url":"https://data.go.th/dataset/c7d39c47-cd41-4f5c-b41b-48382a8bb1fb/resource/7415d96f-3a04-4d31-bf99-915069873868/download/-2540.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/c7d39c47-cd41-4f5c-b41b-48382a8bb1fb/resource/ca7de87e-a196-4e54-9c13-51c7206f7e57/download/item_3c649412-91ac-40d7-b654-b6db1a76e611-_87di3.zip"}]','Creative Commons Attributions','2021-10-31T05:44:07.671041','https://data.go.th/dataset/item_3c649412-91ac-40d7-b654-b6db1a76e611');
