INSERT OR REPLACE INTO datasets VALUES ('item_3704580f-4f51-469b-9ab1-8d0bcafe2355','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนมิถุนายน 2559','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง&nbsp;1111 โดยจำแนกตามประเภทเรื่องร้องทุกข์','สำนักงานปลัดสำนักนายกรัฐมนตรี','["ร้องทุกข์","ร้องเรียน"]','["CSV","ZIP"]',2,'[{"name":"จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนมิถุนายน 2559","format":"CSV","url":"https://data.go.th/dataset/c088f762-876d-4a1a-8d70-9150d4f38311/resource/4c1461da-7503-49c2-af95-f1e6e1cee8c5/download/opendata-06-2559.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/c088f762-876d-4a1a-8d70-9150d4f38311/resource/a2a86780-c4c3-488f-88a5-a3c656736abd/download/item_3704580f-4f51-469b-9ab1-8d0bcafe2355-eb9m3j.zip"}]','Creative Commons Attributions','2021-10-31T05:44:04.118864','https://data.go.th/dataset/item_3704580f-4f51-469b-9ab1-8d0bcafe2355');
INSERT OR REPLACE INTO datasets VALUES ('item_3579c955-e816-4fb3-97af-cb052fe89c29','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2544','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2544","format":"XLSX","url":"https://data.go.th/dataset/6a208270-ef15-46f3-a062-24fc2401cc94/resource/a9c55248-c894-4b8b-99c0-01f92f51460a/download/-2544.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/6a208270-ef15-46f3-a062-24fc2401cc94/resource/995c76c5-4a8a-45d2-aff3-f2993115be15/download/item_3579c955-e816-4fb3-97af-cb052fe89c29-fb3ieg.zip"}]','Creative Commons Attributions','2021-10-31T05:44:02.548248','https://data.go.th/dataset/item_3579c955-e816-4fb3-97af-cb052fe89c29');
