INSERT OR REPLACE INTO datasets VALUES ('item_27d3aedf-32ae-4528-9c80-821b351c1b16','จำนวนคนต่างด้าวเข้าเมืองถูกกฎหมายที่ได้รับอนุญาตทำงานคงเหลืออยู่ในประเทศไทย จำแนกตามจังหวัด ทั่วราชอาณาจักร ณ ธันวาคม 2558','ข้อมูลจำนวนคนต่างด้าวเข้าเมืองถูกกฎหมายที่ได้รับอนุญาตทำงานคงเหลืออยู่ในประเทศไทย &nbsp;จำแนกตามจังหวัด ทั่วราชอาณาจักร &nbsp;ณ ธันวาคม &nbsp;2558 เป็นข้อมูลจาการดำเนินงานการทำงานของคนต่างด้าว ของหน่วยงานในสังกัดกรมการจัดหางาน ทั่วประเทศ ประกอบด้วย -ประเภทการอนุญาต -ประเภทคนต่างด้าว ได้แก่ ตลอดชีพ &nbsp;ทั่วไป นำเข้า ตรวจสัญชาติ ส่งเสริมการลงทุน&nbsp; -จังหวัด','กรมการจัดหางาน','["คงเหลือ","ตรวจสัญชาติ","ตลอดชีพ","ทั่วไป","นำเข้า","ส่งเสริมการลงทุน"]','["XLSX","ZIP"]',2,'[{"name":"คนต่างด้าวถูก กม.คงเหลือ","format":"XLSX","url":"https://data.go.th/dataset/4af7478c-dfcc-4156-bee8-5006050e9fdd/resource/7498f8f4-aefd-4979-b147-2c992d79f7d1/download/-..xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/4af7478c-dfcc-4156-bee8-5006050e9fdd/resource/74af9c53-a7c0-421b-b652-e6ecd2107030/download/item_27d3aedf-32ae-4528-9c80-821b351c1b16-rsao02.zip"}]','Creative Commons Attributions','2021-10-31T05:43:52.591868','https://data.go.th/dataset/item_27d3aedf-32ae-4528-9c80-821b351c1b16');
