INSERT OR REPLACE INTO datasets VALUES ('item_1e4f4571-2f11-4f2b-90ad-05bfecc8956f','สถิติขนส่งทางอากาศปริมาณการจราจรทางอากาศของสายการบินต้นทุนต่ำปี 2553','สถิติขนส่งทางอากาศปริมาณการจราจรทางอากาศของสายการบินต้นทุนต่ำปี 2553','บริษัท ท่าอากาศยานไทย จำกัด (มหาชน)','[]','["XSL","ZIP"]',2,'[{"name":"สถิติขนส่งทางอากาศปริมาณการจราจรทางอากาศของสายการบินต้นทุนต่ำปี 2553","format":"XSL","url":"https://data.go.th/dataset/8be1318e-ba43-44b2-98f6-b14ea9d42eaf/resource/b78307f9-95a7-4133-9a60-0e72c025c51e/download/_2553.xls"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/8be1318e-ba43-44b2-98f6-b14ea9d42eaf/resource/4fd66156-0092-46f2-a730-b5b5d921576a/download/item_1e4f4571-2f11-4f2b-90ad-05bfecc8956f-uxmp1v.zip"}]','Creative Commons Attributions','2021-10-31T05:43:46.526790','https://data.go.th/dataset/item_1e4f4571-2f11-4f2b-90ad-05bfecc8956f');
INSERT OR REPLACE INTO datasets VALUES ('item_1bb6c907-75f5-4aab-95f8-3f6f8862ac1e','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2559','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2559","format":"XLSX","url":"https://data.go.th/dataset/0d5eec10-de65-4255-9afc-e2dacb2d0cb3/resource/152b298f-748c-47fb-82d0-c92755e2ea60/download/-2559.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/0d5eec10-de65-4255-9afc-e2dacb2d0cb3/resource/e124de95-ef13-4130-801a-f39383a8790f/download/item_1bb6c907-75f5-4aab-95f8-3f6f8862ac1e-nzltlb.zip"}]','Creative Commons Attributions','2021-10-31T05:43:46.047711','https://data.go.th/dataset/item_1bb6c907-75f5-4aab-95f8-3f6f8862ac1e');
INSERT OR REPLACE INTO datasets VALUES ('item_1c379951-0251-4e57-b354-d190e5c5cc8d','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนสิงหาคม 2560','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนสิงหาคม 2560','สำนักงานปลัดสำนักนายกรัฐมนตรี','["ร้องทุกข์","ร้องเรียน"]','["CSV","ZIP"]',2,'[{"name":"จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนสิงหาคม 2560","format":"CSV","url":"https://data.go.th/dataset/bb1869ee-7a07-41e8-9866-0c352aa179d6/resource/eb94e3d5-5808-49d9-8a3d-089533eab4ee/download/opendata-60.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/bb1869ee-7a07-41e8-9866-0c352aa179d6/resource/241977cc-8c29-4a82-91d0-8b12009b3930/download/item_1c379951-0251-4e57-b354-d190e5c5cc8d-6x6ci_.zip"}]','Creative Commons Attributions','2021-10-31T05:43:45.603558','https://data.go.th/dataset/item_1c379951-0251-4e57-b354-d190e5c5cc8d');
INSERT OR REPLACE INTO datasets VALUES ('item_1bda08ac-6a6a-4269-a2c0-4e50d40f830e','สถิติการศึกษาต่อของนักเรียนทุนรัฐบาลตามประเทศที่ศึกษาและประเภททุน ในเดือนมกราคม 2558','สถิติการศึกษาต่อของนักเรียนทุนรัฐบาล แบ่งตามประเทศที่ศึกษา และ ประเภททุน ประจำเดือนมกราคม พ.ศ. 2558','สำนักงานคณะกรรมการข้าราชการพลเรือน','["ประจำเดือนมกราคม","ประเภททุน","พ.ศ.","และ"]','["CSV","ZIP"]',2,'[{"name":"สถิติการศึกษาต่อของนักเรียนทุนรัฐบาลตามประเทศที่ศึกษาและประเภททุน ในเดือนมกราคม 2558","format":"CSV","url":"https://data.go.th/dataset/86949f78-4e0c-48f9-a5a5-d08f6785b791/resource/258f74d4-efeb-4b0a-bb99-e3265b0f6fbb/download/580131-ccountry.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/86949f78-4e0c-48f9-a5a5-d08f6785b791/resource/30e8ade0-ba65-4659-9700-03a7a36fef23/download/item_1bda08ac-6a6a-4269-a2c0-4e50d40f830e-a9pequ.zip"}]','Creative Commons Attributions','2021-10-31T05:43:45.152573','https://data.go.th/dataset/item_1bda08ac-6a6a-4269-a2c0-4e50d40f830e');
