INSERT OR REPLACE INTO datasets VALUES ('item_1a76eafd-3423-44c8-b0c5-db1ac476dad5','จำนวนใบอนุญาตขับรถ และใบอนุญาตผู้ประจำรถสะสม 31 ธันวาคม 2558','สถิติจำนวนใบอนุญาตขับรถและใบอนุญาตผู้ประจำรถสะสม ณ วันที่ ........ &nbsp; หมายถึง &nbsp; จำนวนใบอนุญาตขับรถและใบอนุญาตผู้ประจำรถ ตามกฎหมายว่าด้วยรถยนต์&nbsp; และกฎหมายว่าด้วยการขนส่งทางบก &nbsp;ที่มีอยู่ทั้งสิ้น ณ วันที่ ............ &nbsp; โดยเป็นใบอนุญาตที่ยังไม่ถึงกำหนดวันหมดอายุใบอนุญาต &nbsp;','กรมการขนส่งทางบก','["จำนวนใบอนุญาตขับรถ"]','["CSV","XSL","ZIP"]',4,'[{"name":"จำนวนใบอนุญาตขับรถ และใบอนุญาตผู้ประจำรถสะสม 31 ธันวาคม 2558 - csv","format":"CSV","url":"https://data.go.th/dataset/23af2aba-0cc6-43a2-8854-902d6822283e/resource/6a1b2b73-279d-4c33-a40d-e7c083c3d42e/download/data_dr12-2558.csv"},{"name":"จำนวนใบอนุญาตขับรถ และใบอนุญาตผู้ประจำรถสะสม 31 ธันวาคม 2558 - xls","format":"XSL","url":"https://data.go.th/dataset/23af2aba-0cc6-43a2-8854-902d6822283e/resource/fdd22bf1-79c8-44bd-87cb-fdffd5abbc49/download/data_dr12-2558.xls"},{"name":"คำอธิบายชุดข้อมูล จำนวนใบอนุญาตขับรถ และใบอนุญาตผู้ประจำรถสะสม 31 ธันวาคม 2558","format":"XSL","url":"https://data.go.th/dataset/23af2aba-0cc6-43a2-8854-902d6822283e/resource/e9d58b82-3d5f-4c64-bc05-48ec73103350/download/metadata_dr12-2558.xls"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/23af2aba-0cc6-43a2-8854-902d6822283e/resource/8779bc07-24b8-480e-bc0d-619687607ffd/download/item_1a76eafd-3423-44c8-b0c5-db1ac476dad5-3zzara.zip"}]','Creative Commons Attributions','2021-10-31T05:43:43.372892','https://data.go.th/dataset/item_1a76eafd-3423-44c8-b0c5-db1ac476dad5');
INSERT OR REPLACE INTO datasets VALUES ('item_18768792-ac2d-488e-a1d4-8e851835fc1a','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนกุมภาพันธ์ 2559','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง&nbsp;1111 โดยจำแนกตามประเภทเรื่องร้องทุกข์','สำนักงานปลัดสำนักนายกรัฐมนตรี','["ร้องทุกข์","ร้องเรียน"]','["CSV","ZIP"]',2,'[{"name":"จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนกุมภาพันธ์ 2559","format":"CSV","url":"https://data.go.th/dataset/6568263f-de44-4101-a4e9-892ee11aff08/resource/786bf136-82eb-4e69-88af-f592ad043bd3/download/opendata__02-2559.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/6568263f-de44-4101-a4e9-892ee11aff08/resource/3ba6c491-f5e1-48eb-98d5-74ea261a2dd9/download/item_18768792-ac2d-488e-a1d4-8e851835fc1a-itfn4r.zip"}]','Creative Commons Attributions','2021-10-31T05:43:42.797883','https://data.go.th/dataset/item_18768792-ac2d-488e-a1d4-8e851835fc1a');
INSERT OR REPLACE INTO datasets VALUES ('item_14d76e6f-5298-49a0-87c3-52f1a08c9a44','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนพฤศจิกายน 2558','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง&nbsp;1111 โดยจำแนกตามประเภทเรื่องร้องทุกข์','สำนักงานปลัดสำนักนายกรัฐมนตรี','["ร้องทุกข์","ร้องเรียน"]','["CSV","ZIP"]',2,'[{"name":"จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนพฤศจิกายน 2558","format":"CSV","url":"https://data.go.th/dataset/d6b8dbad-53fd-4556-adc2-62870b17570b/resource/ae3b9baa-ed0d-4458-9035-b28122fd4112/download/opendata__11-2558.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/d6b8dbad-53fd-4556-adc2-62870b17570b/resource/f7beb6cb-729e-4545-8bf0-889edc10d81d/download/item_14d76e6f-5298-49a0-87c3-52f1a08c9a44-yn8gje.zip"}]','Creative Commons Attributions','2021-10-31T05:43:41.665571','https://data.go.th/dataset/item_14d76e6f-5298-49a0-87c3-52f1a08c9a44');
INSERT OR REPLACE INTO datasets VALUES ('item_14546c4b-8629-434c-9df6-61d254d15633','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2547','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2547","format":"XLSX","url":"https://data.go.th/dataset/e2229624-6aab-4edd-a768-e76a369defc3/resource/885c5b13-ae89-4e41-ad06-fbc264b60a07/download/-2547.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/e2229624-6aab-4edd-a768-e76a369defc3/resource/90918885-a705-4ba3-a7d9-bd5bebc13903/download/item_14546c4b-8629-434c-9df6-61d254d15633-o08_7n.zip"}]','Creative Commons Attributions','2021-10-31T05:43:40.867299','https://data.go.th/dataset/item_14546c4b-8629-434c-9df6-61d254d15633');
