INSERT OR REPLACE INTO datasets VALUES ('item_ad087826-8400-4384-997d-0ef26cd49e45','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2554','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2554","format":"XLSX","url":"https://data.go.th/dataset/ca465a1d-2610-482d-b222-5c462bb44d55/resource/18b43f01-5929-438a-9b6e-ab9d5cc56468/download/-2554.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/ca465a1d-2610-482d-b222-5c462bb44d55/resource/c3101f90-769d-4a1c-8fdd-0c7934ecb957/download/item_ad087826-8400-4384-997d-0ef26cd49e45-j3mdtq.zip"}]','Creative Commons Attributions','2021-10-31T05:43:30.865615','https://data.go.th/dataset/item_ad087826-8400-4384-997d-0ef26cd49e45');
