INSERT OR REPLACE INTO datasets VALUES ('item_a8ea9335-8009-4de6-aa22-124d9c9bc0b7','จำนวนคนต่างด้าวเข้าเมืองถูกกฎหมายที่ยื่นคำขอและได้รับอนุญาตให้ทำงาน จำแนกตามจังหวัด ทั่วราชอาณาจักร ปี 2558','ข้อมูลจำนวนคนต่างด้าวเข้าเมืองถูกกฎหมายที่ยื่นคำขอและได้รับอนุญาตให้ทำงาน จำแนกตามจังหวัด ทั่วราชอาณาจักร &nbsp;ปี &nbsp;2558 เป็นข้อมูลจาการดำเนินงานพิจารณาออกใบอนุญาตทำงานให้คนต่างด้าว ของหน่วยงานในสังกัดกรมการจัดหางาน ทั่วประเทศ ประกอบด้วย -การยื่นคำขอใบอนุญาตทำงาน -การได้รับใบอนุญาตทำงาน -จังหวัด -คนต่างด้าวประเภท ทั่วไป , นำเข้า , ตรวจสัญชาติ , ส่งเสริมการลงทุน&nbsp;','กรมการจัดหางาน','["คนต่างด้าว","ตรวจสัญชาติ","ทั่วไป","นำเข้า","ยื่นคำขอ","ส่งเสริมการลงทุน","อนุญาต"]','["XLSX","ZIP"]',2,'[{"name":"คนต่างด้าวถูก กม.ได้รับอนุญาตทำงาน","format":"XLSX","url":"https://data.go.th/dataset/b24de4f6-fdf3-41cb-9a82-d1f9a3a26854/resource/c974beba-12c3-49b4-82fe-90ec92d635ad/download/-..xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/b24de4f6-fdf3-41cb-9a82-d1f9a3a26854/resource/ba85a0ee-6dee-4873-8ff5-23b83278977a/download/item_a8ea9335-8009-4de6-aa22-124d9c9bc0b7-u6dct7.zip"}]','Creative Commons Attributions','2021-10-31T05:43:28.117482','https://data.go.th/dataset/item_a8ea9335-8009-4de6-aa22-124d9c9bc0b7');
