INSERT OR REPLACE INTO datasets VALUES ('item_90ca9ae8-cee3-443f-9125-ced727bc3eb9','นโยบายของคณะรัฐมนตรีแห่งประเทศไทย','นโยบายของคณะรัฐมนตรีแห่งประเทศไทย คณะรัฐมนตรีพลเอก ประยุทธ์ จันทร์โอชา พระบรมราชโองการประกาศแต่งตั้งนายกรัฐมนตรี 24 สิงหาคม 2557 &nbsp;พระบรมราชโองการประกาศแต่งตั้งรัฐมนตรี &nbsp;30 สิงหาคม 2557 &nbsp; พระบรมราชโองการประกาศแต่งตั้งรัฐมนตรี [นายวิสุทธิ์ ศรีสุพรรณ และ นายอำนวย ปะติเส เมื่อ 18 พ.ย. 2557 (เพิ่มเติมครั้งที่ 1)] ถวายสัตย์ฯ วันที่ 23 พ.ย. 2557 &nbsp;พระบรมราชโองการประกาศ ให้รัฐมนตรีพ้นจากความเป็นรัฐมนตรีและแต่งตั้งรัฐมนตรี เมื่อ 19 ส.ค. 2558 &nbsp;(ปรับคณะรัฐมนตรี ครั้งที่ 1) ปรับปรุงข้อมูลครั้งสุดท้ายเมื่อ 3 กันยายน 2558 &nbsp;','สำนักเลขาธิการคณะรัฐมนตรี','["cabinet","policy","คณะรัฐมนตรี","นโยบาย"]','["CSV","XLSX","ZIP"]',3,'[{"name":"Cabinet Policy","format":"CSV","url":"https://data.go.th/dataset/0b025a80-7057-4297-8e6c-ab6c57d1d86f/resource/11663ff6-861e-489d-b73d-6ed828a7294d/download/cab_policy.csv"},{"name":"CABINET_POLICY_METADATA","format":"XLSX","url":"https://data.go.th/dataset/0b025a80-7057-4297-8e6c-ab6c57d1d86f/resource/22d76e4b-1d65-4119-88b5-3c1757598309/download/cabinet_policy_metadata.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/0b025a80-7057-4297-8e6c-ab6c57d1d86f/resource/5c6b5ea2-46c1-4905-aebb-fd5522b0b137/download/item_90ca9ae8-cee3-443f-9125-ced727bc3eb9-s7z3y6.zip"}]','Creative Commons Attributions','2021-10-31T05:43:13.264002','https://data.go.th/dataset/item_90ca9ae8-cee3-443f-9125-ced727bc3eb9');
