INSERT OR REPLACE INTO datasets VALUES ('item_8fec201c-3da4-476b-a173-e9e7c5431251','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2552','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2552","format":"XLSX","url":"https://data.go.th/dataset/d87c89e1-84ec-4013-88f4-0a7bcee39312/resource/55451835-6324-4a30-ac5e-0686b5c0a181/download/-2552.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/d87c89e1-84ec-4013-88f4-0a7bcee39312/resource/57b28591-d315-4624-bf6f-de2b4a23d797/download/item_8fec201c-3da4-476b-a173-e9e7c5431251-r1d_fd.zip"}]','Creative Commons Attributions','2021-10-31T05:43:11.686951','https://data.go.th/dataset/item_8fec201c-3da4-476b-a173-e9e7c5431251');
