INSERT OR REPLACE INTO datasets VALUES ('item_8794f78d-8f39-403a-b119-6c9fe9067629','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2542','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2542","format":"XLSX","url":"https://data.go.th/dataset/8f20b639-4627-403e-be2c-736729c0d49c/resource/ba9589cd-86c7-4dad-ae78-fad8540a367c/download/-2542.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/8f20b639-4627-403e-be2c-736729c0d49c/resource/a4ef9f5b-00d6-4b2f-b645-2f7d727be904/download/item_8794f78d-8f39-403a-b119-6c9fe9067629-i87lat.zip"}]','Creative Commons Attributions','2021-10-31T05:43:06.588226','https://data.go.th/dataset/item_8794f78d-8f39-403a-b119-6c9fe9067629');
