INSERT OR REPLACE INTO datasets VALUES ('item_7d715de9-1018-4ac0-9fb2-ec231d5009cf','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2556','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2556","format":"XLSX","url":"https://data.go.th/dataset/5c5bfd69-4c5a-465a-9b00-f3471106aa28/resource/988a2df2-2156-406b-bfae-20bc238b618a/download/-2556.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/5c5bfd69-4c5a-465a-9b00-f3471106aa28/resource/e952e3e7-81f0-4eb1-b507-e07c11619820/download/item_7d715de9-1018-4ac0-9fb2-ec231d5009cf-uxljk3.zip"}]','Creative Commons Attributions','2021-10-31T05:43:00.469686','https://data.go.th/dataset/item_7d715de9-1018-4ac0-9fb2-ec231d5009cf');
