INSERT OR REPLACE INTO datasets VALUES ('item_5ef79739-2f55-4c8d-b087-a7932f3d92b0','จำนวนใบอนุญาตขับรถ และใบอนุญาตผู้ประจำรถสะสม 31 กรกฎาคม 2559','สถิติจำนวนใบอนุญาตขับรถและใบอนุญาตผู้ประจำรถสะสม ณ วันที่ ........ &nbsp; หมายถึง &nbsp;จำนวนใบอนุญาตขับรถและใบอนุญาตผู้ประจำรถ ตามกฎหมายว่าด้วยรถยนต์ และกฎหมายว่าด้วยการขนส่งทางบก &nbsp;ที่มีอยู่ทั้งสิ้น ณ วันที่ ............ &nbsp;โดยเป็นใบอนุญาตที่ยังไม่ถึงกำหนดวันหมดอายุใบอนุญาต','กรมการขนส่งทางบก','["จำนวนใบอนุญาตขับรถ","แ�"]','["CSV","XSL","ZIP"]',4,'[{"name":"DR07-2559.csv","format":"CSV","url":"https://data.go.th/dataset/7ea85be2-fe11-43c2-9ac5-d2d95e00bb6f/resource/a030923b-b862-4990-8cbe-42651dfd9346/download/data_dr07-2559.csv"},{"name":"DR07-2559.xls","format":"XSL","url":"https://data.go.th/dataset/7ea85be2-fe11-43c2-9ac5-d2d95e00bb6f/resource/60cd2398-c247-4368-bf3d-9c0abbb7e4b6/download/data_dr07-2559.xls"},{"name":"MetaData_DR07_2559.xls","format":"XSL","url":"https://data.go.th/dataset/7ea85be2-fe11-43c2-9ac5-d2d95e00bb6f/resource/63c63022-ffdc-4388-bd98-498a82556d7b/download/metadata_dr07-2559.xls"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/7ea85be2-fe11-43c2-9ac5-d2d95e00bb6f/resource/d340e5a3-8985-4cff-ac4a-f8965454b916/download/item_5ef79739-2f55-4c8d-b087-a7932f3d92b0-veadrz.zip"}]','Creative Commons Attributions','2021-10-31T05:42:56.663403','https://data.go.th/dataset/item_5ef79739-2f55-4c8d-b087-a7932f3d92b0');
INSERT OR REPLACE INTO datasets VALUES ('item_5d71dbdb-3008-497d-ac36-114703f7b92e','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนกันยายน 2559','จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนกันยายน 2559','สำนักงานปลัดสำนักนายกรัฐมนตรี','["ร้องทุกข์","ร้องเรียน"]','["CSV","ZIP"]',2,'[{"name":"จำนวนเรื่องร้องทุกข์ที่ประชาชนแจ้งเรื่องผ่านช่องทาง 1111 ประจำเดือนกันยายน 2559","format":"CSV","url":"https://data.go.th/dataset/c00cf4d3-c35b-4606-a5a1-6457e1cf1339/resource/cdcf95c2-9703-40fc-a26a-3d1a4c428afe/download/opendata2559.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/c00cf4d3-c35b-4606-a5a1-6457e1cf1339/resource/fb246035-75b2-44dc-94aa-577e444980ea/download/item_5d71dbdb-3008-497d-ac36-114703f7b92e-xokiti.zip"}]','Creative Commons Attributions','2021-10-31T05:42:56.081025','https://data.go.th/dataset/item_5d71dbdb-3008-497d-ac36-114703f7b92e');
INSERT OR REPLACE INTO datasets VALUES ('item_5acf6bf7-6598-4729-8d0f-2beeed3a679f','ข้อมูลทะเบียนแหล่งเรียนรู้การเลี้ยงสัตว์','ข้อมูลแหล่งเรียนรู้ด้านการเลี้ยงสัตว์ที่ขึ้นทะเบียนกับกองส่งเสริมและพัฒนาการปศุสัตว์ ได้แก่ ฟาร์มตัวอย่าง ฟาร์มสาธิต หรือฟาร์มต้นแบบ เพื่อใช้เป็นแบบอย่างสำหรับเกษตรกร และพัฒนาสู่การเป็นศูนย์เรียนรู้ เพื่อเพิ่มขีดความสามารถในการเป็นแหล่งฝึกอบรมและศึกษาดูงานของเกษตรกรและผู้สนใจ และสามารถพัฒนาความพร้อมและคุณภาพของแหล่งเรียนรู้สู่มาตรฐานที่กำหนดไว้ เพื่อเป็นการรับรองสถานภาพของแหล่งเรียนรู้ รวมทั้งเผยแพร่ประชาสัมพันธ์แหล่งเรียนรู้ดังกล่าวแก่หน่วยงานต่างๆ เพื่อร่วมกับพัฒนาและใช้ประโยชน์ต่อไป','กรมปศุสัตว์','["จังหวัด"]','["XSL","ZIP"]',2,'[{"name":"ข้อมูลทะเบียนแหล่งเรียนรู้การเลี้ยงสัตว์","format":"XSL","url":"https://data.go.th/dataset/991543f0-fed2-4531-bc0a-a62c003f43d7/resource/76be0607-bbb9-433f-ba8a-1aed3cd896a1/download/2016-dld7.xls"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/991543f0-fed2-4531-bc0a-a62c003f43d7/resource/7095abcd-bb09-45f9-82fe-8f15aa49cb72/download/item_5acf6bf7-6598-4729-8d0f-2beeed3a679f-bj1ktl.zip"}]','Creative Commons Attributions','2021-10-31T05:42:55.758854','https://data.go.th/dataset/item_5acf6bf7-6598-4729-8d0f-2beeed3a679f');
INSERT OR REPLACE INTO datasets VALUES ('item_5cdee949-2d0a-41b9-af32-8af617cf21c6','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2557','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิ�"]','["XLSX","ZIP"]',2,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2557","format":"XLSX","url":"https://data.go.th/dataset/32784c68-6c47-4457-95ba-297ca81f1519/resource/211057ac-94cc-4c57-a3aa-9ded08016078/download/-2557.xlsx"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/32784c68-6c47-4457-95ba-297ca81f1519/resource/3aa7cee3-ac8e-4b0b-a865-61000c95509e/download/item_5cdee949-2d0a-41b9-af32-8af617cf21c6-kddl41.zip"}]','Creative Commons Attributions','2021-10-31T05:42:55.045100','https://data.go.th/dataset/item_5cdee949-2d0a-41b9-af32-8af617cf21c6');
