INSERT OR REPLACE INTO datasets VALUES ('item_5290246b-97a4-43d9-acd2-da52bc6c810a','การดำเนินงานโครงการเงินอุดหนุนเพื่อการเลี้ยงดูเด็กแรกเกิด','โครงการเงินอุดหนุนเพื่อการเลี้ยงดูเด็กแรกเกิด เป็นนโยบายสาคัญระดับชาติตามแผนบูรณาการ การพัฒนาคนตลอดช่วงชีวิต มุ่งเน้นให้เด็กแรกเกิดได้รับการเลี้ยงดูที่มีคุณภาพ และมีพัฒนาการเหมาะสมตามวัยเพื่อเติบโตเป็นประชากรที่มีคุณภาพในอนาคต รวมทั้งเป็นหลักประกันให้เด็กได้รับสิทธิ์ด้าน การอยู่รอดและการพัฒนาตามอนุสัญญาว่าด้วยสิทธิเด็ก ซึ่งคณะรัฐมนตรีมีมติเมื่อวันที่ 31 มีนาคม 2558 เห็นชอบหลักการโครงการเงินอุดหนุนเพื่อการเลี้ยงดูเด็กแรกเกิด โดยให้เงินอุดหนุนแก่เด็กแรกเกิด ที่เกิดระหว่าง วันที่ 1 ตุลาคม 2558 ถึง 30 กันยายน 2559 อยู่ในครัวเรือนยากจนและครัวเรือนที่เสี่ยงต่อความยากจน รายละ 400 บาท ต่อคน/เดือน เป็…','กรมกิจการเด็กและเยาวชน','["โครงการเงินอุดหนุนเพ"]','["PDF","CSV","ZIP"]',5,'[{"name":"คู่มือการดำเนินงานโครงการเงินอุดหนุนเพื่อการเลี้ยงดูเด็กแรกเกิด","format":"PDF","url":"https://data.go.th/dataset/18f1cf48-21fe-45d6-9528-c2920bd8aa70/resource/ed2f6ef7-f47c-49c0-804a-2225b2e44b3a/download/manual_final-2.pdf"},{"name":"โปสเตอร์","format":"PDF","url":"https://data.go.th/dataset/18f1cf48-21fe-45d6-9528-c2920bd8aa70/resource/9a05b76e-66c5-481f-af16-319dc05498c0/download/poster-1.pdf"},{"name":"การดำเนินงานโครงการเงินอุดหนุนเพื่อการเลี้ยงดูเด็กแรกเกิด","format":"CSV","url":"https://data.go.th/dataset/18f1cf48-21fe-45d6-9528-c2920bd8aa70/resource/08b9d64d-cde2-43d7-a0b2-25f816d9fbd3/download/x1.csv"},{"name":"ประชาสัมพันธ์โครงการ","format":"CSV","url":"https://data.go.th/dataset/18f1cf48-21fe-45d6-9528-c2920bd8aa70/resource/63ec5e76-4b4f-462c-b7c1-0f4c980c9650/download/x1.csv"},{"name":"All resource data","format":"ZIP","url":"https://data.go.th/dataset/18f1cf48-21fe-45d6-9528-c2920bd8aa70/resource/f8e26f85-4b1e-4343-97ea-7257bdfaca55/download/item_5290246b-97a4-43d9-acd2-da52bc6c810a-kf5d2l.zip"}]','Creative Commons Attributions','2021-10-31T05:42:49.989059','https://data.go.th/dataset/item_5290246b-97a4-43d9-acd2-da52bc6c810a');
