INSERT OR REPLACE INTO datasets VALUES ('item_4d748419-0846-4ff7-9604-6bf79fc54e55','ข้อมูลหน่วยงานบริการสุขภาพประจวบคีรีขันธ์','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["หน่วยงานบริการสุขภาพ"]','["CSV"]',1,'[{"name":"รหัสหน่วยงานบริการสุขภาพ_ประจวบคีรีขันธ์_CSV","format":"CSV","url":"https://data.go.th/dataset/848c859d-e947-48b7-90e2-d23629f06db6/resource/08325837-24fe-4b7f-b699-aa45066d157b/download/__csv.csv"}]','Creative Commons Attributions','2021-10-31T05:42:41.639077','https://data.go.th/dataset/item_4d748419-0846-4ff7-9604-6bf79fc54e55');
INSERT OR REPLACE INTO datasets VALUES ('item_0b0f96f2-8275-48d5-a485-227ed0f4bb44','ข้อมูลหน่วยงานบริการสุขภาพนครนายก','ข้อมูลหน่วยงานบริการสุขภาพ ประกอบไปด้วย รหัสหน่วย ชื่อหน่วยงาน รหัสสังกัด สังกัด รหัสประเภท ประเภท ระดับขีดความสามารถ จำนวนเตียง รหัสจังหวัด จังหวัด รหัสอำเภอ อำเภอ รหัสตำบล ตำบล รหัสหมู่ หมู่ สถานะ สถานะการเปิดบริการ ที่อยู่ รหัสไปรษณีย์ โทรศัพท์ โทรสาร รหัสระดับการบริการ ระดับการบริการ รหัสประเภทบริการ ประเภทบริการ รหัสการเปลี่ยนแปลง ชื่อการเปลี่ยนแปลง หมายเหตุ วันที่กำหนดรหัส วันที่ยกเลิกรหัส วันที่เปิดบริการ วันที่ปิดบริการ และวันที่ปรับปรุงข้อมูลล่าสุด','สำนักงานปลัดกระทรวงสาธารณสุข','["หน่วยงานบริการสุขภาพ"]','["CSV","XML"]',2,'[{"name":"รหัสหน่วยงานบริการสุขภาพ_นครนายก_CSV","format":"CSV","url":"https://data.go.th/dataset/04cfcdfb-aa18-45bd-bff3-07f3ec09944b/resource/b63db42f-0c9e-486f-8915-409a99f32902/download/__csv.csv"},{"name":"รหัสหน่วยงานบริการสุขภาพ_นครนายก_XML","format":"XML","url":"https://data.go.th/dataset/04cfcdfb-aa18-45bd-bff3-07f3ec09944b/resource/44c9a80f-7323-4376-92b2-949f27550c87/download/__xml.xml"}]','Creative Commons Attributions','2021-10-31T05:42:40.951210','https://data.go.th/dataset/item_0b0f96f2-8275-48d5-a485-227ed0f4bb44');
