INSERT OR REPLACE INTO datasets VALUES ('item_0ac3e558-72eb-4413-8a6b-4cb651b09ee4','ข้อมูลประทานบัตร','เป็นข้อมูลใบอนุญาตที่ออกให้ เพื่อทำเหมืองแร่ภายในเขตที่กำหนด โดยประทานบัตรแต่ละแปลงจะมีเนื้อที่ไม่เกิน 300 ไร่ เว้นแต่ประทานบัตรในทะเลจะมีเนื้อที่ได้ไม่เกิน 50,000 ไร่ และมีอายุไม่เกิน 25 ปี ประกอบด้วยข้อมูลดังนี้ - เลขที่ประทานบัตร - ชื่อผู้ถือประทานบัตร - วันอนุญาต - วันสิ้นอายุ - ภาค, จังหวัด, อำเภอ, ตำบล - เนื่้อที่ (ไร่ - งาน - วา) - ชนิดแร่ - รหัส TSIC (*&nbsp;รหัสธุรกิจ TSIC&nbsp;2552 ที่สัมพันธ์กับกิจกรรม หมวด B: การทำเหมืองแร่และเหมืองหิน (Mining and Quarrying) - หมายเลขท่อ (** หมายเลข หลักหมายเขตเหมืองแร่ มุมที่ 1) - พิกัด X, พิกัด Y (*** ตามระวางแผนที่ภูมิประเทศลำดับชุด L7017)','กรมอุตสาหกรรมพื้นฐานและการเหมืองแร่','["ข้อมูลใบอนุญาต","ชนิดแร่","ประทานบัตร","เหมืองหิน","เหมืองแร่","แร่","ใบอนุญาต"]','["CSV","XSL","PDF"]',9,'[{"name":"ข้อมูลประทานบัตร(21/06/2559)","format":"CSV","url":"https://data.go.th/dataset/b9da4f6d-fb97-4db7-895f-512d9df9df8c/resource/b991ef39-9282-4926-ae04-500163dc94f9/download/21392016100621dpim200.csv"},{"name":"ข้อมูลประทานบัตร(ปรับปรุงล่าสุด : 11/08/2558)","format":"CSV","url":"https://data.go.th/dataset/b9da4f6d-fb97-4db7-895f-512d9df9df8c/resource/d1f94b31-d84c-4920-805d-21c6a9b26e93/download/new25580811mining_permit.csv"},{"name":"ข้อมูลประทานบัตร(ปรับปรุงล่าสุด : 11/08/2558)","format":"XSL","url":"https://data.go.th/dataset/b9da4f6d-fb97-4db7-895f-512d9df9df8c/resource/95d3c52c-227c-4a93-a9de-29add624db00/download/new25580811mining_permit.xls"},{"name":"คำอธิบายข้อมูลประทานบัตร","format":"PDF","url":"https://data.go.th/dataset/b9da4f6d-fb97-4db7-895f-512d9df9df8c/resource/727010e8-53d4-4227-99cf-be4737671b3b/download/xx.pdf"},{"name":"รหัสธรุ กิจ TSIC 2552 ที่สัมพันธก์ ับกิจกรรม หมวด B :กำรท ำเหมอืงแร่และเหมอืงหิน (Mining and Quarry…","format":"PDF","url":"https://data.go.th/dataset/b9da4f6d-fb97-4db7-895f-512d9df9df8c/resource/5fcc5587-ed80-4fc6-a263-f93f125e73a0/download/tsic_mining.pdf"},{"name":"ข้อมูลประทานบัตร","form