INSERT OR REPLACE INTO datasets VALUES ('item_e85c10bb-d155-4292-8352-0cf0b3dfa752','สิถิติจราจรปี 2556','สิถิติจราจรปี 2556 ประกอบด้วย ข้อมูลปริมาณจราจร อัตราความเร็วในการเดินทาง ข้อมูลสะพาน ข้อมูลสัญญาณไฟจราจร ข้อมูลอุปกรณ์ด้านความปลอดภัย จำนวนผู้ใช้บริการระบบขนส่งสาธารณะ สถิติอุบัติเหตุจราจร จำนวนรถที่จดทะเบียน ข้อมูลเชื้อเพลิง และข้อมูลการตรวจวัดคุณภาพอากาศ','กรุงเทพมหานคร','["ข้อมูลพื้นฐานจราจร"]','["PDF"]',1,'[{"name":"สิถิติจราจรปี 2556","format":"PDF","url":"https://data.go.th/dataset/82959d2b-7af8-4873-9a3a-3b074716a74b/resource/e77bdf4f-6b91-4be6-8aa5-1ae95926c1fe/download/stat_book2556.pdf"}]','Creative Commons Attributions','2021-10-31T05:41:28.784706','https://data.go.th/dataset/item_e85c10bb-d155-4292-8352-0cf0b3dfa752');
