INSERT OR REPLACE INTO datasets VALUES ('item_94a0b576-c3ee-45ec-8de6-d07b55921571','ข้อมูลส่งออกอาหารสัตว์','ข้อมูลส่งออกอาหารสัตว์ กรมปศุสัตว์ ได้เก็บรวบรวม วิเคราะห์ และรายงาน จากหนังสือรับรองความปลอดภัยอาหารสัตว์เพื่อการส่งออก (Health Certificate) ซึ่งมาจากผู้ประกอบการที่มาขออนุญาตส่งออกอาหารสัตว์กับกรมปศุสัตว์ เป็นสถิติข้อมูลให้ผู้ประกอบการ หน่วยงานที่เกี่ยวข้อง และระดับผู้บริหารเพื่อนำไปใช้ประโยชน์ในการประเมินสถานการณ์ส่งออกอาหารสัตว์ของประเทศไทย','กรมปศุสัตว์','["กรมปศุสัตว์","ข้อมูล","ส่งออกอาหารสัตว์","อาหารสัตว์","อาหารสัตว์เลี้ยง"]','["CSV","PDF"]',4,'[{"name":"ข้อมูลส่งออกอาหารสัตว์","format":"CSV","url":"https://data.go.th/dataset/ac205c9a-c550-46d1-8792-7df696ef47c5/resource/516de5d8-1534-4e4f-8b22-7dd3896a859e/download/2015-ogd3.csv"},{"name":"ข้อมูลส่งออกอาหารสัตว์","format":"CSV","url":"https://data.go.th/dataset/ac205c9a-c550-46d1-8792-7df696ef47c5/resource/26cb0cff-1ed5-483c-b9cb-9a35a12e4e8e/download/2015-dld3.csv"},{"name":"ข้อมูลส่งออกอาหารสัตว์","format":"CSV","url":"https://data.go.th/dataset/ac205c9a-c550-46d1-8792-7df696ef47c5/resource/2a184be0-0d87-4dc6-b961-a7e3f68dcf98/download/2015-ogd3.csv"},{"name":"Metadataข้อมูลส่งออกอาหารสัตว์","format":"PDF","url":"https://data.go.th/dataset/ac205c9a-c550-46d1-8792-7df696ef47c5/resource/8d208fbe-3464-4ae0-82ef-8973d0d4f3aa/download/metadata3.pdf"}]','Creative Commons Attributions','2021-10-31T05:41:19.804253','https://data.go.th/dataset/item_94a0b576-c3ee-45ec-8de6-d07b55921571');
INSERT OR REPLACE INTO datasets VALUES ('item_e67664ed-c322-493d-9f30-a0542aa6c1cb','ข้อมูลปราชญ์ชาวบ้าน','รายชื่อปราชญ์ชาวบ้าน ศูนย์เครือข่ายปราชญ์ชาวบ้าน และที่อยู่ศูนย์เครือข่ายปราชญ์ชาวบ้าน ที่เข้าร่วมโครงการพัฒนาการเกษตรตามแนวทฤษฎีใหม่ โดยยึดปรัชญาเศรษฐกิจพอเพียง ปีงบประมาณ พ.ศ. 2558 ของสำนักงานปลัดกระทรวงเกษตรและสหกรณ์','สำนักงานปลัดกระทรวงเกษตรและสหกรณ์','["ข้อมูลปราชญ์ชาวบ้าน"]','["XLSX","XSL"]',2,'[{"name":"Metadata-ข้อมูลปราชญ์ชาวบ้าน","format":"XLSX","url":"https://data.go.th/dataset/01057b6b-705c-4048-84b0-1c8a3890da98/resource/5623c05f-ed77-4923-8c87-4a4d71f4c99b/download/metadata-.xlsx"},{"name":"ศูนย์ปราชญ์58-กษ.xls","format":"XSL","url":"https://data.go.th/dataset/01057b6b-705c-4048-84b0-1c8a3890da98/resource/412645d4-18b0-463e-943f-ebc2ec85c88c/download/58-.xls"}]','Creative Commons Attributions','2021-10-31T05:41:19.025721','https://data.go.th/dataset/item_e67664ed-c322-493d-9f30-a0542aa6c1cb');
INSERT OR REPLACE INTO datasets VALUES ('item_de26c80b-0571-4721-8a82-aeed70919906','ข้อมูลนำเข้าอาหารสัตว์','ข้อมูลนำเข้าอาหารสัตว์ กรมปศุสัตว์ ได้เก็บรวบรวม วิเคราะห์ และรายงาน จากหนังสือแจ้งการนำเข้าซึ่งอาหารสัตว์เข้ามาในราชอาณาจักร (น.ส.4) ซึ่งมาจากผู้ประกอบการที่มาขออนุญาตนำเข้าอาหารสัตว์กับกรมปศุสัตว์ เป็นสถิติข้อมูลให้ผู้ประกอบการ หน่วยงานที่เกี่ยวข้อง และระดับผู้บริหารเพื่อนำไปใช้ประโยชน์ในการประเมินสถานการณ์นำเข้าอาหารสัตว์ของประเทศไทย','กรมปศุสัตว์','["กรมปศุสัตว์","ข้อมูล","นำเข้าอาหารสัตว์","วัตถุดิบอาหารสัตว์","อาหารสัตว์","อาหารสัตว์เลี้ยง"]','["CSV","PDF"]',4,'[{"name":"ข้อมูลนำเข้าอาหารสัตว์","format":"CSV","url":"https://data.go.th/dataset/b7fd3047-e5ab-4d8e-af89-629a3d017bfd/resource/4b74bcdf-89cb-4672-b6f9-97c2bce8b8fe/download/2015-ogd2.csv"},{"name":"ข้อมูลนำเข้าอาหารสัตว์","format":"CSV","url":"https://data.go.th/dataset/b7fd3047-e5ab-4d8e-af89-629a3d017bfd/resource/71415333-5b85-4c21-8882-59563b661d65/download/2015-dld2.csv"},{"name":"ข้อมูลนำเข้าอาหารสัตว์","format":"CSV","url":"https://data.go.th/dataset/b7fd3047-e5ab-4d8e-af89-629a3d017bfd/resource/d753ebc2-d044-48ff-9d71-354b426a507e/download/2015-ogd2.csv"},{"name":"Metadataข้อมูลนำเข้าอาหารสัตว์","format":"PDF","url":"https://data.go.th/dataset/b7fd3047-e5ab-4d8e-af89-629a3d017bfd/resource/06cdde40-2ec6-4a4d-9371-eeef6907ba5b/download/metadata2.pdf"}]','Creative Commons Attributions','2021-10-31T05:41:18.456419','https://data.go.th/dataset/item_de26c80b-0571-4721-8a82-aeed70919906');
