INSERT OR REPLACE INTO datasets VALUES ('item_3ac7c6a8-25da-456b-b867-64b50600c93e','ข้อมูลมติคณะรัฐมนตรี','ข้อมูลมติคณะรัฐมนตรีบนเว็บไซต์สำนักเลขาธิการคณะรัฐมนตรี (www.cabinet.thaigov.go.th)','สำนักเลขาธิการคณะรัฐมนตรี','["cabinet","resolution","ครม","มติคณะรัฐมนตรี","มติครม"]','["XLSX","CSV"]',3,'[{"name":"CABINET_RESOLUTION_METADATA","format":"XLSX","url":"https://data.go.th/dataset/b74447f0-19cd-47d0-aabf-b2781a8b26d6/resource/f2dfa066-22fe-4325-9b90-b7da628de49f/download/cabinet_metadata.xlsx"},{"name":"PREP_DOC","format":"CSV","url":"https://data.go.th/dataset/b74447f0-19cd-47d0-aabf-b2781a8b26d6/resource/0ee78359-947e-4ea0-9728-6be3dab5b63b/download/prep_doc.csv"},{"name":"RELATE_DOC","format":"CSV","url":"https://data.go.th/dataset/b74447f0-19cd-47d0-aabf-b2781a8b26d6/resource/c0dbf348-1d4a-4502-84b0-8be27da22909/download/relate_doc.csv"}]','Creative Commons Attributions','2021-10-31T05:41:13.974670','https://data.go.th/dataset/item_3ac7c6a8-25da-456b-b867-64b50600c93e');
INSERT OR REPLACE INTO datasets VALUES ('item_d69b704d-3300-49ff-9e91-12c7ea58f0e2','สถิติแสดงผลการดำเนินงานด้านปราบปรามการทุจริตของคณะกรรมการ ป.ป.ช. (ตั้งแต่ปีงบประมาณ พ.ศ. 2550 – 2556)','&nbsp; &nbsp; &nbsp;รัฐธรรมนูญแห่งราชอาณาจักรไทย พ.ศ. ๒๕๕๐ มาตรา ๒๕๐ และพระราชบัญญัติประกอบรัฐธรรมนูญว่าด้วยการป้องกันและปราบปรามการทุจริต พ.ศ. ๒๕๔๒ แก้ไขเพิ่มเติม (ฉบับที่ ๒) พ.ศ. ๒๕๕๔ บัญญัติให้คณะกรรมการ ป.ป.ช.มีอำนาจหน้าที่ในการไต่สวนข้อเท็จจริงผู้ดำรงตำแหน่งทางการเมืองและเจ้าหน้าที่ของรัฐซึ่งมิใช่ผู้ดำรงตำแหน่งทางการเมืองใน ๕ กรณี ดังนี้ &nbsp; &nbsp; &nbsp;๑. กรณีการไต่สวนข้อเท็จจริงเพื่อการถอดถอนบุคคลออกจากตำแหน่ง &nbsp; &nbsp; &nbsp;๒. กรณีการไต่สวนข้อเท็จจริงเพื่อการดำเนินคดีอาญากับผู้ดำรงตำแหน่งทางการเมือง &nbsp; &nbsp; &nbsp;๓. กรณีการไต่สวนและวินิจฉัยว่าผู้ดำรงตำแหน่งทางการเมืองหร…','สำนักงานคณะกรรมการป้องกันและปราบปรามการทุจริตแห่งชาติ','["ทุจริต","ป.ป.ช.","ปราบปราม","ปราบปรามการทุจริต","สถิติ"]','["CSV","XLSX"]',2,'[{"name":"สถิติแสดงผลการดำเนินงานด้านปราบปรามการทุจริตของคณะกรรมการ ป.ป.ช. (ตั้งแต่ปีงบประมาณ พ.ศ. 2550 – 255…","format":"CSV","url":"https://data.go.th/dataset/72ba3324-a53d-4831-b322-53058072ec3b/resource/4d5e85e1-2652-4f2e-b448-40df803eedf1/download/naccms_2550_2556.csv"},{"name":"สถิติแสดงผลการดำเนินงานด้านปราบปรามการทุจริตของคณะกรรมการ ป.ป.ช. (ตั้งแต่ปีงบประมาณ พ.ศ. 2550 – 255…","format":"XLSX","url":"https://data.go.th/dataset/72ba3324-a53d-4831-b322-53058072ec3b/resource/3a6c5eab-c7d9-4472-a70e-3cb933533ff2/download/naccms_xls_2550_2556.xlsx"}]','Creative Commons Attributions','2021-10-31T05:41:13.205495','https://data.go.th/dataset/item_d69b704d-3300-49ff-9e91-12c7ea58f0e2');
