INSERT OR REPLACE INTO datasets VALUES ('item_fbada57c-1f5d-496f-a4b1-068a9afd7954','ผู้ลงทะเบียนสมัครงาน ตำแหน่งงานว่าง และการบรรจุงาน จำแนกตามอายุ ทั่วราชอาณาจักร ปี 2558','ข้อมูลผู้ลงทะเบียนสมัครงาน &nbsp;ตำแหน่งงานว่าง &nbsp;และการบรรจุงาน &nbsp;จำแนกตามอายุ ทั่วราชอาณาจักร ปี 2558 เป็นข้อมูลจากการให้บริการจัดหางานในประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ&nbsp; ประกอบด้วยข้อมูลดังนี้ -ผู้ลงทะเบียนสมัครงาน -ตำแหน่งงานว่าง -การบรรจุงาน โดยจำแนกตามอายุ ทั่วประเทศ ปี 2558','กรมการจัดหางาน','["จัดหางานในประเทศ","ตำแหน่งงานว่าง","บรรจุงาน","ปี","ผู้ลงทะเบียนสมัครงาน","อายุ"]','["XLSX"]',1,'[{"name":"ผู้สมัคร ตำแหน่ง บรรจุ แยกอายุ","format":"XLSX","url":"https://data.go.th/dataset/b99650e8-4c18-4608-a6ed-9e878f45750e/resource/10148d11-49d3-4514-bfe7-ac0b15179ef5/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:56.708329','https://data.go.th/dataset/item_fbada57c-1f5d-496f-a4b1-068a9afd7954');
INSERT OR REPLACE INTO datasets VALUES ('item_fd0f77a8-6c5a-4e92-921a-41fcaa7f43d2','ผู้ลงทะเบียนสมัครงาน ตำแหน่งงานว่าง และการบรรจุงาน จำแนกตามอาชีพ และรายอาชีพที่มีความต้องการมาก ทั่วราชอาณาจักร ปี 2558','ข้อมูลผู้ลงทะเบียนสมัครงาน &nbsp;ตำแหน่งงานว่าง &nbsp;และการบรรจุงาน &nbsp;จำแนกตามอาชีพ และรายอาชีพที่มีความต้องการมาก &nbsp;ทั่วราชอาณาจักร ปี 2558 เป็นข้อมูลจากการให้บริการจัดหางานในประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ&nbsp; ประกอบด้วยข้อมูลดังนี้ -ผู้ลงทะเบียนสมัครงาน -ตำแหน่งงานว่าง -การบรรจุงาน โดยจำแนกตามอาชีพ และรายอาชีพที่มีความต้องการมาก &nbsp;ทั่วประเทศ ปี 2558','กรมการจัดหางาน','["ความต้องการ","จัดหางานในประเทศ","ตำแหน่งงานว่าง","บรรจุงาน","ปี","ผู้ลงทะเบียนสมัครงาน","อาชีพ"]','["XLSX"]',1,'[{"name":"ผู้สมัคร ตำแหน่ง บรรจุ รายอาชีพ","format":"XLSX","url":"https://data.go.th/dataset/91e74a8e-e3d7-4e92-aa1a-87b9258b3d53/resource/81baf1dc-5e8f-40a1-a710-5dcd2e9ccb33/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:56.283606','https://data.go.th/dataset/item_fd0f77a8-6c5a-4e92-921a-41fcaa7f43d2');
