INSERT OR REPLACE INTO datasets VALUES ('item_4b492f19-182f-487a-a01b-55972833cc99','ข้อมูลกองทุนสวัสดิการ','ข้อมูลกองทุนสวัสดิการ แยกรายกองทุนสวัสดิการปีล่าสุด ทั้งประเทศ ไม่คัดกรองความสมบูรณ์ของข้อมูล','สถาบันพัฒนาองค์กรชุมชน (องค์การมหาชน)','["กองทุนสวัสดิการ","สวัส�"]','["XLSX"]',1,'[{"name":"Welfare_0111201713424_All","format":"XLSX","url":"https://data.go.th/dataset/fcb9f5e3-da84-4b55-a2a1-b9258310b681/resource/e1bbcda8-36d7-4666-86b8-e06c0aa6c585/download/welfare_0111201713424_all.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:33.557519','https://data.go.th/dataset/item_4b492f19-182f-487a-a01b-55972833cc99');
INSERT OR REPLACE INTO datasets VALUES ('item_2ec63b13-334e-4acc-a894-5855490f0854','การรับเรื่องร้องทุกข์ และการช่วยเหลือคนหางาน กรณีบริษัทจัดหางาน และกรณีสายนายหน้าเถื่อน ตาม พ.ร.บ.จัดหางานฯ 2528 จำแนกตามรายจังหวัด ทั่วราชอาณาจักร ปี 2558','ข้อมูลการรับเรื่องร้องทุกข์ &nbsp;และการช่วยเหลือคนหางาน กรณีบริษัทจัดหางาน และกรณีสายนายหน้าเถื่อน ตาม พ.ร.บ.จัดหางานฯ 2528 จำแนกตามรายจังหวัด ทั่วราชอาณาจักร ปี 2558 เป็นข้อมูลจากการดำเนินการรับเรื่องร้องทุกข์และช่วยเหลือคนหางานที่ถูกหลอกจากบริษัทจัดหางานและสายนายหน้าเถื่อน ประกอบด้วยข้อมูล - รับเรื่องร้องทุกข์ -การช่วยเหลือ -กรณีบริษัทจัดหางาน -กรณีสายนายหน้าเถื่อน -จังหวัด','กรมการจัดหางาน','["กรณีบริษัทจัดหางาน","กรณีสายนายหน้าเถื่อน","การช่วยเหลือ","รับเรื่องร้องทุกข์"]','["XLSX"]',1,'[{"name":"รับเรื่องร้องทุกข์","format":"XLSX","url":"https://data.go.th/dataset/8f6de47f-a479-435e-9b1c-50386710f76c/resource/328920a8-9dc9-4b48-b31c-c21291da8410/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:32.869127','https://data.go.th/dataset/item_2ec63b13-334e-4acc-a894-5855490f0854');
INSERT OR REPLACE INTO datasets VALUES ('item_a7f2e41e-f81f-4eea-97b7-1b8bcd8e6871','การบรรจุงาน จำแนกตามอาชีพ และวุฒิการศึกษา ทั่วราชอาณาจักร ปี 2558','ข้อมูลการบรรจุงาน จำแนกตามอาชีพ และวุฒิการศึกษา ทั่วราชอาณาจักร ปี 2558&nbsp;เป็นข้อมูลจากการให้บริการจัดหางานในประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ ประกอบด้วยข้อมูลดังนี้ - การบรรจุงาน - ประเภทอาชีพ - วุฒิการศึกษา','กรมการจัดหางาน','["การบรรจุงาน","ประเภทอาชีพ","วุฒิการศึกษา"]','["XLSX"]',1,'[{"name":"บรรจุงานอาชีพวุฒิ","format":"XLSX","url":"https://data.go.th/dataset/bebf800f-418a-4b8e-83eb-31eb578c1811/resource/c6ff47b6-0a17-4a14-bb9d-17ac2458033f/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:32.254897','https://data.go.th/dataset/item_a7f2e41e-f81f-4eea-97b7-1b8bcd8e6871');
INSERT OR REPLACE INTO datasets VALUES ('item_5ff49cba-d467-4ec9-a56c-9aaed9a8af35','การบรรจุงาน จำแนกตามอาชีพ และอายุ ทั่วราชอาณาจักร ปี 2558','ข้อมูลการบรรจุงาน &nbsp;จำแนกตามอาชีพ &nbsp;และอายุ &nbsp; ทั่วราชอาณาจักร ปี 2558&nbsp;เป็นข้อมูลจากการให้บริการจัดหางานในประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ ประกอบด้วยข้อมูลดังนี้ - การบรรจุงาน - ประเภทอาชีพ - อายุ','กรมการจัดหางาน','["การบ�","ประเภทอาชีพ","อายุ"]','["XLSX"]',1,'[{"name":"บรรจุงานอาชีพอายุ","format":"XLSX","url":"https://data.go.th/dataset/e9ef1d39-362f-4d52-82c3-9a2387e248fb/resource/7ee73a0f-1ff1-46ca-a185-4cf842935fa4/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:31.572998','https://data.go.th/dataset/item_5ff49cba-d467-4ec9-a56c-9aaed9a8af35');
INSERT OR REPLACE INTO datasets VALUES ('item_a5d8676a-8bb5-4a2c-8a59-b7b34a00c067','การแนะแนวอาชีพนักเรียน / นักศึกษา ประชาชนทั่วไป และผู้ประกันตนกรณีว่างงาน จำแนกตามจังหวัด ทั่วราชอาณาจักร ปี 2558','ข้อมูลการแนะแนวอาชีพนักเรียน / นักศึกษา &nbsp;ประชาชนทั่วไป &nbsp;และผู้ประกันตนกรณีว่างงาน จำแนกตามจังหวัด ทั่วราชอาณาจักร ปี 2558 เป็นข้อมูลการให้บริการแนะแนวอาชีพและส่งเสริมการมีงานทำของหน่วยงานในสังกัดกรมการจัดหางาน ซึ่งให้บริการแนะแนวอาชีพให้แก่นักเรียน นักศึกษา ประชาชน และผู้ประกันตนกรณีว่างงาน ประกอบด้วยข้อมูล -นักเรียน / นักศึกษา -ประชาชนทั่วไป&nbsp; -ผู้ประกันตนกรณีว่างงาน -จังหวัด','กรมการจัดหางาน','["นักศึกษา","นักเรียน","ประชาชน","แนะแนวอาชีพ"]','["XLSX"]',1,'[{"name":"แนะแนวอาชีพ","format":"XLSX","url":"https://data.go.th/dataset/ec265689-55d4-4830-950b-55796417fb2a/resource/a294eef5-4bea-42ad-b0f0-d0d09eb5d2f3/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:31.187057','https://data.go.th/dataset/item_a5d8676a-8bb5-4a2c-8a59-b7b34a00c067');
INSERT OR REPLACE INTO datasets VALUES ('item_62dc1892-fbc3-457c-ab8a-4c99f0c37baf','หนังสือเที่ยวชุมชนไปกับคน อพท. (ภาษาอังกฤษ/ภาษาไทย)','หนังสือเที่ยวชุมชนไปกับคน อพท. เปรียบเสมือนประตูบานแรกที่จะเปิดให้ผู้อ่านได้ก้าวเข้าไปรู้จักการท่องเที่ยวที่เรียกว่า &ldquo;การท่องเที่ยวโดยชุมชน&rdquo; (๑๔ ชุมชนต้นแบบของ อพท.) ซึ่งเสน่ห์ของการท่องเที่ยวโดยชุมชนนี้ ไม่ได้อยู่ที่ความยิ่งใหญ่ของสถานที่ หรือสิ่งปลูกสร้างใดๆ แต่อยู่ที่เรื่องราวที่ร้อยเรียงกัน จากสิ่งของสู่เรื่องเล่า จากมิตรภาพสู่เครือญาติเสน่ห์บนความแตกต่างแต่ลงตัวนี้เอง ที่จะทำให้เข้าใจการท่องเที่ยวโดยชุมชนมากยิ่งขึ้น','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',2,'[{"name":"หนังสือเที่ยวชุมชนไปกับคน อพท. (ภาษาไทย)","format":"PDF","url":"https://data.go.th/dataset/d9dc4283-3ddd-4da6-9fda-4c6a0e7d9c1c/resource/0e3cd6d3-b1b7-4304-9d56-51cf660cb146/download/booklet-__thai.pdf"},{"name":"หนังสือเที่ยวชุมชนไปกับคน อพท. (ภาษาอังกฤษ)","format":"PDF","url":"https://data.go.th/dataset/d9dc4283-3ddd-4da6-9fda-4c6a0e7d9c1c/resource/1d6966ad-dd87-4fda-8e52-315d0e7180e5/download/booklet-__eng.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:25.756044','https://data.go.th/dataset/item_62dc1892-fbc3-457c-ab8a-4c99f0c37baf');
INSERT OR REPLACE INTO datasets VALUES ('item_987320b0-f57a-4b3c-8b53-6f429a16b6df','ผลการสำรวจความพึงพอใจด้านประชาชน ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย','โครงการสำรวจทัศนคติและความพึงพอใจของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย มีวัตถุประสงค์เพื่อนำข้อมูลที่ได้ไปพัฒนาและปรับปรุงด้านการท่องเที่ยวของประเทศไทย โดยดำเนินการสำรวจนักท่องเที่ยวชาวต่างประเทศที่เดินทางมาท่องเที่ยวในประเทศไทย ตามจังหวัดที่เป็นแหล่งท่องเที่ยวสำคัญๆ รวมทั้งบริเวณด่านตรวจคนเข้าเมืองต่างๆ ในช่วงเดือนมกราคม &ndash; กันยายน 2557 ซึ่งนักท่องเที่ยวชาวต่างประเทศมีความพึงพอใจต่อประชาชนในภาพรวมในระดับพอใจมาก และมีความพึงพอใจในระดับพอใจมากในทุกประเด็นที่ประเมิน ได้แก่ ความเป็นมิตร และความซื่อสัตย์ &nbsp;(คะแนนเต็ม 5)','สำนักงานปลัดกระทรวงการท่องเที่ยวและกีฬา','["ความซื่อสัตย์","ความเป็นมิตร","สำรวจความพึงพอใจ"]','["CSV"]',1,'[{"name":"ผลการสำรวจความพึงพอใจด้านประชาชน ของนักท่องเที่ยวชาวต่างประเทศที่เดินทางท่องเที่ยวในประเทศไทย","format":"CSV","url":"https://data.go.th/dataset/d2b76d64-5765-44d5-bf1f-a240f21720e3/resource/a4bdd298-7c78-4d7f-8fcb-700f2a530d43/download/people.csv"}]','Creative Commons Attributions','2021-10-31T05:40:25.141402','https://data.go.th/dataset/item_987320b0-f57a-4b3c-8b53-6f429a16b6df');
INSERT OR REPLACE INTO datasets VALUES ('item_828bf427-f728-45a2-9c7c-a9001341614a','บ้านโคก มนต์เสน่ห์แห่งวิถีชาวลาวครั่ง','บ้านโคก มนต์เสน่ห์แห่งวิถีชาวลาวครั่ง','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["ชาวลาวครั่ง","บ้านโคก"]','["XLSX","PDF"]',2,'[{"name":"metadata_องค์การบริหาร(บ้านโคก มนต์เสน่ห์แห่งวิถีชาวลาวครั่ง)","format":"XLSX","url":"https://data.go.th/dataset/6e860770-0048-4404-b22b-71d4fa198642/resource/95bf89b0-da8a-4a95-aafb-365e95b3787e/download/metadata_-.xlsx"},{"name":"บ้านโคก มนต์เสน่ห์แห่งวิถีชาวลาวครั่ง","format":"PDF","url":"https://data.go.th/dataset/6e860770-0048-4404-b22b-71d4fa198642/resource/03096a4b-785b-4018-b790-56444ec9ca81/download/x-.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:24.644273','https://data.go.th/dataset/item_828bf427-f728-45a2-9c7c-a9001341614a');
INSERT OR REPLACE INTO datasets VALUES ('item_89e69b62-e914-4a5f-a68d-5e65036e59c7','ชุดความรู้ เรื่องLow Carbon Tourism เที่ยวแบบคนไม่เอาถ่าน','ชุดความรู้เที่ยวแบบคนไม่เอาถ่านบอกเล่าถึงความสำคัญการท่องเที่ยวอย่างยั่งยืนในรูปแบบ &quot;Low Carbon Tourism&quot; เพื่อกระตุ้นให้ผู้ประกอบการและนักท่องเที่ยวตระหนักถึงการท่องเที่ยวที่ช่วยลดโลกร้อนและจุดประกายความคิดในการดำเนินธุรกิจหรือการท่องเที่ยวแบบ Low carbon','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',1,'[{"name":"ชุดความรู้ เรื่องLow Carbon Tourism เที่ยวแบบคนไม่เอาถ่าน","format":"PDF","url":"https://data.go.th/dataset/10dd2858-9576-4cec-b603-303396e3be06/resource/a5288282-e078-4263-bd7c-c77bde95f1f7/download/low-carbon-tourism.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:24.237693','https://data.go.th/dataset/item_89e69b62-e914-4a5f-a68d-5e65036e59c7');
INSERT OR REPLACE INTO datasets VALUES ('item_eabcb79b-da0d-4b44-a1c1-5b5cb83cdbf0','ชุดความรู้ เรื่องGastronomy Tourism ท่องเที่ยวเชิงอาหาร','ชุดความรู้การท่องเที่ยวเชิงอาหารบอกเล่าถึงการดำเนินงานของอพท. ในด้านการพัฒนาเส้นทางการท่องเที่ยวเชิงอาหารและเมนูเด่นในท้องถิ่น ที่สามารถสะท้อนความจริงแท้ (Authenticity) ที่เน้นคุณค่าความเป็นไทย (Thainess) วิถีชีวิต ภูมิปัญญาท้องถิ่น ศิลปวัฒนธรรม ประเพณีและประวัติศาสตร์&nbsp;','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',1,'[{"name":"ชุดความรู้ เรื่องGastronomy Tourism ท่องเที่ยวเชิงอาหาร","format":"PDF","url":"https://data.go.th/dataset/138b9e9e-408b-4d88-bb35-65b1f7af0e47/resource/15e5e0fa-5868-4489-85f3-9b9c11e29da3/download/gastronomy-tourism.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:23.794610','https://data.go.th/dataset/item_eabcb79b-da0d-4b44-a1c1-5b5cb83cdbf0');
INSERT OR REPLACE INTO datasets VALUES ('item_f295ee2f-9baa-480e-951f-d8cf87d7c4e6','ชุดความรู้ เรื่องCreative Tourism การท่องเที่ยวเชิงสร้างสรรค์','ชุดความรู้การท่องเที่ยวเชิงสร้างสรรค์นำเสนอแนวคิดเกี่ยวกับการท่องเที่ยวเชิงสร้างสรรค์ในมิติของ อพท. ซึ่งมุ่งเน้นการสร้างคุณค่า (Value Creation) บนพื้นฐานแก่นแท้แห่งความเป็นไทย วิถีชีวิต ภูมิปัญญาท้องถิ่นศิลปวัฒนธรรม ประเพณี และประวัติศาสตร์','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',1,'[{"name":"ชุดความรู้ เรื่องCreative Tourism การท่องเที่ยวเชิงสร้างสรรค์","format":"PDF","url":"https://data.go.th/dataset/285b272b-8cad-41c0-9a8a-8eefeb58944a/resource/cad0b4dd-0ee1-4661-bb76-027495b731fb/download/creative-tourism.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:23.347063','https://data.go.th/dataset/item_f295ee2f-9baa-480e-951f-d8cf87d7c4e6');
INSERT OR REPLACE INTO datasets VALUES ('item_c99ebccf-b06f-45f1-93a9-c43d77ab0369','ชุดความรู้ เรื่องCommunity Based Tourism ท่องเที่ยวโดยชุมชน','ชุดความรู้การท่องเที่ยวโดยชุมชน นำเสนอรูปแบบการท่องเที่ยวที่จะช่วยให้เกิดการกระจายผลประโยชน์ทางเศรษฐกิจและสังคมไปสู่สมาชิกในชุมชน และแนวคิดที่ อพท. ใช้ในการส่งเสริมการพัฒนาชุมชน โดยใช้การท่องเที่ยวเป็นเครื่องมือหลัก เพื่อสร้างให้เกิดความยั่งยืนและความอยู่ดีมีสุขของชุมชน &nbsp;พร้อมทั้งได้มีการนำเสนอข้อมูลรูปแบบการจัดการการท่องเที่ยวโดยชุมชนของชุมชนต้นแบบทั้ง ๑๓ แห่ง ที่อยู่ในพื้นที่พิเศษ อพท. เข้าไปดำเนินการส่งเสริมการพัฒนาตามแนวทางของ อพท. และกรณีศึกษาการจัดการการท่องเที่ยวที่น่าสนใจจากต่างประเทศ','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ชุดความรู้","ท่องเที่ยวโดยชุมชน"]','["XLSX","PDF"]',3,'[{"name":"metadata_องค์การบริหารการพัฒนาพื้นที่(ชุดความรู้ เรื่องCommunity Based Tourism)","format":"XLSX","url":"https://data.go.th/dataset/10af6d3d-ebc1-4f6b-a948-7ad6edd5b7bc/resource/5d5e6055-2129-4541-8259-52fb9e356254/download/metadata_-community-based-tourism.xlsx"},{"name":"ชุดความรู้ เรื่อง Community Based Tourism ท่องเที่ยวโดยชุมชน(TH)","format":"PDF","url":"https://data.go.th/dataset/10af6d3d-ebc1-4f6b-a948-7ad6edd5b7bc/resource/545b011b-5ea7-48bb-bab6-6d79620ac6d5/download/-community-based-tourism-th.pdf"},{"name":"ชุดความรู้ เรื่อง Community Based Tourism ท่องเที่ยวโดยชุมชน(ENG)","format":"PDF","url":"https://data.go.th/dataset/10af6d3d-ebc1-4f6b-a948-7ad6edd5b7bc/resource/0ae9911f-78a7-422f-97c9-7e39c93e8e16/download/-community-based-tourism-eng.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:22.956504','https://data.go.th/dataset/item_c99ebccf-b06f-45f1-93a9-c43d77ab0369');
INSERT OR REPLACE INTO datasets VALUES ('item_d1279514-655d-4b15-b914-f166466c2f18','งานวิจัยผลการประเมินการทวีคูณของรายได้จากการท่องเที่ยวในพื้นที่พิเศษ (Multiplier Effects)','ผลการประเมินผลกระทบด้านเศรษฐกิจจากการท่องเที่ยวในพื้นที่พิเศษทั้งรายได้ทางตรง และรายได้แบบทวีคูณของรายได้จากการท่องเที่ยว (Multiplier Effects of Tourism) ทั้งแสดงถึงรูปแบบของรายได้ การกระจายรายได้ การลงทุนและผู้รับผลประโยชน์ทั้งในและนอกพื้นที่พิเศษของ อพท.','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',1,'[{"name":"งานวิจัยผลการประเมินการทวีคูณของรายได้จากการท่องเที่ยวในพื้นที่พิเศษ (Multiplier Effects)","format":"PDF","url":"https://data.go.th/dataset/ac3db6c0-2f8c-444d-b639-1008569ff62e/resource/3699e612-115e-4014-a941-afa80454bfbc/download/multiplier-effects.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:22.639081','https://data.go.th/dataset/item_d1279514-655d-4b15-b914-f166466c2f18');
INSERT OR REPLACE INTO datasets VALUES ('item_a60717e6-5f28-44e5-aba5-e2904f8a924d','งานวิจัยการดำเนินงานวิจัยเพื่อพัฒนาองค์ความรู้ทางวิชาการด้านการท่องเที่ยวอย่างยั่งยืน','งานวิจัยเรื่อง &quot;การดำเนินงานวิจัยเพื่อพัฒนาองค์ความรู้ทางวิชาการด้านการท่องเที่ยวอย่างยั่งยืน&quot; เป็นการการรวบรวมองค์ความรู้ด้านการพัฒนาการท่องเที่ยวอย่างยั่งยืนในมิติด้านสังคม เศรษฐกิจ และสิ่งแวดล้อมของ อพท. ที่ดำเนินงานภายใต้เกณฑ์การท่องเที่ยวอย่างยั่งยืนโลก (GSTC Criteria) และนำประสิทธิผลของการปฏิบัติงานมาทำการสังเคราะห์ เพื่อให้เกิดเป็นองค์ความรู้ใหม่ ที่จะสามารถพัฒนาไปเผยแพร่และใช้ประโยชน์ ในการถ่ายทอดความรู้แก่บุคลากรด้านการท่องเที่ยว ให้ได้ร่วมเรียนรู้และสามารถนำองค์ความรู้ที่มีไปพัฒนาการดำเนินงานต่อยอดการดำเนินงานที่ผ่านมาให้เกิดประสิทธิภาพยิ่งขึ้น','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["งานวิจัย","ทัวร์","ท่องเที่ยว"]','["PDF"]',1,'[{"name":"การดำเนินงานวิจัยเพื่อพัฒนาองค์ความรู้ทางวิชาการด้านการท่องเที่ยวอย่างยั่งยืน","format":"PDF","url":"https://data.go.th/dataset/06d5ee56-d551-4761-a61c-61739ebca55e/resource/06100f2d-73ed-4a24-9099-59f776b1aa6e/download/xx.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:22.320520','https://data.go.th/dataset/item_a60717e6-5f28-44e5-aba5-e2904f8a924d');
INSERT OR REPLACE INTO datasets VALUES ('item_360fa310-cf5a-45df-9eb2-9cf9f9373927','โครงการจัดทำกรณีศึกษา(case study)เกี่ยวกับผู้ผลิตสินค้าและบริการด้านการท่องเที่ยวที่มีความโดดเด่นในการใช้ปัจจัยการผลิตหรือการจ้างแรงงานในท้องถิ่น','โครงการจัดทำกรณีศึกษา(case study)เกี่ยวกับผู้ผลิตสินค้าและบริการด้านการท่องเที่ยวที่มีความโดดเด่นในการใช้ปัจจัยการผลิตหรือการจ้างแรงงานในท้องถิ่น','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["กรณีศึกษา","การท่องเที่ยว","ผู้ผลิตสินค้า"]','["PDF","XLSX"]',4,'[{"name":"ริสาสินีสปา แอนด์ รีสอร์ทจากสปาสู่กาแฟ","format":"PDF","url":"https://data.go.th/dataset/fcd0ed20-99d2-417b-97cf-ebca01971120/resource/7599dce2-9421-4804-89c2-cb5ad9445365/download/x-.pdf"},{"name":"metadata_องค์การบริหาร(โครงการจัดทำกรณีศึกษา(case study))","format":"XLSX","url":"https://data.go.th/dataset/fcd0ed20-99d2-417b-97cf-ebca01971120/resource/7c718f52-2016-4dda-b92e-053a5f42d11e/download/metadata_case-study.xlsx"},{"name":"ภูนาคำรีสอร์ท จากเนินภูสู่รีสอร์ทสีเขียว","format":"PDF","url":"https://data.go.th/dataset/fcd0ed20-99d2-417b-97cf-ebca01971120/resource/609de763-f5ed-4678-8b25-1588b2760da0/download/x-.pdf"},{"name":"บ้านปูรีสอร์ท จากบ่อปูสู่ธุรกิจ MICE","format":"PDF","url":"https://data.go.th/dataset/fcd0ed20-99d2-417b-97cf-ebca01971120/resource/0aaa1a5d-5d19-4ded-ab5a-b2d4939ee03f/download/-mice.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:21.754833','https://data.go.th/dataset/item_360fa310-cf5a-45df-9eb2-9cf9f9373927');
INSERT OR REPLACE INTO datasets VALUES ('item_e9b07471-3c9a-4104-ac80-004a78d303c4','คู่มือเลือกซื้อของที่ระลึกอาหารแปรรูป','คู่มือเลือกซื้อของที่ระลึกอาหารแปรรูป','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["คู่มือ","ซื้อของ","ที่ระลึก","อาหารแปรรูป"]','["XLSX","PDF"]',2,'[{"name":"metadata_องค์การบริหาร(คู่มือเลือกซื้อของที่ระลึกอาหารแปรรูป)","format":"XLSX","url":"https://data.go.th/dataset/968664ee-ebba-40a2-8f4f-307261c01da2/resource/dd0a4611-d8c9-41b2-8b8a-6e47fe901898/download/metadata_.xlsx"},{"name":"คู่มือเลือกซื้อของที่ระลึกอาหารแปรรูป","format":"PDF","url":"https://data.go.th/dataset/968664ee-ebba-40a2-8f4f-307261c01da2/resource/6200ecd6-fe6c-468c-9198-05ad558660a6/download/xx.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:21.219770','https://data.go.th/dataset/item_e9b07471-3c9a-4104-ac80-004a78d303c4');
INSERT OR REPLACE INTO datasets VALUES ('item_f9500c0d-2b08-4c58-9312-4594a3e82887','คู่มือการท่องเที่ยวเขตพัฒนาการท่องเที่ยวมรดกโลกด้านวัฒนธรรม','คู่มือการท่องเที่ยวเขตพัฒนาการท่องเที่ยวมรดกโลกด้านวัฒนธรรม','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","คู่มือ","มรดกโลก","วัฒนธรรม"]','["PDF","XLSX"]',2,'[{"name":"คู่มือการท่องเที่ยวเขตพัฒนาการท่องเที่ยวมรดกโลกด้านวัฒนธรรม","format":"PDF","url":"https://data.go.th/dataset/1fd253d6-9a12-426c-a4f6-3bc08714b014/resource/02a18c03-bbaa-42ff-b882-6fdfdee36e02/download/xx.pdf"},{"name":"metadata_องค์การบริหาร(คู่มือการท่องเที่ยวเขตพัฒนาการท่องเที่ยวมรดกโลกด้านวัฒนธรรม)","format":"XLSX","url":"https://data.go.th/dataset/1fd253d6-9a12-426c-a4f6-3bc08714b014/resource/3d94c0ed-965d-4d30-a5b6-45a683ede469/download/metadata_.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:20.798602','https://data.go.th/dataset/item_f9500c0d-2b08-4c58-9312-4594a3e82887');
INSERT OR REPLACE INTO datasets VALUES ('item_db41976b-78b5-4c3d-b13d-223414de8c2b','เกณฑ์การพัฒนาการท่องเที่ยวโดยชุมชน','เกณฑ์มาตรฐานการบริหารจัดการแหล่งท่องเที่ยวโดยชุมชน เป็นเครื่องมือสำคัญในการพัฒนาการท่องเที่ยวโดยชุมชนของ อพท. อีกทั้งเป็นเครื่องมือวัดระดับการพัฒนาการท่องเที่ยวโดยชุมชนอย่างยั่งยืนและยังนำไปใช้เป็นเกณฑ์พิจารณารางวัลการพัฒนา DASTA CBT AWARDS','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',1,'[{"name":"เกณฑ์การพัฒนาการท่องเที่ยวโดยชุมชน","format":"PDF","url":"https://data.go.th/dataset/bcbd804e-aea8-4d8c-aa72-f87d431d22c6/resource/d4103ef8-e7b6-4540-9c31-d921a8099b8f/download/x-.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:20.487367','https://data.go.th/dataset/item_db41976b-78b5-4c3d-b13d-223414de8c2b');
INSERT OR REPLACE INTO datasets VALUES ('item_54b2d1a8-fc35-4255-b08f-9356f454d7a8','การศึกษาออกแบบพัฒนาเส้นทางเรือยอร์ชให้มีมาตรฐานระดับสากล โครงการพัฒนาและส่งเสริมเส้นทางการท่องเที่ยวเดินเรือใบและเรือยอร์ช','การศึกษาออกแบบพัฒนาเส้นทางเรือยอร์ชให้มีมาตรฐานระดับสากล โครงการพัฒนาและส่งเสริมเส้นทางการท่องเที่ยวเดินเรือใบและเรือยอร์ช','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การศึกษา","องค์การบริห�"]','["XLSX","PDF"]',2,'[{"name":"metadata_องค์การบริหารการพัฒนาพื้นที่(การศึกษาออกแบบพัฒนาเส้นทางเรือยอร์ชให้มีมาตร)","format":"XLSX","url":"https://data.go.th/dataset/360f2952-7e8f-44f4-82bd-92e26eb5f6ab/resource/e936be96-06c3-4eb4-9c9d-d62e98fb898f/download/metadata_.xlsx"},{"name":"โครงการพัฒนาและส่งเสริมเส้นทางการท่องเที่ยวเดินเรือใบและเรือยอร์ช","format":"PDF","url":"https://data.go.th/dataset/360f2952-7e8f-44f4-82bd-92e26eb5f6ab/resource/050023d4-6bd5-4d89-99dd-bf9e7d78a99d/download/xx.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:20.082922','https://data.go.th/dataset/item_54b2d1a8-fc35-4255-b08f-9356f454d7a8');
INSERT OR REPLACE INTO datasets VALUES ('item_e7bb224f-ff64-4a54-9035-b27f7cd4f898','การท่องเที่ยวเชิงวัฒนธรรม ชุมชนบ้านน้ำเชี่ยว','การท่องเที่ยวเชิงวัฒนธรรม ชุมชนบ้านน้ำเชี่ยว&nbsp;','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ชุมชนบ้านน้ำเชี่ยว","เชิงวัฒนธรรม"]','["PDF","XLSX"]',2,'[{"name":"การท่องเที่ยวเชิงวัฒนธรรม ชุมชนบ้านน้ำเชี่ยว","format":"PDF","url":"https://data.go.th/dataset/a40e7c24-d0ed-4964-b50b-97bd0adc2130/resource/17bac8a3-d3b8-48eb-96a4-873b9cd2259b/download/x-.pdf"},{"name":"metadata_องค์การบริหาร(การท่องเที่ยวเชิงวัฒนธรรม ชุมชนบ้านน้ำเชี่ยว)","format":"XLSX","url":"https://data.go.th/dataset/a40e7c24-d0ed-4964-b50b-97bd0adc2130/resource/91add966-1990-4a28-917e-ae7f5a25ea6c/download/metadata_.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:19.734873','https://data.go.th/dataset/item_e7bb224f-ff64-4a54-9035-b27f7cd4f898');
INSERT OR REPLACE INTO datasets VALUES ('item_e4b72ec0-3870-4360-8465-ca4c2ee454b7','การท่องเที่ยวเชิงนิเวศ ชุมชนกกสะทอน','การท่องเที่ยวเชิงนิเวศ ชุมชนกกสะทอน','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ชุมชนกกสะทอน","เชิงนิเวศ"]','["PDF","XLSX"]',2,'[{"name":"การท่องเที่ยวเชิงนิเวศ ชุมชนกกสะทอน","format":"PDF","url":"https://data.go.th/dataset/10aacd68-5209-4f21-967c-04c2a1d649b9/resource/f765d3ec-b899-4736-b39d-514fb2f6c24d/download/x-.pdf"},{"name":"metadata_องค์การบริหาร(การท่องเที่ยวเชิงนิเวศ ชุมชนกกสะทอน)","format":"XLSX","url":"https://data.go.th/dataset/10aacd68-5209-4f21-967c-04c2a1d649b9/resource/92baa417-a050-4276-aacc-b630f6c2cabf/download/metadata_-.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:19.375756','https://data.go.th/dataset/item_e4b72ec0-3870-4360-8465-ca4c2ee454b7');
INSERT OR REPLACE INTO datasets VALUES ('item_5e66fadb-4a50-4070-9ffb-b9cfad5270b9','DASTA''S RESEARCH COLLECTION ON SUSTAINABLE TOURISM','เป็นหนังสือที่รวบรวมผลงานวิชาการและงานวิจัยด้านการท่องเที่ยวอย่างยั่งยืนของอพท. ที่เกิดขึ้นในแต่ละปี โดยเป็นการสะท้อนให้เห็นว่าในประเด็นเรื่องการท่องเที่ยวอย่างยั่งยืนนั้น ต้องมีการอาศัยศาสตร์ที่หลากหลายในการศึกษาและดำเนินการ ทั้งในเชิงวิทยาศาสตร์ เช่น การวัดค่าการปล่อยคาร์บอน และเชิงสังคมศาสตร์ เช่น การท่องเที่ยวเชิงสร้างสรรค์และการจัดการแหล่งท่องเที่ยว','องค์การบริหารการพัฒนาพื้นที่พิเศษเพื่อการท่องเที่ยวอย่างยั่งยืน (องค์การมหาชน)','["การท่องเที่ยว","ทัวร์"]','["PDF"]',1,'[{"name":"DASTA''S RESEARCH COLLECTION ON SUSTAINABLE TOURISM","format":"PDF","url":"https://data.go.th/dataset/68292173-6155-4b9a-8f6d-18ef3b539e17/resource/a0d3f332-8de5-40f5-9aee-0b0fbd58cc3b/download/d_on-sustainable_research2015.pdf"}]','Creative Commons Attributions','2021-10-31T05:40:18.785776','https://data.go.th/dataset/item_5e66fadb-4a50-4070-9ffb-b9cfad5270b9');
INSERT OR REPLACE INTO datasets VALUES ('item_d138dc68-45d2-4893-ae10-00f1295610d4','จำนวนคนต่างด้าวมาตรา 13 (ประเภทชนกลุ่มน้อย) ที่ยื่นคำขอและได้รับอนุญาตให้ทำงาน จำแนกตามจังหวัด ทั่วราชอาณาจักร ปี 2558','จำนวนคนต่างด้าวมาตรา 13 (ประเภทชนกลุ่มน้อย) ที่ยื่นคำขอและได้รับอนุญาตให้ทำงาน จำแนกตามจังหวัด ทั่วราชอาณาจักร &nbsp;ปี &nbsp;2558 เป็นข้อมูลจาการดำเนินงานพิจารณาออกใบอนุญาตทำงานให้คนต่างด้าว ของหน่วยงานในสังกัดกรมการจัดหางาน ทั่วประเทศ ประกอบด้วย -การยื่นคำขอใบอนุญาตทำงาน -การได้รับใบอนุญาตทำงาน -จังหวัด -คนต่างด้าวประเภทชนกลุ่มน้อย','กรมการจัดหางาน','["ชนกลุ่มน้อย","มาตรา","ได้รับใบอนุญาตทำงาน"]','["XLSX"]',1,'[{"name":"ม.13ได้รับอนุญาตทำงาน","format":"XLSX","url":"https://data.go.th/dataset/77038a7a-9708-4589-a16f-4e84381b7073/resource/95b503d2-e3c9-43da-9bc1-810d92e04df0/download/.13.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:18.056342','https://data.go.th/dataset/item_d138dc68-45d2-4893-ae10-00f1295610d4');
INSERT OR REPLACE INTO datasets VALUES ('item_e8d6e29e-52ed-45a1-8418-fe67a866ab06','จำนวนคนต่างด้าวมาตรา 13 (ประเภทชนกลุ่มน้อย) ที่ได้รับอนุญาตทำงานคงเหลืออยู่ในประเทศไทย จำแนกตามจังหวัด ทั่วราชอาณาจักร ณ ธันวาคม 2558','ข้อมูลจำนวนคนต่างด้าวมาตรา 13 (ประเภทชนกลุ่มน้อย) ที่ได้รับอนุญาตทำงานคงเหลืออยู่ในประเทศไทย &nbsp;จำแนกตามจังหวัด ทั่วราชอาณาจักร &nbsp;ณ ธันวาคม 2558 เป็นข้อมูลจาการดำเนินงานการทำงานของคนต่างด้าว ของหน่วยงานในสังกัดกรมการจัดหางาน ทั่วประเทศ ประกอบด้วย -ประเภทการอนุญาต -ชนกลุ่มน้อย -จังหวัด','กรมการจัดหางาน','["คงเหลือ","ชนกลุ่มน้อย","ประเภทการอนุญาต"]','["XLSX"]',1,'[{"name":"ม.13 คงเหลือ","format":"XLSX","url":"https://data.go.th/dataset/add33a09-942f-4cc6-9202-925d64ea99d7/resource/80138aa0-5d59-4308-910f-b4e22495b6d3/download/.13-.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:17.599283','https://data.go.th/dataset/item_e8d6e29e-52ed-45a1-8418-fe67a866ab06');
INSERT OR REPLACE INTO datasets VALUES ('item_5df63e23-48f1-4df6-b85b-e2fd98f33c7d','จำนวนคนต่างด้าวคงเหลือทำงานอยู่ในประเทศไทย(ประเภทส่งเสริมการลงทุน ) จำแนกตามสัญชาติและอาชีพ ณ ธันวาคม 2558','ข้อมูลจำนวนคนต่างด้าวคงเหลือทำงานอยู่ในประเทศไทย(ประเภทส่งเสริมการลงทุน ) &nbsp;จำแนกตามสัญชาติและอาชีพ ณ ธันวาคม 2558 เป็นข้อมูลจาการดำเนินงานการทำงานของคนต่างด้าว ของหน่วยงานในสังกัดกรมการจัดหางาน ทั่วประเทศ ประกอบด้วย -ประเภทส่งเสริมการลงทุน -สัญชาติ -ประเภทอาชีพ &nbsp;','กรมการจัดหางาน','["คงเหลือ","ประเภ�","สัญชาติ"]','["XLSX"]',1,'[{"name":"คนต่างด้าวคงเหลือ(ส่งเสริมการลงทุน)","format":"XLSX","url":"https://data.go.th/dataset/1fb4b6f6-d6b4-402f-b16a-0e4eba1f60a5/resource/a8c52b4e-4378-4e0a-8d8f-422d73db0fc5/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:17.262245','https://data.go.th/dataset/item_5df63e23-48f1-4df6-b85b-e2fd98f33c7d');
INSERT OR REPLACE INTO datasets VALUES ('item_53b06ae1-4987-481b-bc4e-62d78209f75a','จำนวนคนต่างด้าวคงเหลือทำงานอยู่ในประเทศไทย (ประเภททั่วไป) จำแนกตามสัญชาติและอาชีพ ณ ธันวาคม 2558','ข้อมูลจำนวนคนต่างด้าวคงเหลือทำงานอยู่ในประเทศไทย (ประเภททั่วไป) &nbsp;จำแนกตามสัญชาติและอาชีพ ณ ธันวาคม 2558 เป็นข้อมูลจาการดำเนินงานการทำงานของคนต่างด้าว ของหน่วยงานในสังกัดกรมการจัดหางาน ทั่วประเทศ ประกอบด้วย -ประเภททั่วไป -สัญชาติ -ประเภทอาชีพ &nbsp;','กรมการจัดหางาน','["คงเหลือ","สัญชาติ"]','["XLSX"]',1,'[{"name":"คนต่างด้าวคงเหลือ(ทั่วไป)","format":"XLSX","url":"https://data.go.th/dataset/2bd45551-cbdb-4748-b1e5-ff22e4cb6710/resource/224d7e32-da62-4233-95cd-ad16b54ec3a0/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:16.775366','https://data.go.th/dataset/item_53b06ae1-4987-481b-bc4e-62d78209f75a');
INSERT OR REPLACE INTO datasets VALUES ('item_f7553aa9-c72d-410c-b780-b896f72b9118','จำนวนคนงานไทยที่ลงทะเบียนแจ้งความประสงค์เดินทางไปทำงานต่างประเทศ จำแนกตามจังหวัด ทั่วราชอาณาจักร ปี 2558','ข้อมูลจำนวนคนงานไทยที่ลงทะเบียนแจ้งความประสงค์เดินทางไปทำงานต่างประเทศ จำแนกตามจังหวัด ทั่วราชอาณาจักร &nbsp;ปี 2558 เป็นข้อมูลการให้บริการการทำงานในต่างประเทศของหน่วยงานในสังกัดกรมการจัดหางาน คือคนหางานมาลงทะเบียนแจ้งความประสงค์จะไปทำงานต่างประเทศ ประกอบด้วย -จังหวัด -เพศ','กรมการจัดหางาน','["ต่างประเทศ","แจ้งความประสงค์"]','["XLSX"]',1,'[{"name":"แจ้งความประสงค์ไปทำงานต่างประเทศ","format":"XLSX","url":"https://data.go.th/dataset/ac5b9e54-c8db-4a1a-82c7-243ef10e0d39/resource/c5448275-f6f7-4545-afc9-b6e31ed852c1/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:16.274128','https://data.go.th/dataset/item_f7553aa9-c72d-410c-b780-b896f72b9118');
INSERT OR REPLACE INTO datasets VALUES ('item_20510977-0279-49a8-8f56-ee719ddb7019','จำนวนคนงานไทยที่ลงทะเบียนแจ้งความประสงค์เดินทางไปทำงานต่างประเทศ จำแนกตามวุฒิการศึกษา ทั่วราชอาณาจักร ปี 2558','ข้อมูลจำนวนคนงานไทยที่ลงทะเบียนแจ้งความประสงค์เดินทางไปทำงานต่างประเทศ &nbsp;จำแนกตามวุฒิการศึกษา &nbsp;ทั่วราชอาณาจักร ปี 2558 เป็นข้อมูลจากการให้บริการการทำงานต่างประเทศ ของหน่วยงานในสังกัดกรมการจัดหางาน เป็นข้อมูลของคนหางานที่มาขึ้นทะเบียนแจ้งความประสงค์ไปทำงานต่างประเทศ โดยจำแนกตามวุฒิการศึกษา ประกอบด้วยข้อมูล -วุฒิการศึกษา -เพศ &nbsp;','กรมการจัดหางาน','["ต่างประเทศ","วุฒิการศึกษา","แจ้งความประสงค์"]','["XLSX"]',1,'[{"name":"แจ้งความประสงค์ไปทำงานต่างประเทศ แยกวุฒิ","format":"XLSX","url":"https://data.go.th/dataset/a3fc672b-6e2e-4834-8d20-62ac6c2873dd/resource/49d65673-8708-43b2-8b83-00c1eab55875/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:15.939608','https://data.go.th/dataset/item_20510977-0279-49a8-8f56-ee719ddb7019');
INSERT OR REPLACE INTO datasets VALUES ('item_b3b33bd2-3ee3-4563-bc31-2fb692c0f81a','จำนวนคนงานไทยที่เดินทางไปทำงานต่างประเทศ จำแนกตามประเทศ เพศ และวิธีการเดินทางไปทำงาน ทั่วราชอาณาจักร ปี 2558','ข้อมูลคนงานไทยที่เดินทางไปทำงานต่างประเทศ จำแนกตามประเทศ เพศ และวิธีการเดินทางไปทำงาน &nbsp;ทั่วราชอาณาจักร &nbsp;ปี &nbsp;2558 เป็นข้อมูลจากการให้บริการการไปทำงานต่างประเทศของหน่วยงานในสังกัดกรมการจัดหางานทั่วประเทศ ประกอบด้วยข้อมูลดังนี้ -แจ้งการเดินทางด้วยตนเอง -Re-entry กรมการจัดหางานจัดส่ง -นายจ้างพาลูกจ้างไปทำงาน -นายจ้างส่งลูกจ้างไปฝึกงาน -บริษัทจัดหางานจัดส่ง','กรมการจัดหางาน','["Re-entry","ต่างประเทศ"]','["XLSX"]',1,'[{"name":"ต่างประเทศ","format":"XLSX","url":"https://data.go.th/dataset/438cfe54-14a8-4606-b8c9-39b63a41e0cf/resource/a42c9cc9-5be7-4b17-aa9e-0f7e5bd99a96/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:40:15.447282','https://data.go.th/dataset/item_b3b33bd2-3ee3-4563-bc31-2fb692c0f81a');
