INSERT OR REPLACE INTO datasets VALUES ('item_dbc23d6f-30eb-4bd2-98f4-4c6df508b79b','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2549','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX"]',1,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2549","format":"XLSX","url":"https://data.go.th/dataset/1e7aec7e-242a-4480-afe3-930b7f746b3e/resource/0b0362eb-b9de-4a1c-bd11-172b5982fde3/download/-2549.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:46.102126','https://data.go.th/dataset/item_dbc23d6f-30eb-4bd2-98f4-4c6df508b79b');
INSERT OR REPLACE INTO datasets VALUES ('item_f9deba33-dc43-4fd5-a55c-39e9b3e700d2','รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2543','&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; สำนักงานกองทุนสนับสนุนการวิจัย (สกว.) ได้รับการจัดตั้งขึ้นเป็นกลไกสนับสนุนและ ส่งเสริมการวิจัย เพื่อประโยชน์ในการพัฒนาเศรษฐกิจ สังคมและวิชาการของประเทศ โดยให้ทุนสนับสนุนการวิจัย ทั้งที่เป็นการวิจัยพื้นฐาน การวิจัยประยุกต์ และการวิจัยและพัฒนา นอกจากนี้ สกว. ยังพัฒนาความเข้มแข็งของนักวิจัยและสถาบันวิจัย โดยให้ทุนหลายประเภท รวมทั้งทุนส่งเสริมกลุ่มวิจัย ทุนพัฒนานักวิจัย และทุนส่งเสริมกิจกรรมเครือข่ายการวิจัย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;ทุนส่งเสริมกลุ่มวิจัย ตั้งขึ้นมาเพื่อสนับสนุนนักวิจัยอาวุโส ให้สร้างนักวิจัยใหม่ที่มีความสามารถทางวิชาการสูงและเพื่อ…','สำนักงานคณะกรรมการส่งเสริมวิทยาศาสตร์ วิจัยและนวัตกรรม','["นักวิจัยชาวไทย","นักวิทยาศาสตร์ชาวไทย"]','["XLSX"]',1,'[{"name":"รายนามเมธีวิจัยอาวุโส สกว. ประจำปี 2543","format":"XLSX","url":"https://data.go.th/dataset/310ba8d7-a20a-4373-a4f8-24872a339014/resource/664ec2c3-ce6f-428d-aef2-aab3340b01c6/download/-2543.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:45.785529','https://data.go.th/dataset/item_f9deba33-dc43-4fd5-a55c-39e9b3e700d2');
INSERT OR REPLACE INTO datasets VALUES ('item_a7344286-bc73-4fb7-a0f8-267d8b7ec6ee','รายงานประจำปี 2560 กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','หนังสือสรุปผลการดำเนินงานในรอบปีงบประมาณที่ผ่านมาของ พพ.มี 2 เวอร์ชั่นคือ ภาษาไทยและอังกฤษ&nbsp;','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["สรุปผลการดำเนินงาน"]','["XLSX"]',1,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(รายงานประจำปี 2560 กรมพัฒนาพลังงาน)","format":"XLSX","url":"https://data.go.th/dataset/5ee2118f-08d1-4228-b0ef-828e53da522c/resource/a7274267-fb5d-49ef-b29d-932cac379e31/download/metadata_-2560-.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:44.658487','https://data.go.th/dataset/item_a7344286-bc73-4fb7-a0f8-267d8b7ec6ee');
INSERT OR REPLACE INTO datasets VALUES ('item_7c16123f-45fe-4dec-aa0d-640c02d818a2','รายงานดุลยภาพพลังงานของประเทศไทย ปี 2559 (Energy Balance of Thailand 2016)','ดุลยภาพพลังงานของประเทศไทยปี 2559 (เบื้องต้น) สามารถนำมาใช้เป็นเครื่องมือ&nbsp; ชี้วัดสถานการณ์พลังงานของประเทศไทย ประกอบด้วยสถิติข้อมูลการผลิต การนำเข้า การส่งออก การแปรรูป และการใช้พลังงาน ตามรอบระยะเวลาปีปฏิทิน 2559','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ดุลยภาพพลังงาน"]','["XLSX"]',1,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(รายงานดุลยภาพพลังงานของประเทศไทย )","format":"XLSX","url":"https://data.go.th/dataset/4541a61e-aecb-423b-a658-ab04978a7bcc/resource/7c43d779-6cc3-429e-a787-ff2902c4b081/download/metadata_-.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:44.101971','https://data.go.th/dataset/item_7c16123f-45fe-4dec-aa0d-640c02d818a2');
