INSERT OR REPLACE INTO datasets VALUES ('item_dd49a513-1fc3-4f47-9f95-e18d242e87ac','โครงการศึกษาศักยภาพพื้นที่ที่เหมาะสมในการพัฒนาระบบผลิตไฟฟ้าพลังงานอาทิตย์ของประเทศไทย','ศักยภาพแสงอาทิตย์ในการผลิตไฟฟ้าจากเซลล์แสงอาทิตย์บนหลังคาโรงงานอุตสาหกรรมทั่วประเทศไทย (ปี 2560)','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ศักยภาพแสงอาทิตย์"]','["XLSX"]',1,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(โครงการศึกษาศักยภาพพื้นที่ที่เหมาะสม)","format":"XLSX","url":"https://data.go.th/dataset/cb800302-cc02-430a-a068-856b6653730d/resource/b728ff75-c5cf-48ca-b895-2e36ce6e11f8/download/metadata_.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:41.733818','https://data.go.th/dataset/item_dd49a513-1fc3-4f47-9f95-e18d242e87ac');
INSERT OR REPLACE INTO datasets VALUES ('item_087dadb0-4ad2-4acf-890f-fbc6c2d2e730','โครงการปรับปรุงแผนที่ศักยภาพพลังงานแสงอาทิตย์จากภาพถ่ายดาวเทียมสำหรับประเทศไทย','ศักยภาพพลังงานแสงอาทิตย์จากภาพถ่ายดาวเทียมสำหรับประเทศไทย (ปี 2552)','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ภาพถ่ายดาวเทียม"]','["XLSX"]',1,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(โครงการปรับปรุงแผนที่ศักยภาพ)","format":"XLSX","url":"https://data.go.th/dataset/ca5eb3a2-7e11-4f82-9030-ec038741caf6/resource/28653430-a25c-4658-a3c2-b2fb44e5a1a9/download/metadata_.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:41.284338','https://data.go.th/dataset/item_087dadb0-4ad2-4acf-890f-fbc6c2d2e730');
