INSERT OR REPLACE INTO datasets VALUES ('item_c9ed1d2f-cc49-4a32-b12a-dd5be708770f','ข้อมูลผลิตภัณฑ์ที่ได้รับฉลากประหยัดพลังงานประสิทธิภาพสูง','เป็นข้อมูล ประเภทผลิตภัณฑ์ รุ่นของผลิตภัณฑ์ และค่าประสิทธิภาพของผลิตภัณฑ์ที่ได้รับฉลากประสิทธิภาพสูง','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ฉลากประสิทธิภาพสูง","ประเภทผลิตภัณฑ์","รุ่น","และค่าประสิทธิภาพ"]','["XLSX"]',2,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(ข้อมูลผลิตภัณฑ์ที่ได้รับฉลากประหยัด)","format":"XLSX","url":"https://data.go.th/dataset/aa54acb4-a7d9-4892-812b-867238f2c421/resource/3f334d36-f923-40ad-8f5f-96a854bdeea4/download/metadata_.xlsx"},{"name":"ข้อมูลผลิตภัณฑ์ที่ได้รับฉลากประหยัดพลังงานประสิทธิภาพสูง","format":"XLSX","url":"https://data.go.th/dataset/aa54acb4-a7d9-4892-812b-867238f2c421/resource/c944c0ba-49e4-4e22-96b6-128694f4f43f/download/4_-60.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:40.069006','https://data.go.th/dataset/item_c9ed1d2f-cc49-4a32-b12a-dd5be708770f');
INSERT OR REPLACE INTO datasets VALUES ('item_7d9538a8-96c6-4732-a8a5-cd8dec4332b2','ข้อมูลประทานบัตร[update 10-06-2559]','เป็นข้อมูลใบอนุญาตที่ออกให้ เพื่อทำเหมืองแร่ภายในเขตที่กำหนด โดยประทานบัตรแต่ละแปลง จะมีเนื้อที่ไม่เกิน 300 ไร่ เว้นแต่ประทานบัตรในทะเลจะมีเนื้อที่ได้ไม่เกิน 50,000 ไร่ และมีอายุ ไม่เกิน 25 ปี ประกอบด้วยข้อมูลดังนี้ - เลขที่ประทานบัตร - ชื่อผู้ถือประทานบัตร - วันอนุญาต - วันสิ้นอายุ - ภาค, จังหวัด, อำเภอ, ตำบล - เนื่้อที่ (ไร่ - งาน - วา) - ชนิดแร่ - รหัส TSIC (*&nbsp;รหัสธุรกิจ TSIC&nbsp;2552 ที่สัมพันธ์กับกิจกรรม หมวด B: การทำเหมืองแร่และเหมืองหิน (Mining and Quarrying) - หมายเลขท่อ (** หมายเลข หลักหมายเขตเหมืองแร่ มุมที่ 1) - พิกัด X, พิกัด Y (*** ตามระวางแผนที่ภูมิประเทศลำดับชุด L7017','กรมอุตสาหกรรมพื้นฐานและการเหมืองแร่','["ข้อมูลประทานบัตร","ชนิดแร่","ประทานบัตร","ประทานบัตรเหมืองแร่","เหมืองหิน","เหมืองแร่","แร่","ใบอนุญาต"]','["CSV","XSL","PDF"]',4,'[{"name":"ข้อมูลประทานบัตร","format":"CSV","url":"https://data.go.th/dataset/afe697c9-cf1a-47aa-9f5a-6b928a92af2d/resource/04ab6775-0067-4782-b58f-09c45fff5f60/download/25590610mining_permit.csv"},{"name":"ข้อมูลประทานบัตร","format":"XSL","url":"https://data.go.th/dataset/afe697c9-cf1a-47aa-9f5a-6b928a92af2d/resource/49fad929-154b-4d96-860c-c1212cc23c38/download/25590610mining_permit.xls"},{"name":"คำอธิบายรหัส TSIC การทำเหมืองแร่และเหมืองหิน (Mining and Quarrying)","format":"PDF","url":"https://data.go.th/dataset/afe697c9-cf1a-47aa-9f5a-6b928a92af2d/resource/d7beae9c-ea29-4901-825b-0bf8b6a1be7e/download/tsic_mining-1.pdf"},{"name":"คำอธิบาย ข้อมูลประทานบัตร","format":"PDF","url":"https://data.go.th/dataset/afe697c9-cf1a-47aa-9f5a-6b928a92af2d/resource/fab02144-d927-4de4-968a-149fe4fd2858/download/-1.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:39.261592','https://data.go.th/dataset/item_7d9538a8-96c6-4732-a8a5-cd8dec4332b2');
INSERT OR REPLACE INTO datasets VALUES ('item_37612e58-1f62-4155-8b0a-f415b8b72256','ข้อมูลไบโอดีเซล','1.รายชื่อโรงงานไบโอดีเซล 2.ปริมาณการจำหน่ายน้ำมันดีเซล และปริมาณการใช้ไบโอดีเซล 3.ราคาไบโอดีเซล 4.ปริมาณการผลิตไบโอดีเซล 5.ราคาวัตถุดิบ 6.ปริมาณรถยนต์ (ดีเซล) 7.การส่งเสริมและสถานภาพการใช้ไบโอดีเซลในปัจจุบัน','กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน','["ไบโอดีเซล"]','["XLSX"]',1,'[{"name":"metadata_กรมพัฒนาพลังงานทดแทนและอนุรักษ์พลังงาน(ข้อมูลไบโอดีเซล)","format":"XLSX","url":"https://data.go.th/dataset/606c7ff2-423d-4746-bbd7-09251c484348/resource/7e4dc8e5-6ece-4367-b2a4-5f1188611b13/download/metadata_.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:38.900102','https://data.go.th/dataset/item_37612e58-1f62-4155-8b0a-f415b8b72256');
