INSERT OR REPLACE INTO datasets VALUES ('item_ab41f1c8-bfda-4ff9-95be-34dc21e68a9c','Web Services สำหรับตรวจสอบการรับทุนขององค์กร บุคคล เพื่อตรวจสอบและป้องกันการรับทุนซ้ำซ้อน','Web Services สำหรับเปิดเผยข้อมูลหน่วยงานภาครัฐ (Open Data) แบบอัตโนมัติ ประกอบด้วย 1. Service สำหรับค้นหาผู้รับทุน (องค์กร/บุคคล) 2. Service สำหรับค้นหาโครงการ 3. Service สำหรับดึงรายละเอียดของข้อมูลโครงการ เช่น ชื่อโครงการ ประเภทโครงการ ผู้รับทุน&nbsp; องค์กรรับทุน ที่อยู่องค์กร ความเป็นมา หลักการและเหตุผล กรอบแนวคิดและยุทธศาสตร์ ขั้นตอนการทำงาน','สำนักงานกองทุนสนับสนุนการสร้างเสริมสุขภาพ','["กลุ่มบุคคล","ตรวจสอบ","บุคคล","บุคคลรับทุน","รับทุน","สสส","องค์กร","องค์กรรับทุน"]','["XLSX"]',1,'[{"name":"คำอธิบายชุดข้อมูล","format":"XLSX","url":"https://data.go.th/dataset/2647d472-ae63-4d58-90eb-d5eae2b0f855/resource/68cde5a4-6db6-4d8c-aa20-3112c6832866/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:28.413069','https://data.go.th/dataset/item_ab41f1c8-bfda-4ff9-95be-34dc21e68a9c');
