INSERT OR REPLACE INTO datasets VALUES ('item_1ae0762c-bc06-4314-b4b6-988260fe34ff','สำนักผู้ว่าการ สผว (แผ่นพับโครงการรถไฟฟ้าสายสีน้ำเงิน ช่วงบางแค-พุทธมณฑลสาย 4)','โครงการรถไฟฟ้าสายสีน้ำเงิน ช่วงบางแค-พุทธมณฑลสาย 4 มีระยะทางทั้งสิ้น 8 กิโลเมตร 4 สถานี แนวเส้นทางต่อจากโครงการรถไฟฟ้าสายสีน้ำเงิน ช่วงหัวลำโพงบางแค ที่สถานีหลักสอง ลักษณะเส้นทางเป็นทางยกระดับไปตามเกาะกลางของถนนเพชรเกษม ข้ามแยกเพชรเกษม-พุทธมณฑล สาย 2 จากนั้นแนวเส้นทางจะลดระดับลงเพื่อลอดสายส่งไฟฟ้าแรงสูงบริเวณหน้าโรงไฟฟ้าบางกอกน้อย แล้วจึงยกระดับขึ้นไปยังสถานีพุทธมณฑล สาย 2 และยกระดับเพิ่มขึ้นเพื่อข้ามโครงการสะพานข้ามทางแยกในอนาคตของ กทม. ไปยังสถานีทวีวัฒนา คงระดับเดิมต่อไปจนถึงจุดสิ้นสุดโครงการ ผ่านสถานีพุทธมณฑลสาย 3 ข้ามแยกเพชรเกษม-พุทธมณฑล สาย 3 &nbsp;และสะพานข้ามทางแยกในอนาคตของ กทม. วิ่งข…','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["บางแคพุทธมณฑลสาย4"]','["PDF"]',1,'[{"name":"blueline_พุทธมณฑล","format":"PDF","url":"https://data.go.th/dataset/19b4e9f2-6313-4529-a5bd-1bd8e3c3099c/resource/1499d13f-f60e-4d8b-b8fc-9d235e9814dc/download/blueline_.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:26.822211','https://data.go.th/dataset/item_1ae0762c-bc06-4314-b4b6-988260fe34ff');
INSERT OR REPLACE INTO datasets VALUES ('item_cd9498b8-42f3-4811-9565-103e45d67a6c','รายงานประจำปี 2558','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทยได้ดำเนินการจัดทำรายงานรายงานประจำปี 2558 เพื่อรายงานผลการดำเนินงานขององค์กรในรอบปีงบประมาณ 2558 และเผยแพร่ผลการดำเนินงานของ รฟม. ให้หน่วยราชการ องค์กรต่างๆ สื่อมวลชน ตลอดจนประชาชนทั่วไปได้รับทราบ&nbsp;','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["รฟม","รฟม.","รายงานประจำปี"]','["PDF"]',1,'[{"name":"AR MRT 58 Th","format":"PDF","url":"https://data.go.th/dataset/dac6452b-87af-48d0-bf68-3bfd98de539d/resource/183366a8-9d30-43cd-a585-16356e6e2e8f/download/ar-mrt-58-th.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:26.472517','https://data.go.th/dataset/item_cd9498b8-42f3-4811-9565-103e45d67a6c');
INSERT OR REPLACE INTO datasets VALUES ('item_dd5e59c4-860f-45cd-80e6-058860b36a21','แผนวิสาหกิจ ปีงบประมาณ 2555-2559','แผนวิสาหกิจ ปีงบประมาณ 2555-2559','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["รถไฟฟ้า","รฟม","เวนคืนที่ดิน","โครงการรถไฟฟ้า"]','["XLSX"]',1,'[{"name":"แผนวิสาหกิจ ปีงบประมาณ 2555-2559","format":"XLSX","url":"https://data.go.th/dataset/d4230008-0757-4314-8d3f-f84de692cab7/resource/33c8db42-1089-4f78-bf08-7ccf96e240fd/download/-2555-2559.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:26.105402','https://data.go.th/dataset/item_dd5e59c4-860f-45cd-80e6-058860b36a21');
INSERT OR REPLACE INTO datasets VALUES ('item_1190f3d0-cdbc-4edb-83c1-aec1b1cdfe8a','แผ่นพับโครงการรถไฟฟ้าสายสีส้ม ช่วงตลิ่งชัน-มีนบุรี','โครงการรถไฟฟ้าสายสีส้ม ช่วงตลิ่งชัน-มีนบุรี มีระยะทางรวม 39.8 กิโลเมตร เป็นโครงสร้างทางวิ่งใต้ดิน 30.6 กิโลเมตร และเป็นโครงสร้างยกระดับ 9.2 กิโลเมตร มีสถานีทั้งสิ้น 30 สถานี (สถานีใต้ดิน 23 สถานี และสถานียกระดับ 7 สถานี) มีจุดเริ่มต้นที่สถานีตลิ่งชัน จากนั้นวิ่งไปตามแนวเขตรถไฟสายบางกอกน้อย ผ่านโรงพยาบาลศิริราช ลอดใต้แม่น้ำเจ้าพระยาบริเวณเชิงสะพานพระปิ่นเกล้า ผ่านใต้ถนนราชดำเนิน แล้วเบี่ยงใช้แนวถนนหลานหลวง ผ่านยมราช แล้วเข้าสู่แนวถนนเพชรบุรี เลี้ยวเข้าถนนราชปรารภถึงดินแดง แล้วเลี้ยวไปตามถนนวิภาวดีรังสิต ผ่านศาลาว่าการกรุงเทพมหานคร 2 (ดินแดง) เลี้ยวขวาไปเชื่อมกับโครงการรถไฟฟ้ามหานคร สายเฉลิมรัช…','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["ตลิ่งชันมีนบุรี"]','["PDF"]',1,'[{"name":"OrangeLine","format":"PDF","url":"https://data.go.th/dataset/9a8fba84-8385-4795-8098-b0a5860b5621/resource/004a7df6-a160-463e-94d4-3071799836de/download/orangeline.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:25.811198','https://data.go.th/dataset/item_1190f3d0-cdbc-4edb-83c1-aec1b1cdfe8a');
INSERT OR REPLACE INTO datasets VALUES ('item_1bc839f6-fe17-49f8-8dbf-2129baf93b05','แผ่นพับโครงการรถไฟฟ้าสายสีม่วง ช่วงบางใหญ่-บางซื่อ','โครงการรถไฟฟ้าสายสีม่วง (ช่วงบางใหญ่-บางซื่อ) มีระยะทางประมาณ 23 กิโลเมตร เป็นทางวิ่งยกระดับทั้งหมด รวม 16 สถานี เริ่มจากบริเวณคลองบางไผ่ซึ่งเป็นที่ตั้งของศูนย์ซ่อมบำรุงรถไฟฟ้า ถนนวงแหวนรอบนอก (ตะวันตก) กาญจนาภิเษก เลี้ยวซ้ายเข้าสู่ถนนรัตนาธิเบศร์ ข้ามแม่น้ำเจ้าพระยาใกล้สะพานพระนั่งเกล้า ก่อนถึงสี่แยกแครายจะเลี้ยวขวาไปตามถนนติวานนท์ เลี้ยวซ้านเข้าสู่ถนนกรุงเทพ-นนทบุรี ถึงบริเวณแยกเตาปูน มีสถานีเตาปูนเป็นสถานีเชื่อมต่อกับสถานีบางซื่อของรถไฟฟ้ามหานคร สายเฉลิมรัชมงคล (รถไฟฟ้าใต้ดิน MRT) และในอนาคตจะเชื่อมต่อกับรถไฟฟ้าสายสีน้ำเงิน (ช่วงบางซื่อ-ท่าพระ) และรถไฟฟ้าสายสีม่วง (ช่วงเตาปูน-ราษฎร์บูรณะ)','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["เตาปูนราษฎร์บูรณะ"]','["PDF"]',1,'[{"name":"PurpleLine บางใหญ่","format":"PDF","url":"https://data.go.th/dataset/ea3eadba-f9ba-456e-b7f2-0abe82edac11/resource/cc365586-dfbc-4002-b3ca-3b18c9d89916/download/purpleline-.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:25.491260','https://data.go.th/dataset/item_1bc839f6-fe17-49f8-8dbf-2129baf93b05');
INSERT OR REPLACE INTO datasets VALUES ('item_bb839168-240c-4f42-acf8-d0c4cab303f0','แผ่นพับโครงการรถไฟฟ้าสายสีม่วง ช่วงเตาปูน-ราษฎร์บูรณะ','โครงการรถไฟฟ้าสายสีม่วง (ช่วงเตาปูน-ราษฎร์บูรณะ) ระยะทางประมาณ 23.6 กิโลเมตร เป็นโครงสร้างทางวิ่งใต้ดิน 12.6 กิโลเมตร และโครงสร้างทางยกระดับ 11 กิโลเมตร รวม 17 สถานี เริ่มต้นจากจุดเชื่อมต่อโครงการรถไฟฟ้าสายสีม่วง ช่วงบางใหญ่-บางซื่อ ที่บริเวณเตาปูน โดยเปลี่ยนเป็นเส้นทางใต้ดินแล้วเบี่ยงเข้าสู่ถนนสามเสนบริเวณคลองบางซื่อ ผ่านรัฐสถาแห่งใหม่ (โรงเรียนโยธินบูรณะเดิม) โรงเรียนราชินีบน กรมชลประทาน โรงพยาบาลวชิรพยาบาลหอสมุดแห่งชาต คลองบางลำพู เลี้ยวซ้ายเข้าถนนพระสุเมรุผ่านวัดบวรนิเวศราชวรวิหาร แยกผ่านฟ้า ถนนราชดำเนินกลาง เข้าสู่ถนนมหาไชย ผ่านวัดราชนัดดารามวรวิหาร เข้าสู่ถนนจักรเพชร ลอดใต้แม่น้ำเจ้าพระ…','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["เตาปูนราษฎร์บูรณะ"]','["PDF"]',1,'[{"name":"PurpleLine_ราษฎร์บูรณะ","format":"PDF","url":"https://data.go.th/dataset/a26eb9b8-296b-41fe-8a58-92f1f841cd3a/resource/24ad222c-a05e-490a-944d-0191f62860e4/download/purpleline_.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:25.197794','https://data.go.th/dataset/item_bb839168-240c-4f42-acf8-d0c4cab303f0');
INSERT OR REPLACE INTO datasets VALUES ('item_34fa6c26-56c0-4738-bcc5-5da952fd22b5','แผ่นพับโครงการรถไฟฟ้าสายสีน้ำเงิน ช่วงหัวลำโพง-บางแค และ บางซื่อ-ท่าพระ','โครงการรถไฟฟ้าสายสีน้ำเงิน ช่วงหัวลำโพง-บางแค และ บางซื่อ-ท่าพระ มีระยะทางประมาณ 14 กิโลเมตร เป็นโครงสร้างทางวิ่งใต้ดินในช่วงหัวลำโพง-ท่าพระ ระยะทางประมาณ 5 กิโลเมตร มีลักษณะเป็นทางวิ่งอุโมงค์คู่รางเดี่ยว มีสถานีใต้ดินจำนวน 4 สถานี และโครงสร้างทางวิ่งยกระดับในช่วงท่าพระ-บางแค ระยะทางประมาณ 9 กิโลเมตร มีสถานียกระดับ จำนวน 7 สถานี โดยเริ่มต้นจากเส้นทางเชื่อมต่อกับสถานีรถไฟฟ้าหัวลำโพงของรถไฟฟ้ามหานคร สายเฉลิมรัชมงคล เป็นเส้นทางใต้ดินตามแนวถนนพระรามที่ 4 เข้าสู่ถนนเจริญกรุง ผ่านวัดมังกรกมลาวาส ผ่านวังบูรพา เลี้ยวซ้ายเข้าถนนสนามไชย ลอดใต้แม่น้ำเจ้าพระยาที่ปากคลองตลาด ลอดใต้คลองบางกอกใหญ่ เข้าสู่ถน…','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["บางซื่อท่าพระ","หัวลำโพงบางแค"]','["PDF"]',1,'[{"name":"BlueLine_หัวลำโพง","format":"PDF","url":"https://data.go.th/dataset/a1661601-ad91-4425-88e6-55a1aaa756f5/resource/c913027f-04d5-4c50-a8bb-79144664d07b/download/blueline_.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:24.874259','https://data.go.th/dataset/item_34fa6c26-56c0-4738-bcc5-5da952fd22b5');
INSERT OR REPLACE INTO datasets VALUES ('item_c7ce5a23-a342-469d-88e6-58c99ecaf0ed','แผ่นพับโครงการรถไฟฟ้าสายสีชมพู ช่วงแคราย-มีนบุรี','โครงการรถไฟฟ้าสายสีชมพู ช่วงแคราย-มีนบุรี เป็นโครงการตามแผนแม่บทระบบขนส่งมวลชนทางรางในเขตกรุงเทพมหานครและปริมณฑล จากการศึกษาของสำนักงานนโยบายและแผนการขนส่งและจราจร (สนข.) โดยกำหนดให้โครงการนี้เป็นระบบขนส่งมวลชนสายรองประเภทรถไฟฟ้ารางเดี่ยว (Straddle Monorail) ที่เป็นทางยกระดับตลอดเส้นทาง ต้นทางของรถไฟฟ้าสายสีชมพู ช่วงแคราย &ndash; มีนบุรี เริ่มจากสถานีศูนย์ราชการจังหวัดนนทบุรี ซึ่งอยู่ใกล้แยกแคราย ผ่านถนนติวานนท์ก่อนเลี้ยวเข้าถนนแจ้งวัฒนะ เชื่อมต่อถนนรามอินทรา ไปสิ้นสุดปลายทางที่สถานีมีนบุรี รวมระยะทาง 34.5 กิโลเมตร มีจำนวน 30 สถานี &nbsp;','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["แครายมีนบุรี"]','["PDF"]',1,'[{"name":"PinkLine","format":"PDF","url":"https://data.go.th/dataset/a56ffe3c-9c5f-4839-ac80-22af99f4f56b/resource/4e0e4829-e86b-472f-891a-5765efdfddfb/download/pinkline.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:24.595315','https://data.go.th/dataset/item_c7ce5a23-a342-469d-88e6-58c99ecaf0ed');
INSERT OR REPLACE INTO datasets VALUES ('item_fc94f657-25a3-48fe-96f2-c71b0037d794','แผ่นพับโครงการรถไฟฟ้าสายสีเขียว ช่วงแบริ่ง-สมุทรปราการ','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย ได้รับมอบหมายให้ดำเนินการโครงการรถไฟฟ้าสายสีเขียว ช่วงแบริ่ง &ndash; สมุทรปราการ โดยมีระยะทาง 13 กม. เป็นทางวิ่งยกระดับทั้งหมด 9 สถานี แนวเส้นทางเริ่มต้นต่อเนื่องจากแนวเส้นทางของโครงการระบบขนส่งมวลชนกรุงเทพมหานครหรือ BTS ส่วนต่อขยายสายสุขุมวิท ตอนที่ 1 ช่วงอ่อนนุช - แบริ่ง ที่บริเวณซอยสุขุมวิท 107 (ซอยแบริ่ง) ไปตามแนวถนนสุขุมวิท ผ่านแยกเทพารักษ์ แยกปู่เจ้าสมิงพราย แยกศาลากลาง และเลี้ยวซ้ายไปตามถนนสุขุมวิท จนถึงบริเวณแยกการไฟฟ้า ผ่านถนนแพรกษา แยกสายลวด สิ้นสุดบริเวณหน้าสถานีไฟฟ้าย่อยบางปิ้ง','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["แบริ่งสมุทรปราการ"]','["PDF"]',1,'[{"name":"GreenBaring","format":"PDF","url":"https://data.go.th/dataset/83bac75a-8738-423b-a481-6551f4904436/resource/80660dc8-4f19-459f-8090-37f8753b5903/download/greenbaring.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:24.163128','https://data.go.th/dataset/item_fc94f657-25a3-48fe-96f2-c71b0037d794');
