INSERT OR REPLACE INTO datasets VALUES ('item_dc8714f1-ae19-4941-8cf8-fd67c6a1d420','โครงการสำรวจภาพลักษณ์องค์กร รฟม. และความพึงพอใจในการให้บริการรถไฟฟ้ามหานครสายเฉลิมรัชมงคล ปีงบประมาณ 2559','เพื่อสำรวจความพึงพอใจในการให้บริการรถไฟฟ้ามหานคร สายเฉลิมรัชมงคล และเพื่อสำรวจการรู้จัก การเชื่อถือ และภาพลักษณ์ในการทำงานของ รฟม. ของประชาชนในกรุงเทพมหานคร และโครงการรถไฟฟ้าที่อยู่ในความรับผิดชอบของ รฟม.','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["ภาพลักษณ์องค์กร","สำรวจความพึงพอใจ"]','["PDF"]',1,'[{"name":"รายงานฉบับสมบูรณ์ ปี2559","format":"PDF","url":"https://data.go.th/dataset/034c347f-2aa0-4f4b-9dba-71edb6b28700/resource/dd2474a2-fa52-4081-9e8f-cb14b4bfe644/download/-2559.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:04.503012','https://data.go.th/dataset/item_dc8714f1-ae19-4941-8cf8-fd67c6a1d420');
INSERT OR REPLACE INTO datasets VALUES ('item_814d7ff5-7aec-45e6-8691-302d41576986','โครงการรถไฟฟ้าในความรับผิดชอบของการรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย (รฟม.)','รายละเอียดโครงการรถไฟฟ้าในความรับผิดชอบของการรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย (รฟม.) ซึ่งมีโครงข่ายรถไฟฟ้าสายหลักที่รับผิดชอบทั้งหมด 6 สายทาง 13 โครงการ','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["รถไฟฟ้า","รฟม","โครงการรถไฟฟ้า"]','["PPT"]',1,'[{"name":"โครงการรถไฟฟ้าในความรับผิดชอบของการรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย (รฟม.)","format":"PPT","url":"https://data.go.th/dataset/838952fc-6421-4360-b697-ef7c31ab5981/resource/27fad305-c072-4321-8c78-c607e6cd3de3/download/xx.ppt"}]','Creative Commons Attributions','2021-10-31T05:39:04.187775','https://data.go.th/dataset/item_814d7ff5-7aec-45e6-8691-302d41576986');
INSERT OR REPLACE INTO datasets VALUES ('item_c44045c1-9356-4b90-ae67-fe875449801d','ข้อมูลด้านโครงสร้างพื้นฐานและสาธารณูปโภค องค์กรปกครองส่วนท้องถิ่น','เป็นข้อมูลในการวางแผนหรือกำหนดข้อบัญญัติ ในการพัฒนา ซ่อมแซมถนน แหล่งน้ำ และการติดตั้งไฟฟ้าใช้ในครัวเรือน','กรมส่งเสริมการปกครองท้องถิ่น','["ถนน","น้ำประปา","บ่อ","สะพาน","อบจ.","อบต.","อปท.","เทศบาล"]','["CSV","XSL","XLSX"]',3,'[{"name":"ข้อมูลด้านโครงสร้างพื้นฐานและสาธารณูปโภค องค์กรปกครองส่วนท้องถิ่น","format":"CSV","url":"https://data.go.th/dataset/b78011c1-91db-4dc7-9e93-fe623ee9835e/resource/79a73e5e-0550-4ebb-a18f-80d05cb7c6fc/download/01.csv"},{"name":"ข้อมูลด้านโครงสร้างพื้นฐานและสาธารณูปโภค องค์กรปกครองส่วนท้องถิ่น","format":"XSL","url":"https://data.go.th/dataset/b78011c1-91db-4dc7-9e93-fe623ee9835e/resource/951a5c06-de22-4974-826c-6bb3e34118a8/download/01-.xls"},{"name":"คำอธิบายชุดข้อมูลด้านโครงสร้างพื้นฐานและสาธารณูปโภค องค์กรปกครองส่วนท้องถิ่น","format":"XLSX","url":"https://data.go.th/dataset/b78011c1-91db-4dc7-9e93-fe623ee9835e/resource/beced0ef-12c8-4961-91dd-c4126800fa58/download/untitled.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:03.423858','https://data.go.th/dataset/item_c44045c1-9356-4b90-ae67-fe875449801d');
INSERT OR REPLACE INTO datasets VALUES ('item_2aabbeac-0dd8-4b5d-96ae-f2e91a780cce','การเวนคืนอสังหาริมทรัพย์และการกำหนดลักษณะภาระในอสังหาริมทรัพย์ เพื่อสร้างโครงการของการรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','ความรู้สำหรับประชาชน เรื่อง การเวนคืนอสังหาริมทรัพย์และการกำหนดลักษณะภาระ ในอสังหาริมทรัพย์ เพื่อสร้างโครงการของการรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย ซึ่งมีเนื้อหาเกี่ยวกับการเวนคืนฯ และการกำหนดลักษณะภาระฯ เช่น วิธีดำเนินการจัดกรรมสิทธิ์ที่ดิน ขั้นตอนการจัดกรรมสิทธิ์ที่ดิน และสิทธิหน้าที่และผลประโยขน์ของผู้ถูกเวนคืน เป็นต้น','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["รถไฟฟ้า","รฟม","เวนคืนที่ดิน","โครงการรถไฟฟ้า"]','["XSL"]',1,'[{"name":"การเวนคืนและการกำหนดลักษณะภาระเพื่อสร้างโครงการของการรถไฟฟ้า","format":"XSL","url":"https://data.go.th/dataset/7cab4bda-842a-4b71-8055-3028eea99924/resource/a6c66c6f-1891-4bd3-87e9-0f0573b6e203/download/xx.xls"}]','Creative Commons Attributions','2021-10-31T05:39:03.071526','https://data.go.th/dataset/item_2aabbeac-0dd8-4b5d-96ae-f2e91a780cce');
INSERT OR REPLACE INTO datasets VALUES ('item_617b5630-451d-4d84-bf25-5b8701f56fb1','การบริการและอัตราค่าโดยสาร','องค์การขนส่งมวลชนกรุงเทพ เป็นหน่วยงานรัฐวิสาหกิจประเภทสาธารณูปโภคสังกัดกระทรวงคมนาคม จัดตั้งขึ้นโดยพระราชกฤษฎีกาจัดตั้งองค์การขนส่งมวลชนกรุงเทพ พุทธศักราช 2519 (ก่อตั้งเมื่อวันที่ 19 ตุลาคม 2519) มีภาระหน้าที่ในการจัดบริการรถโดยสารประจำทางวิ่งรับส่งประชาชนในเขตกรุงเทพมหานคร นนทบุรี นครปฐม ปทุมธานี สมุทรสาคร สมุทรปราการ จัดรถวิ่งบริการในเส้นทางต่าง ๆ รวม 458 เส้นทาง มีจำนวนรถทั้งสิ้น 13,942 คัน (ณ 31 พฤษภาคม 2561) แยกเป็นรถ ขสมก. รถธรรมดา 1,543 คัน รถปรับอากาศ 1,111 คัน รถ PBC(รถเช่า) 117 คัน และมีรถของบริษัทเอกชนที่ร่วมวิ่งบริการกับ องค์การขนส่งมวลชนกรุงเทพ รถร่วมบริการ รถธรรมดา 2,037 คัน รถร…','องค์การขนส่งมวลชนกรุงเทพ','["การบริการ","อัตราค่าโด�"]','["XLSX"]',1,'[{"name":"metadata_องค์การขนส่งมวลชนกรุงเทพ(การบริการและอัตราค่าโดยสาร)","format":"XLSX","url":"https://data.go.th/dataset/57b0bb28-e93b-4461-8b8c-922c0dafb431/resource/04058008-5e57-4d3c-bf27-951591510937/download/metadata_.xlsx"}]','Creative Commons Attributions','2021-10-31T05:39:02.779878','https://data.go.th/dataset/item_617b5630-451d-4d84-bf25-5b8701f56fb1');
INSERT OR REPLACE INTO datasets VALUES ('item_2c6e3207-a1df-4401-9eae-f04f94a19122','MRTA Project','The Mass Rapid Transit Authority of Thailand (MRTA) is supervising the initial system project that is officially called the M.R.T. Chaloem Ratchamongkhon Line. In Addition, the MRTA has been assigned to implement a part of MRT extension network approved by the Cabinet on March 9, 2010','การรถไฟฟ้าขนส่งมวลชนแห่งประเทศไทย','["mrtaproject"]','["PDF"]',1,'[{"name":"MRTA_A","format":"PDF","url":"https://data.go.th/dataset/44b5c2e9-1445-4b6a-9801-a3c6edf68af3/resource/1446b0e4-a37f-4538-8df2-1b935a77730c/download/mrta_a.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:02.527139','https://data.go.th/dataset/item_2c6e3207-a1df-4401-9eae-f04f94a19122');
INSERT OR REPLACE INTO datasets VALUES ('item_5c41eb00-ef89-452b-9999-ab25d60c32e1','ประวัติความเป็นมาของตลาดสินค้าเกษตรล่วงหน้าแห่งประเทศไทย','ข้อมูลภาพรวมและประวัติความเป็นมาของตลาดสินค้าเกษตรล่วงหน้าแห่งประเทศไทย','ตลาดสินค้าเกษตรล่วงหน้าแห่งประเทศไทย','["ข้อมูลภาพรวมและประวั"]','["DOC"]',1,'[{"name":"ข้อมูลภาพรวมและประวัติความเป็นมาของตลาดสินค้าเกษตรล่วงหน้าแห่งประเทศไทย","format":"DOC","url":"https://data.go.th/dataset/eb8fcef9-e2ad-43f0-9dcf-316990c1a0e5/resource/979b0771-e39b-4e3a-b6e8-188b6052bee3/download/-9-6-59-.docx"}]','Creative Commons Attributions','2021-10-31T05:39:02.203650','https://data.go.th/dataset/item_5c41eb00-ef89-452b-9999-ab25d60c32e1');
INSERT OR REPLACE INTO datasets VALUES ('item_5e02c727-adaa-4fc8-800c-9e349ff22d84','ประกาศรับสมัครงาน','การประกาศรับสมัครงานตำแหน่งข้าราชการหรือพนักงานราชการหรือบุคลากรภาครัฐอื่นๆ ของสำนักงานปลัดกระทรวงเกษตรและสหกรณ์','สำนักงานปลัดกระทรวงเกษตรและสหกรณ์','["ประกาศรับสมัครงาน"]','["XML"]',1,'[{"name":"ประกาศรับสมัครงาน","format":"XML","url":"https://data.go.th/dataset/0a698987-0d73-4af1-a724-b15e4e37a4d6/resource/7d33ebf4-30f8-404d-8219-868a3367ceea/download/group111.xml"}]','Creative Commons Attributions','2021-10-31T05:39:01.923298','https://data.go.th/dataset/item_5e02c727-adaa-4fc8-800c-9e349ff22d84');
INSERT OR REPLACE INTO datasets VALUES ('item_c3441613-e5ff-4648-9465-efa6efb10c25','ข้อมูลเกษตรกรผู้เลี้ยงสัตว์และปศุสัตว์','ข้อมูลจำนวนเกษตรกรผู้เลี้ยงสัตว์และปศุสัตว์ในประเทศไทย ปี 2558 ที่ได้จัดทำขึ้นนี้ มีความมุ่งหมายเพื่อรวบรวม และนำเสนอข้อมูลที่ได้จากการสำรวจข้อมูลปศุสัตว์ โดยสำนักงานปศุสัตว์จังหวัดทั่วประเทศ เพื่อใช้เป็นข้อมูลพื้นฐาน ในการวางแผนโครงการต่างๆ ของกรมปศุสัตว์รวมถึงผู้ที่ต้องการนำข้อมูลไปประกอบในการค้นคว้า วิเคราะห์ วิจัย เกี่ยวกับสถานการณ์ทางด้านปศุสัตว์ของประเทศไทย ซึ่งประกอบด้วยข้อมูลจำนวนเกษตรกรผู้เลี้ยงสัตว์และปศุสัตว์ ทั้งหมด 9 ชนิด ได้แก่ โคเนื้อ โคนม กระบือ สุกร ไก่ เป็ด แพะ แกะ และสัตว์เลี้ยงอื่นๆ','กรมปศุสัตว์','["กรมปศุสัตว์","ประจำปี2558","รายจังหวัด"]','["CSV","PDF"]',2,'[{"name":"ข้อมูลเกษตรกรผู้เลี้ยงสัตว์และปศุสัตว์","format":"CSV","url":"https://data.go.th/dataset/439e88f1-abd2-42b6-9f21-91e60ae54f98/resource/d3d1e33b-94a1-40a1-8dc1-a637110ee1c8/download/2015-ogd1.csv"},{"name":"คำอธิบายMetadata1","format":"PDF","url":"https://data.go.th/dataset/439e88f1-abd2-42b6-9f21-91e60ae54f98/resource/9f86bb64-5861-4d3b-8131-44ac696dd82a/download/metadata1.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:01.593271','https://data.go.th/dataset/item_c3441613-e5ff-4648-9465-efa6efb10c25');
