INSERT OR REPLACE INTO datasets VALUES ('item_36482772-8500-4397-8599-80499b041021','หนังสือรอบรู้ระบบกฎหมายและระบบศาลในกลุ่มประเทศอาเซียน','หนังสือรอบรู้ระบบกฎหมายและระบบศาลในกลุ่มประเทศอาเซียน&nbsp;สำนักงานศาลยุติธรรม ศาลยุติธรรม','สำนักงานศาลยุติธรรม','["กฎหมาย","กฎหมายอาเซียน","ระบบศาล","ศาลยุติธรรม","สำนักงานศาลยุติธรรม"]','["PDF"]',1,'[{"name":"รอบรู้ระบบกฎหมายและระบบศาลในกลุ่มประเทศอาเซียน","format":"PDF","url":"https://data.go.th/dataset/02d52377-8d8e-49da-a836-61fe9f57ebf3/resource/22dc5079-e124-4aff-8bc1-2ddf10ceb84c/download/2.-2.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:00.860172','https://data.go.th/dataset/item_36482772-8500-4397-8599-80499b041021');
INSERT OR REPLACE INTO datasets VALUES ('item_94b0f3e1-549c-4642-95f0-55c82945bdf0','หนังสือกรอบความตกลงและความรู้เบื้องต้นเกี่ยวกับ AEC ที่น่าสนใจ','หนังสือกรอบความตกลงและความรู้เบื้องต้นเกี่ยวกับ AEC ที่น่าสนใจ สำนักงานศาลยุติธรรม ศาลยุติธรรม ซึ่งภายในเล่มจะมีทั้งภาษาไทย และภาษาอังกฤษ','สำนักงานศาลยุติธรรม','["กรอบความตกลง","ศาลยุติธรรม","สำนักงานศาลยุติธรรม"]','["PDF"]',1,'[{"name":"หนังสือกรอบความตกลงและความรู้เบื้องต้นเกี่ยวกับ AEC ที่น่าสนใจ","format":"PDF","url":"https://data.go.th/dataset/5f0bf462-b550-4727-8d93-5f3a212db91c/resource/191c4a2f-ac75-4a5a-9719-eab63ad68bc6/download/1.-5.pdf"}]','Creative Commons Attributions','2021-10-31T05:39:00.328011','https://data.go.th/dataset/item_94b0f3e1-549c-4642-95f0-55c82945bdf0');
