INSERT OR REPLACE INTO datasets VALUES ('item_8977c6ec-483f-470f-8944-8b31ff660689','รวมชื่อภาษาอังกฤษเกี่ยวกับหน่วยงานและตำแหน่งของบุคลากรในศาลยุติธรรม','รวมชื่อภาษาอังกฤษเกี่ยวกับหน่วยงานและตำแหน่งของบุคลากรในศาลยุติธรรม','สำนักงานศาลยุติธรรม','["ศาลยุติธรรม","สำนักงานศาลยุติธรรม"]','["PDF"]',1,'[{"name":"รวมชื่อภาษาอังกฤษเกี่ยวกับหน่วยงานและตำแหน่งของบุคลากรในศาลยุติธรรม","format":"PDF","url":"https://data.go.th/dataset/3b70d54e-e75c-47c6-8b61-2e9c6ec6f49e/resource/98ce5b6c-20b1-4f79-b611-08e7b73658a4/download/3..pdf"}]','Creative Commons Attributions','2021-10-31T05:38:59.658238','https://data.go.th/dataset/item_8977c6ec-483f-470f-8944-8b31ff660689');
