INSERT OR REPLACE INTO datasets VALUES ('item_a07dea1b-33d9-475b-831a-f2d4024f2e9e','ประกาศสำนักงานศาลยุติธรรม เรื่อง อัตราค่าป่วยการอนุญาโตตุลาการ สำนักงานศาลยุติธรรม','ประกาศสำนักงานศาลยุติธรรม เรื่อง อัตราค่าป่วยการอนุญาโตตุลาการ สำนักงานศาลยุติธรรม','สำนักงานศาลยุติธรรม','["กฎหมาย","ค่าป่วยการ","ประกาศ","ศาลยุติธรรม","สำนักงานศาลยุติธรรม","อนุญาโตตุลาการ"]','["PDF"]',1,'[{"name":"ประกาศสำนักงานศาลยุติธรรม เรื่อง อัตราค่าป่วยการอนุญาโตตุลาการ สำนักงานศาลยุติธรรม","format":"PDF","url":"https://data.go.th/dataset/b8f7210b-65d0-46d4-b889-1956df396bcf/resource/a27ddc83-ca79-4880-95a2-5ccf9ea8d67f/download/tai_1464252897.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:58.954803','https://data.go.th/dataset/item_a07dea1b-33d9-475b-831a-f2d4024f2e9e');
INSERT OR REPLACE INTO datasets VALUES ('item_194204e8-ad6c-4f23-901d-b6f1be8c6371','ประกาศสำนักงานศาลยุติธรรม เรื่อง อัตราค่าใช้จ่ายสำหรับดำเนินการข้อพิพาทของสถาบันอนุญาโตตุลาการ สำนักงานศาลยุติธรรม','ประกาศสำนักงานศาลยุติธรรม เรื่อง อัตราค่าใช้จ่ายสำหรับดำเนินการข้อพิพาทของสถาบันอนุญาโตตุลาการ สำนักงานศาลยุติธรรม','สำนักงานศาลยุติธรรม','["ข้อพิพาท","ค่าใช้จ่าย","ประกาศ","ศาลยุติธรรม","สำนักงานศาลยุติธรรม","อนุญาโตตุลาการ"]','["PDF"]',1,'[{"name":"ประกาศสำนักงานศาลยุติธรรม เรื่อง อัตราค่าใช้จ่ายสำหรับดำเนินการข้อพิพาทของสถาบันอนุญาโตตุลาการ สำนั…","format":"PDF","url":"https://data.go.th/dataset/033e4b78-fa6f-4377-be51-ba3d0473b904/resource/96c8e9e9-cc8b-4d1e-9f52-95fcec067420/download/tai_1464252966.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:58.598371','https://data.go.th/dataset/item_194204e8-ad6c-4f23-901d-b6f1be8c6371');
INSERT OR REPLACE INTO datasets VALUES ('item_618e63ac-50db-45bc-95cb-18ef50fec2e1','บริการโอนเงินเข้าบัญชีผู้รับเงินโดยตรง สำนักงานศาลยุติธรรม','แผ่นป้ายประชาสัมพันธ์การบริการโอนเงินเข้าบัญชีผู้รับเงินโดยตรง สำนักงานศาลยุติธรรม','สำนักงานศาลยุติธรรม','["การโอนเงิน","บัญชี","สำนั�"]','["IMAGE"]',1,'[{"name":"บริการโอนเงินเข้าบัญชีผู้รับเงินโดยตรง สำนักงานศาลยุติธรรม","format":"IMAGE","url":"https://data.go.th/dataset/9d6ba6be-a3fc-4e1f-a0cc-488c0e68f21c/resource/87e95d44-076b-4b84-b032-1cef61fe8541/download/finance-leaflet_coj_new_fi.jpg"}]','Creative Commons Attributions','2021-10-31T05:38:58.316746','https://data.go.th/dataset/item_618e63ac-50db-45bc-95cb-18ef50fec2e1');
