INSERT OR REPLACE INTO datasets VALUES ('item_5232b084-1325-4c9d-b52f-c29686872917','คุณสมบัติของบุคคลที่จะขึ้นทะเบียนอนุญาโตตุลาการ สำนักงานศาลยุติธรรม','คุณสมบัติของบุคคลที่จะขึ้นทะเบียนอนุญาโตตุลาการ สำนักงานศาลยุติธรรม','สำนักงานศาลยุติธรรม','["กฎหมาย","คุณสมบัติ","อนุญ�"]','["PDF"]',1,'[{"name":"คุณสมบัติของบุคคลที่จะขึ้นทะเบียนอนุญาโตตุลาการ สำนักงานศาลยุติธรรม","format":"PDF","url":"https://data.go.th/dataset/90ef41b2-4125-48a1-b269-43085bcf6347/resource/47ebf3c9-788e-49ca-b4bf-e78e90717303/download/tai_1464338745.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:57.067647','https://data.go.th/dataset/item_5232b084-1325-4c9d-b52f-c29686872917');
INSERT OR REPLACE INTO datasets VALUES ('item_eb19b14c-f32c-415e-81e4-e31b074a4d73','คำแนะนำในการขอหมายเรียกพยานบุคคลหรือคำสั่งเรียกพยานเอกสารหรือวัตถุในกระบวนการอนุญาโตตุลาการ','คำแนะนำในการขอหมายเรียกพยานบุคคลหรือคำสั่งเรียกพยานเอกสารหรือวัตถุในกระบวนการอนุญาโตตุลาการ','สำนักงานศาลยุติธรรม','["กฎหมาย","พยาน","ศาลยุติธรรม","สำนักงานศาลยุติธรรม","หมายเรีียก","อนุญาโตตุลาการ"]','["PDF"]',1,'[{"name":"คำแนะนำในการขอหมายเรียกพยานบุคคลหรือคำสั่งเรียกพยานเอกสารหรือวัตถุในกระบวนการอนุญาโตตุลาการ","format":"PDF","url":"https://data.go.th/dataset/f220e341-81af-4999-a18c-46ee131bd008/resource/42c1394d-ced6-40b4-8324-73287941a2ff/download/tai_1465202637.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:56.695436','https://data.go.th/dataset/item_eb19b14c-f32c-415e-81e4-e31b074a4d73');
INSERT OR REPLACE INTO datasets VALUES ('item_9b68ff56-e1ca-4997-86f5-315e25443d42','ขั้นตอนการดำเนินกระบวนพิจารณาชั้นอนุญาโตตุลาการ ตามข้อบังคับสำนักงานศาลยุติธรรมว่าด้วยอนุญาโตตุลาการ','ขั้นตอนการดำเนินกระบวนพิจารณาชั้นอนุญาโตตุลาการ ตามข้อบังคับสำนักงานศาลยุติธรรมว่าด้วยอนุญาโตตุลาการ สถาบันอนุญาโตตุลาการ','สำนักงานศาลยุติธรรม','["กฎหมาย","กระบวนการ","ขั้นตอน","ศาลยุติธรรม","สำนักงานศาลยุติธรรม","อนุญาโตตุลาการ"]','["PDF"]',1,'[{"name":"ขั้นตอนการดำเนินกระบวนพิจารณาชั้นอนุญาโตตุลาการ ตามข้อบังคับสำนักงานศาลยุติธรรมว่าด้วยอนุญาโตตุลาการ","format":"PDF","url":"https://data.go.th/dataset/85228d2e-1592-4945-9a40-d86b413e78ef/resource/b2a42cdd-6dc9-48bb-8d88-0eb574da1444/download/tai_1464245864.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:56.334704','https://data.go.th/dataset/item_9b68ff56-e1ca-4997-86f5-315e25443d42');
INSERT OR REPLACE INTO datasets VALUES ('item_0de0f583-db0e-44e8-a77a-465bbf0808dd','ข้อหารือการศึกษาวิจัยการดำเนินงานโครงการนำร่องการจัดการขยะชุมชน','ข้อหารือการศึกษาวิจัยการดำเนินงานโครงการนำร่องการจัดการขยะชุมชน ของเทศบาลตำบลทับกวาง ว่าการที่สถาบันเทคโนโลยีพระจอมเกล้าเจ้าคุณทหารลาดกระบัง มีความประสงค์ขออณุญาตใช้พื้นที่ของเทศบาลตำบลทับกวาง เพื่อดำเนินการโครงการจัดการขยะชุมชนมีกำหนดเวลา 12 เดือน เข้าข่ายต้องขออนุญาตตั้งโรงงานหรือไม่','สำนักงานปลัดกระทรวงอุตสาหกรรม','["กฎหมาย","กรมโรงงานอุตสาหกรรม","กระทรวงอุตสาหกรรม","พ.ศ.","พรบ.โรงงาน","เจ้าคุณทหารลาดกระบัง","เทศบาลตำบลทับกวาง"]','["PDF"]',1,'[{"name":"ข้อหารือการศึกษาวิจัยการดำเนินงานโครงการนำร่องการจัดการขยะชุมชน","format":"PDF","url":"https://data.go.th/dataset/9dafce5b-90ab-4e7d-8879-fc2c844ccae4/resource/b52df6de-ac18-4aad-a48e-95101a741bfb/download/xx.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:55.944790','https://data.go.th/dataset/item_0de0f583-db0e-44e8-a77a-465bbf0808dd');
INSERT OR REPLACE INTO datasets VALUES ('item_a68035d7-e14d-4686-a7ec-baa3b4e789d8','ข้อหารือการพิจารณาดำเนินคดีเปรียบเทียบปรับ กรณีมีน้ำไหลล้นออกจากบ่อพักน้ำเสียของโรงงาน','ข้อหารือการพิจารณาดำเนินคดีเปรียบเทียบปรับ จากกรณีสำนักงานอุตสาหกรรม จ.นครราชสีมา ได้รับแจ้งจากประชาชนว่า มีน้ำไหลล้นออกจากบ่อพักน้ำเสียของโรงงานน้ำตาลของบริษัท น้ำตาลครบุรี จำกัด ไหลลงสู่พื้นที่เกษตรกรรมของชาวบ้านและแหล่งน้ำสาธารณะ','สำนักงานปลัดกระทรวงอุตสาหกรรม','["กฎหมาย","กรมโรงงานอุตสาหกรรม","กระทรวงอุตสาหกรรม","น้ำตาลครบุรี","พ.ศ.","พรบ.โรงงาน"]','["PDF"]',1,'[{"name":"ข้อหารือการพิจารณาดำเนินคดีเปรียบเทียบปรับ","format":"PDF","url":"https://data.go.th/dataset/0ee5add3-5c4b-484a-a9a2-a4fba9a8e70e/resource/0531f36e-67cb-4c51-ab85-281dfd5b6a0c/download/xx.pdf"}]','Creative Commons Attributions','2021-10-31T05:38:55.602330','https://data.go.th/dataset/item_a68035d7-e14d-4686-a7ec-baa3b4e789d8');
