INSERT OR REPLACE INTO datasets VALUES ('item_2af5aa26-15c3-47c5-99dd-8ae392906c6d','รายงานที่ตั้งศูนย์รับแจ้งเหตุและสั่งการจังหวัด','รายงานที่ตั้งศูนย์รับแจ้งเหตุและสั่งการจังหวัด','สถาบันการแพทย์ฉุกเฉินแห่งชาติ','[]','[]',0,'[]','Creative Commons Attributions','2021-10-31T05:38:48.198763','https://data.go.th/dataset/item_2af5aa26-15c3-47c5-99dd-8ae392906c6d');
INSERT OR REPLACE INTO datasets VALUES ('item_26c97ef3-9fa3-48ad-a5a0-120f07b77d96','ข้อมูลนำเข้าอาหารสัตว์','ข้อมูลนำเข้าอาหารสัตว์ กรมปศุสัตว์ ได้เก็บรวบรวม วิเคราะห์ และรายงาน จากหนังสือแจ้งการนำเข้าซึ่งอาหารสัตว์เข้ามาในราชอาณาจักร (น.ส.4) ซึ่งมาจากผู้ประกอบการที่มาขออนุญาตนำเข้าอาหารสัตว์กับกรมปศุสัตว์ เป็นสถิติข้อมูลให้ผู้ประกอบการหน่วยงานที่เกี่ยวข้อง และระดับผู้บริหารเพื่อนำไปใช้ประโยชน์ในการประเมินสถานการณ์นำเข้าอาหารสัตว์ของประเทศไทย','กรมปศุสัตว์','["กรมปศุสัตว์","ข้อมูล","นำเข้าอาหารสัตว์","วัตถุดิบอาหารสัตว์","สัตว์เลี้ยง","อาหาร","อาหารสัตว์"]','[]',0,'[]','Creative Commons Attributions','2021-10-31T05:38:47.828060','https://data.go.th/dataset/item_26c97ef3-9fa3-48ad-a5a0-120f07b77d96');
INSERT OR REPLACE INTO datasets VALUES ('item_250eb2fe-7155-491d-997c-ac4f8b148fdb','ข้อมูลส่งออกอาหารสัตว์','ข้อมูลส่งออกอาหารสัตว์ กรมปศุสัตว์ ได้เก็บรวบรวม วิเคราะห์และรายงาน จากหนังสือรับรองความปลอดภัยอาหารสัตว์เพื่อการส่งออก (Health Certificate) ซึ่งมาจากผู้ประกอบการที่มาขออนุญาตส่งออกอาหารสัตว์กับกรมปศุสัตว์ เป็นสถิติข้อมูลให้ผู้ประกอบการ หน่วยงานที่เกี่ยวข้อง และระดับผู้บริหารเพื่อนำไปใช้ประโยชน์ในการประเมินสถานการณ์ส่งออกอาหารสัตว์ของประเทศไทย','กรมปศุสัตว์','["กรมปศุ","ข้อมูล","สัตว์","ส่งออกอาหารสัตว์","อาหารสัตว์","อาหารสัตว์เลี้ยง"]','[]',0,'[]','Creative Commons Attributions','2021-10-31T05:38:47.494620','https://data.go.th/dataset/item_250eb2fe-7155-491d-997c-ac4f8b148fdb');
