INSERT OR REPLACE INTO datasets VALUES ('mnre_51_23','กรอบการประเมินผลตัวชี้วัด','เป็นการกำหนดทิศทางการดำเนินงานก่อนที่จะกำหนดตัวชี้วัดให้สอดคล้องกับแนวทางการประเมินผลส่วนราชการตามมาตรการการปรับปรุงประสิทธิภาพการปฏิบัติราชการของส่วนราชการ ตามที่สำนักงานก.พ.ร. กำหนด ประกอบด้วย องค์ประกอบตัวชี้วัด ชื่อตัวชี้วัด เป้าหมาย น้ำหนัก และส่วนงานที่รับผิดชอบตัวชี้วัด','กลุ่มพัฒนาระบบบริหาร สำนักงานปลัดกระทรวงทรัพยากรธรรมชาติและสิ่งแวดล้อม','["กรอบตัวชี้วัด","แนวทางการประเมินผล"]','[]',0,'[]','ogl','2021-07-08T07:36:18.136810','https://data.go.th/dataset/mnre_51_23');
